def is_valid_secret_key(secret_key):
    """Validate secret key is exactly 6 digits."""
    return secret_key.isdigit() and len(secret_key) == 6

def is_email_unique(email, exclude_id=None):
    """Check if email exists in users_collection or worker_collection globally (case-insensitive)."""
    if not email:
        return True
    email_norm = str(email).strip().lower()
    
    # Resolve all IDs associated with this identity to prevent self-conflict
    exclude_ids = []
    if exclude_id:
        exclude_id_str = str(exclude_id)
        exclude_ids.append(exclude_id_str)
        
        # 1. Check if this is a user, get their worker_id
        user = users_collection.find_one({"$or": [{"_id": exclude_id_str}, {"worker_id": exclude_id_str}]})
        if user:
            exclude_ids.append(user.get("_id"))
            if user.get("worker_id"):
                exclude_ids.append(user.get("worker_id"))
        
        # 2. Check if this is a worker, find their user record
        worker = worker_collection.find_one({"_id": exclude_id_str})
        if worker:
            user_by_worker = users_collection.find_one({"worker_id": exclude_id_str})
            if user_by_worker:
                exclude_ids.append(user_by_worker.get("_id"))
                
    # Clean and normalize exclude_ids
    exclude_ids = list(set(str(i) for i in exclude_ids if i))

    # 1. Check users_collection (Admins and Employee Login Profiles)
    u_filter = {"email": {"$regex": f"^{re.escape(email_norm)}$", "$options": "i"}}
    if exclude_ids:
        u_filter["_id"] = {"$nin": exclude_ids}
        u_filter["worker_id"] = {"$nin": exclude_ids}
    
    if users_collection.find_one(u_filter):
        return False
        
    # 2. Check worker_collection (Employee HR Profiles)
    w_filter = {
        "email": {"$regex": f"^{re.escape(email_norm)}$", "$options": "i"},
        "isDraft": {"$ne": True}
    }
    if exclude_ids:
        w_filter["_id"] = {"$nin": exclude_ids}
        
    if worker_collection.find_one(w_filter):
        return False
        
    return True

def convert_to_24h(time_str):
    if not time_str:
        return ""
    try:
        # Check if already HH:mm
        datetime.strptime(time_str, '%H:%M')
        return time_str
    except ValueError:
        pass
    
    try:
        # Try 12-hour format with AM/PM
        t = datetime.strptime(time_str, '%I:%M %p')
        return t.strftime('%H:%M')
    except ValueError:
        pass
        
    return time_str

def safe_float(value):
    """Safely convert value to float, default to 0.0 on error."""
    try:
        return float(value) if value is not None else 0.0
    except (ValueError, TypeError):
        return 0.0
def ensure_list(val):
    if not val:
        return []
    if isinstance(val, list):
        # Resolve nested stringified lists like ["['comp1']"]
        flat = []
        for v in val:
            if isinstance(v, str) and v.startswith('[') and v.endswith(']'):
                try:
                    parsed = ast.literal_eval(v)
                    if isinstance(parsed, list):
                        flat.extend(parsed)
                    else:
                        flat.append(parsed)
                except:
                    flat.append(v)
            else:
                flat.append(v)
        return flat
    if isinstance(val, str):
        val = val.strip()
        if not val or val.lower() in ['none', 'null', 'nan']:
            return []
        if val.startswith('[') and val.endswith(']'):
            try:
                parsed = ast.literal_eval(val)
                if isinstance(parsed, list):
                    return parsed
                return [parsed]
            except:
                pass
        if ',' in val:
            return [v.strip() for v in val.split(',')]
        return [val]
    return [val]

def extreme_norm(val):
    """Normalize strings to remove all spaces, underscores and case sensitivity for robust matching."""
    if isinstance(val, list):
        val = val[0] if val else ""
    s = str(val or "").strip().lower()
    return s.replace(' ', '').replace('_', '').replace('-', '')

