@app.before_request
def tenancy_middleware():
    g.tenant_id = request.headers.get('X-Tenant-Id')
    g.company_id = request.headers.get('X-Company-Id')
    g.branch_id = request.headers.get('X-Branch-Id')
    g.user_role = None
    g.user_id = None
    
    auth_header = request.headers.get('Authorization')
    if auth_header and auth_header.startswith('Bearer '):
        token = auth_header.split(" ")[1]
        try:
            payload = jwt.decode(token, JWT_SECRET, algorithms=[JWT_ALGORITHM])
            g.user_role = payload.get('role')
            g.user_id = payload.get('sub') or payload.get('user_id')
        except:
            pass

@app.errorhandler(ValueError)
def handle_value_error(e):
    if "Tenancy validation failed" in str(e):
        return jsonify({"success": False, "error": str(e)}), 400
    # Allow other ValueErrors to pass through or be handled generically
    return jsonify({"success": False, "error": str(e)}), 400

