def save_system_settings(settings, company_name=None, branch_name=None):
    # Consistently normalize IDs to prevent mismatches between roles
    c_norm = str(company_name or '').strip().lower().replace(' ', '')
    b_norm = str(branch_name or '').strip().lower().replace(' ', '')
    
    settings_id = "system_settings"
    if c_norm and b_norm:
        settings_id = f"system_settings_{c_norm}_{b_norm}"
        settings["branch_name"] = branch_name # Keep original for display
        settings["company_name"] = company_name # Keep original for display
    elif c_norm:
        settings_id = f"system_settings_{c_norm}"
        settings["company_name"] = company_name # Keep original for display

    settings["_id"] = settings_id
    settings_collection.replace_one({"_id": settings_id}, settings, upsert=True)
    logger.info(f"System settings saved for {settings_id}")
TEST_USERS = []
def to_json_safe(data):
    """Recursively converts documents to JSON-serializable format."""
    if isinstance(data, list):
        return [to_json_safe(item) for item in data]
    if isinstance(data, dict):
        return {key: to_json_safe(value) for key, value in data.items()}
    if isinstance(data, datetime):
        return data.isoformat()
    return data
def document_to_dict(doc, visited=None):
    if visited is None:
        visited = set()
    
    # Handle primitives
    if doc is None or isinstance(doc, (int, float, str, bool)):
        return doc
        
    # Prevent circular references
    obj_id = id(doc)
    if obj_id in visited:
        return "<Circular Reference>"
    
    if isinstance(doc, list):
        visited.add(obj_id)
        return [document_to_dict(v, visited) for v in doc]
    if isinstance(doc, dict):
        visited.add(obj_id)
        return {str(key): document_to_dict(value, visited) for key, value in doc.items()}
    if isinstance(doc, datetime):
        return doc.isoformat()
    return doc
# NEW: Function to clean expired combo offers
# NEW: Function to clean expired combo offers
def clean_expired_combo_offers(filter_query=None):
    """Delete expired combo offers from the database."""
    try:
        current_time = datetime.now(timezone.utc)
        offers = combo_offers_collection.find(filter_query)
        deleted_count = 0
        for offer in offers:
            if 'offer_end_time' in offer and offer['offer_end_time']:
                try:
                    end_time_str = str(offer['offer_end_time'])
                    if end_time_str.endswith('Z'):
                        end_time_str = end_time_str.replace('Z', '+00:00')
                    end_time = datetime.fromisoformat(end_time_str)
                    if end_time.tzinfo is None:
                        end_time = end_time.replace(tzinfo=timezone.utc)
                    if current_time > end_time:
                        combo_offers_collection.delete_one({'_id': offer['_id']})
                        logger.info(f"Automatically deleted expired combo offer: {offer['_id']} (ended {end_time})")
                        deleted_count += 1
                except (ValueError, TypeError) as e:
                    logger.error(f"Invalid offer_end_time for combo offer {offer['_id']}: {str(e)}")
            else:
                # If no end time, keep it (always active)
                continue
        logger.info(f"Cleanup job completed: Deleted {deleted_count} expired combo offers")
        return True
    except Exception as e:
        logger.error(f"Error in clean_expired_combo_offers: {str(e)}")
        return False
def has_associated_sales(item_name):
    """Check if any sale contains this item_name in its items."""
    sales = sales_collection.find()
    for sale in sales:
        items = sale.get('items', [])
        if any(sale_item.get('item_name') == item_name for sale_item in items):
            return True
    return False
# NEW: Function to get sales for a specific item
def get_sales_for_item(item_name):
    """Get all sales containing the specified item_name."""
    sales = sales_collection.find()
    relevant_sales = []
    for sale in sales:
        items = sale.get('items', [])
        if any(sale_item.get('item_name') == item_name for sale_item in items):
            relevant_sales.append(sale)
    return relevant_sales
