@app.route('/api/get-email-settings', methods=['GET'])
def get_email_settings():
    try:
        user_id, role = get_request_user_info()
        company_name = request.headers.get('X-Company-Name') or request.args.get('company')
        branch_name = request.headers.get('X-Branch-Name') or request.args.get('branch')
        
        # STANDARD: Handle 'All' or empty company context for Group Admins
        if not company_name or str(company_name).lower() in ['all', 'all companies', 'none', 'null', 'undefined', '[object object]']:
             # If no company selected, return 200 with success: false to avoid console errors
             logger.info(f"get_email_settings: REJECTED - Invalid company context: '{company_name}'")
             return jsonify({"success": False, "message": "Please select a company to view its email settings."}), 200

        # Use find with the multi-tenant matching logic in SQLiteCollection
        # We search by company_name AND fallback to 'company'
        query = {'$or': [{'company_name': company_name}, {'company': company_name}]}
        all_settings = list(email_settings_collection.find(query))
        logger.info(f"get_email_settings: Found {len(all_settings)} entries for company '{company_name}'")
        
        # Helper to safely serialize MongoDB-like docs
        def safe_serialize(d):
            if not d: return d
            res = dict(d)
            if '_id' in res and not isinstance(res['_id'], str):
                res['_id'] = str(res['_id'])
            return res

        # 1. Try to find setting specifically for this branch
        settings = None
        if branch_name and branch_name.lower() not in ['all', 'all branches']:
            for s in all_settings:
                # Support both list of branch names and comma-separated string
                branches = s.get('branch_names', [])
                if isinstance(branches, str):
                    branches = [b.strip() for b in branches.split(',') if b.strip()]
                
                if branch_name in branches:
                    settings = s
                    break
        
        # 2. Try to find company-wide setting (no specific branches or Default tagged)
        if not settings:
            for s in all_settings:
                branches = s.get('branch_names', [])
                if isinstance(branches, str):
                    branches = [b.strip() for b in branches.split(',') if b.strip()]
                
                if not branches or "Company-wide (Default)" in branches:
                    settings = s
                    break
                    
        # 3. Last Resort: Global setting
        if not settings:
             settings = email_settings_collection.find_one({'_id': 'email_settings'})

        if settings:
            return jsonify({"success": True, "settings": safe_serialize(settings)}), 200
        
        return jsonify({"success": False, "message": "No email settings found for the selected context."}), 200
    except Exception as e:
        logger.error(f"Error retrieving email settings: {str(e)}")
        return jsonify({"success": False, "error": f"Failed to retrieve email settings: {str(e)}"}), 500

@app.route('/api/list-email-settings', methods=['GET'])
def list_email_settings():
    try:
        user_id, role = get_request_user_info()
        company_name = request.headers.get('X-Company-Name')
        branch_name = request.headers.get('X-Branch-Name')
        
        if not company_name:
            logger.warning("list_email_settings: No company name provided in headers.")
            return jsonify([]), 200
            
        # Get all settings for company - Support both field names for robustness
        query = {'$or': [{'company_name': company_name}, {'company': company_name}]}
        all_company_settings = list(email_settings_collection.find(query))
        
        logger.info(f"list_email_settings: Found {len(all_company_settings)} entries for company '{company_name}'")
        
        # If Company Admin or Group Admin, show everything for that company
        if role in ['company_admin', 'admin', 'group_admin', 'super_admin']:
             return jsonify(convert_objectid_to_str(all_company_settings)), 200

        # If it's a branch user, we MUST have a branch_name to filter strictly
        if not branch_name:
            return jsonify([]), 200
            
        # Strict Filter for branch users: 
        filtered = []
        for s in all_company_settings:
            b_list = s.get('branch_names', [])
            if isinstance(b_list, str):
                b_list = [b.strip() for b in b_list.split(',') if b.strip()]
            
            if branch_name in b_list:
                filtered.append(s)
                
        return jsonify(convert_objectid_to_str(filtered)), 200
    except Exception as e:
        logger.error(f"Error listing email settings: {str(e)}")
        return jsonify({'error': str(e)}), 500

@app.route('/api/test-email-settings', methods=['POST'])
def test_email_settings():
    try:
        data = request.get_json()
        email_type = data.get('email_type', 'gmail')
        
        if email_type == 'gmail':
            email = data.get('email')
            password = data.get('password')
            smtp_server = 'smtp.gmail.com'
            smtp_port = 587 # Default for starttls
        else:
            email = data.get('username') # Use username for login
            password = data.get('password')
            smtp_server = data.get('smtp_server')
            smtp_port = int(data.get('smtp_port', 587))

        if not all([email, password, smtp_server]):
            return jsonify({"success": False, "error": "Missing required fields for test"}), 400
            
        # For Port 465, we use smtplib.SMTP_SSL. For 587 we use starttls.
        if smtp_port == 465:
            with smtplib.SMTP_SSL(smtp_server, smtp_port) as server:
                server.login(email, password)
        else:
            with smtplib.SMTP(smtp_server, smtp_port) as server:
                server.starttls()
                server.login(email, password)
                
        logger.info(f"SMTP authentication successful for {email} on {smtp_server}")
        return jsonify({"success": True, "message": "Email settings are valid"}), 200
    except smtplib.SMTPAuthenticationError as e:
        logger.error(f"SMTP Authentication Error during test: {str(e)}")
        return jsonify({"success": False, "error": "Invalid credentials. Please check your username and password."}), 400
    except socket.gaierror as e:
        logger.error(f"Socket GAI Error (Bad SMTP host) during test: {str(e)}")
        return jsonify({"success": False, "error": f"Invalid SMTP Server address. The server could not be found."}), 400
    except smtplib.SMTPException as e:
        logger.error(f"SMTP Error during test: {str(e)}")
        return jsonify({"success": False, "error": f"SMTP error: {str(e)}"}), 400
    except Exception as e:
        logger.error(f"Unexpected error testing email settings: {str(e)}")
        return jsonify({"success": False, "error": f"Failed to test email settings: {str(e)}"}), 400

