def manage_backup_limit():
    try:
        backup_files = [f for f in os.listdir(app.config['UPLOAD_FOLDER']) if f.endswith('.xlsx')]
        backup_files = sorted(
            backup_files,
            key=lambda x: os.path.getctime(os.path.join(app.config['UPLOAD_FOLDER'], x)),
            reverse=True
        )
        for old_file in backup_files[MAX_BACKUPS:]:
            os.remove(os.path.join(app.config['UPLOAD_FOLDER'], old_file))
            logger.info(f"Deleted old backup: {old_file}")
    except Exception as e:
        logger.error(f"Error managing backup limit: {str(e)}")
def create_backup():
    try:
        if openpyxl is None:
            return False, "Excel library not available. Please install openpyxl."

        # --- Multi-Tenancy & Permission Resolution ---
        user_id, role = get_request_user_info()
        backup_collections = request.headers.get('X-Backup-Collections', 'all')
        company_name = request.headers.get('X-Company-Name') or request.headers.get('company_name') or request.args.get('company') or request.args.get('company_name')
        branch_name = request.headers.get('X-Branch-Name') or request.headers.get('branch_name') or request.args.get('branch') or request.args.get('branch_name')
        
        logger.info(f"Backup Request: user={user_id}, role={role}, company={company_name}, branch={branch_name}")

        # --- Email Settings Lookup ---
        branch_settings = None
        company_settings = None
        settings = None
        
        # Normalize and filter out 'All' for settings lookup
        active_company = company_name if company_name and company_name.lower() not in ['all', 'all companies'] else None
        
        if active_company:
            # Find settings matching the requested company context
            all_company_settings = list(email_settings_collection.find({'company_name': active_company}))
            if not all_company_settings:
                 all_company_settings = list(email_settings_collection.find({'company': active_company}))
            
            # 1. Specific Branch Settings
            if branch_name and branch_name.lower() not in ['all', 'all branches']:
                for s in all_company_settings:
                    if branch_name in s.get('branch_names', []):
                        branch_settings = s
                        break
            
            # 2. Company-wide Fallback
            for s in all_company_settings:
                branches = s.get('branch_names', [])
                if not branches or "Company-wide (Default)" in branches:
                    company_settings = s
                    break

        # Determine primary settings for SMTP connection
        if branch_settings:
            settings = branch_settings
            logger.info(f"Using branch-specific email settings for '{branch_name}'")
        elif company_settings:
            settings = company_settings
            logger.info(f"Using company-wide email settings for '{active_company}'")

        # 3. Last Resort Fallbacks
        if not settings:
            # Try global system setting
            settings = email_settings_collection.find_one({'_id': 'email_settings'})
            
        if not settings and active_company:
            # If still nothing, try to just fine ANY setting the user is authorized to use
             settings = email_settings_collection.find_one({'company_name': active_company}) or email_settings_collection.find_one({'company': active_company})

        if not settings:
            logger.error(f"No email settings configured for context: company={company_name}, branch={branch_name}")
            return False, "Email settings not configured. Please configure in Email Settings before proceeding with the backup."

        # Verify email settings have necessary SMTP fields
        email_type = settings.get('email_type', 'gmail')
        if email_type == 'gmail':
            smtp_user = settings.get('email')
            smtp_pass = settings.get('password')
            from_email = settings.get('from_email')
            smtp_server = 'smtp.gmail.com'
            smtp_port = 587
        else:
            smtp_user = settings.get('username')
            smtp_pass = settings.get('password')
            from_email = settings.get('sender_email') or settings.get('email')
            smtp_server = settings.get('smtp_server')
            smtp_port = int(settings.get('smtp_port', 587) or 587)

        if not all([smtp_user, smtp_pass, from_email, smtp_server]):
            logger.error(f"Missing email configuration for {email_type}")
            return False, f"Email configuration missing or incomplete for {email_type}. Please check your Email Settings."

        # --- Proceed with Backup Generation ---
        wb = openpyxl.Workbook()
        wb.remove(wb.active)
        
        collections = {
            'active_orders': activeorders_collection,
            'address_structures': address_structures_collection,
            'attendance': attendance_collection,
            'brands': brands_collection,
            'combo_offers': combo_offers_collection,
            'company_details': company_details_collection,
            'customer_groups': customer_groups_collection,
            'customers': customers_collection,
            'departments': departments_collection,
            'email_settings': email_settings_collection,
            'email_tokens': email_tokens_collection,
            'employee_designations': employee_designations_collection,
            'employee_schedule_assign': employee_schedule_assign_collection,
            'employee_types': employee_type_collection,
            'employees': worker_collection,
            'item_groups': item_groups_collection,
            'items': items_collection,
            'kitchen_saved_orders': kitchen_saved_collection,
            'kitchens': kitchens_collection,
            'leave_allocation_assign': leave_allocation_collection,
            'leave_applications': leave_apply_collection,
            'leave_types': leave_types_collection,
            'logo_details': logo_details_collection,
            'new_employee': worker_collection,
            'order_counters': order_counters_collection,
            'picked_up_items': picked_up_collection,
            'pos_closing_entries': pos_closing_collection,
            'pos_opening_entries': opening_collection,
            'print_settings': print_settings_collection,
            'purchase_invoices': purchase_invoices_collection,
            'purchase_items': purchase_items_collection,
            'purchase_orders': purchase_orders_collection,
            'purchase_receipts': purchase_receipts_collection,
            'purchase_sales': purchase_sales_collection,
            'role_permissions': role_permissions_collection,
            'salary_slips': salary_slips_collection,
            'sales': sales_collection,
            'schedule_master': schedule_master_collection,
            'shift_master': shift_master_collection,
            'supplier_groups': supplier_group_collection,
            'suppliers': suppliers_collection,
            'system_settings': settings_collection,
            'tables': tables_collection,
            'trip_reports': tripreports_collection,
            'uoms': uoms_collection,
            'users': users_collection,
            'variants': variants_collection,
            'vat': vat_collection,
            'vehicle_management': vehiclemanagement_collection,
            'working_days': working_days_collection
        }
        
        if backup_collections and backup_collections.lower() != 'all':
            requested = [c.strip() for c in backup_collections.split(',')]
            collections = {k: v for k, v in collections.items() if k in requested}
        
        for collection_name, collection in collections.items():
            filter_query = {}
            try:
                from flask import has_request_context
                if has_request_context():
                    page_id_map = {
                        'active_orders': 'pos',
                        'sales': 'sales_report',
                        'purchase_orders': 'purchase',
                        'employees': 'employee_list',
                        'users': 'user_management',
                        'items': 'item_list',
                        'customers': 'customer_list',
                        'suppliers': 'supplier_list',
                        'attendance': 'view_attendance',
                        'departments': 'employee_departments',
                        'employee_designations': 'employee_designations',
                        'employee_types': 'employee_types',
                        'uoms': 'uoms',
                        'branches': 'branches',
                        'kitchen_saved_orders': 'kitchen',
                        'kitchens': 'kitchen',
                        'leave_allocation_assign': 'leave_allocation',
                        'leave_applications': 'leave_application',
                        'leave_types': 'leave_types',
                        'purchase_invoices': 'purchase',
                        'purchase_receipts': 'purchase',
                        'trip_reports': 'trip_report',
                        'vehicle_management': 'vehicle_management',
                        'variants': 'variants',
                        'brands': 'brands', 'tax_master': 'tax_master',
                        'vat': 'vat',
                        'item_groups': 'item_groups',
                        'salary_slips': 'salary_list',
                        'employee_schedule_assign': 'schedule_master',
                        'pos_closing_entries': 'pos_reports',
                        'pos_opening_entries': 'pos_reports',
                        'print_settings': 'terminal_settings',
                        'combo_offers': 'combo_offers',
                        'customer_groups': 'customer_list',
                        'supplier_groups': 'supplier_list',
                        'employee_departments': 'employee_departments',
                        'employee_designations': 'employee_designations',
                        'employee_types': 'employee_types'
                    }
                    target_page_id = page_id_map.get(collection_name, collection_name)
                    can_access, filter_query = get_data_scope_filter(target_page_id)
                    if not can_access:
                        continue
                    
                    # The branch filtering is fully handled by get_data_scope_filter natively,
                    # which correctly includes {$exists: False} for global company records.

            except Exception as e:
                logger.error(f"Backup isolation error for {collection_name}: {e}")

            ws = wb.create_sheet(title=collection_name)
            data_list = list(collection.find(filter_query))
            if not data_list:
                ws.append(['No data'])
                continue
                
            # Strip price fields for specific collections but keep headers
            if collection_name in ['items', 'purchase_items']:
                price_fields = ['price', 'selling_price', 'purchase_price', 'rate', 'standard_rate']
                for doc in data_list:
                    for pf in price_fields:
                        doc[pf] = ""
            
            headers = list(data_list[0].keys())
            ws.append(headers)
            for doc in data_list:
                row = [str(doc.get(header, '')) if isinstance(doc.get(header), (list, dict)) else doc.get(header, '') for header in headers]
                ws.append(row)
                
        if not wb.sheetnames:
            wb.create_sheet(title="Empty_Backup")
        
        buffer = BytesIO()
        wb.save(buffer)
        buffer.seek(0)
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        # Include branch name in filename if specific branch is selected
        if branch_name and branch_name.lower() != 'all':
            clean_branch = "".join([c if c.isalnum() else "_" for c in branch_name])
            filename = f'backup_{clean_branch}_restaurant_data_{timestamp}.xlsx'
        else:
            filename = f'backup_restaurant_data_{timestamp}.xlsx'
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        with open(file_path, 'wb') as f:
            f.write(buffer.getvalue())
        manage_backup_limit()

        # --- Send Email ---
        msg = MIMEMultipart()
        sender_name = settings.get('sender_name')
        if sender_name:
            msg['From'] = f"{sender_name} <{from_email}>"
        else:
            msg['From'] = from_email
            
        # --- RECIPIENT LOGIC (Dual Email Requirement) ---
        to_emails_set = set()
        
        def extract_email(s_dict):
            if not s_dict: return None
            return s_dict.get('receiver_email') or s_dict.get('sender_email') or s_dict.get('email') or s_dict.get('username')
        
        # 1. If branch selected, add branch email AND company email (if they exist)
        if branch_name and branch_name.lower() != 'all':
            b_email = extract_email(branch_settings)
            c_email = extract_email(company_settings)
            if b_email: to_emails_set.add(b_email)
            if c_email: to_emails_set.add(c_email)
        else:
            # 2. If 'all' selected, send ONLY to company wide email
            c_email = extract_email(company_settings)
            if c_email: to_emails_set.add(c_email)
        
        # Fallback to the parsed `to_email` from primary settings if the set is empty
        to_email = settings.get('receiver_email') or (settings.get('email') if email_type == 'gmail' else settings.get('sender_email'))
        if not to_emails_set and to_email:
            to_emails_set.add(to_email)
        if not to_emails_set:
            to_emails_set.add(from_email)

        to_emails = list(to_emails_set)
        msg['To'] = ", ".join(to_emails)
        msg['Subject'] = f'Restaurant Data Backup - {timestamp}'
        body = f'Backup of restaurant data generated on {datetime.now().strftime("%Y-%m-%d %H:%M:%S")}.'
        msg.attach(MIMEText(body, 'plain'))
        
        with open(file_path, 'rb') as f:
            attachment = MIMEBase('application', 'octet-stream')
            attachment.set_payload(f.read())
            encoders.encode_base64(attachment)
            attachment.add_header('Content-Disposition', f'attachment; filename={filename}')
            msg.attach(attachment)

        # SMTP Connection logic
        if smtp_port == 465:
            with smtplib.SMTP_SSL(smtp_server, smtp_port) as server:
                server.login(smtp_user, smtp_pass)
                server.send_message(msg)
        else:
            with smtplib.SMTP(smtp_server, smtp_port) as server:
                server.starttls()
                server.login(smtp_user, smtp_pass)
                server.send_message(msg)
        
        logger.info(f"Backup created and emailed: {filename}")
        return True, f"Backup created successfully: {filename}"

    except smtplib.SMTPAuthenticationError as e:
        logger.error(f"SMTP Authentication Error: {str(e)}")
        return False, "Invalid email or app password. Please check your Email Settings and ensure an App Password is used for Gmail."
    except socket.gaierror as e:
        logger.error(f"Socket GAI Error (Bad SMTP host): {str(e)}")
        return False, "Invalid SMTP Server address. The server could not be found."
    except smtplib.SMTPException as e:
        logger.error(f"SMTP Error: {str(e)}")
        return False, f"SMTP error: {str(e)}"
    except Exception as e:
        logger.error(f"Error in backup: {str(e)}")
        return False, str(e)
@app.route('/api/backup-to-excel', methods=['GET'])
def backup_to_excel():
    """Create a backup and serve it as a download."""
    try:
        success, message = create_backup()
        if not success:
            return jsonify({"error": message}), 400
        filename = message.split(': ')[1]
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        with open(file_path, 'rb') as f:
            file_data = f.read()
        return Response(
            file_data,
            mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
            headers={'Content-Disposition': f'attachment; filename={filename}'}
        )
    except Exception as e:
        logger.error(f"Error serving backup file: {str(e)}")
        return jsonify({"error": f"Server error: {str(e)}"}), 500
@app.route('/api/backup-info', methods=['GET'])
def backup_info():
    """Retrieve information about existing backups."""
    try:
        active_branch = request.headers.get('X-Branch-Name') or request.args.get('branch')
        
        backup_files = [f for f in os.listdir(app.config['UPLOAD_FOLDER']) if f.endswith('.xlsx')]
        backups = []
        for filename in backup_files:
            # Filter logic:
            # 1. If active_branch is specified, show files starting with backup_{branch}_ or the legacy global backup format
            # 2. If no branch (admin/all), show everything
            if active_branch and active_branch.lower() != 'all':
                clean_branch = "".join([c if c.isalnum() else "_" for c in active_branch])
                branch_prefix = f'backup_{clean_branch}_'
                if not filename.startswith(branch_prefix):
                    continue

            file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
            stat = os.stat(file_path)
            backups.append({
                'filename': filename,
                'date': datetime.fromtimestamp(stat.st_ctime).strftime('%Y-%m-%d %H:%M:%S'),
                'size': f"{stat.st_size / 1024:.2f} KB"
            })
        backups.sort(key=lambda x: x['date'], reverse=True)
        return jsonify(backups)
    except Exception as e:
        logger.error(f"Error retrieving backup info: {str(e)}")
        return jsonify({"error": f"Server error: {str(e)}"}), 500
@app.route('/api/download-backup', methods=['POST'])
def download_backup():
    """Download a specific backup file."""
    try:
        data = request.get_json()
        filename = data.get('filename')
        if not filename:
            return jsonify({"error": "Filename not provided"}), 400
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        if not os.path.exists(file_path):
            return jsonify({"error": "Backup file not found"}), 404
        with open(file_path, 'rb') as f:
            file_data = f.read()
        return Response(
            file_data,
            mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
            headers={'Content-Disposition': f'attachment; filename={filename}'}
        )
    except Exception as e:
        logger.error(f"Error downloading backup {filename}: {str(e)}")
        return jsonify({"error": f"Server error: {str(e)}"}), 500
@app.route('/api/get-backup-interval', methods=['GET'])
def get_backup_interval():
    try:
        settings = get_system_settings()
        interval = settings.get('backup_interval_hours', 6)
        return jsonify({"interval": interval}), 200
    except Exception as e:
        logger.error(f"Error fetching backup interval: {str(e)}")
        return jsonify({"error": str(e)}), 500
@app.route('/api/set-backup-interval', methods=['POST'])
def set_backup_interval():
    try:
        data = request.get_json()
        interval = data.get('interval')
        if interval is None or not isinstance(interval, int) or interval <= 0:
            return jsonify({"error": "Invalid interval. Must be a positive integer."}), 400
        settings = get_system_settings()
        settings['backup_interval_hours'] = interval
        save_system_settings(settings)
        # Update scheduler
        if schedule:
            schedule.clear('backup')
            schedule.every(interval).hours.do(create_backup).tag('backup')
            logger.info(f"Backup interval updated to every {interval} hours")
        return jsonify({"message": "Backup interval updated successfully"}), 200
    except Exception as e:
        logger.error(f"Error setting backup interval: {str(e)}")
        return jsonify({"error": str(e)}), 500
def start_scheduler():
    if schedule:
        settings = get_system_settings()
        interval = settings.get('backup_interval_hours', 6)
        schedule.every(interval).hours.do(create_backup).tag('backup')
        threading.Thread(target=run_scheduler, daemon=True).start()
        logger.info(f"Scheduler started with backup every {interval} hours")
def run_scheduler():
    while True:
        schedule.run_pending()
        time.sleep(60)
@app.route('/api/shutdown', methods=['POST'])
def shutdown():
    global shutdown_flag
    logger.info("Shutdown requested")
    try:
        func = request.environ.get('werkzeug.server.shutdown')
        if func:
            func()
            logger.info("Werkzeug server shutdown initiated")
            return jsonify({"message": "Server shutting down"}), 200
        shutdown_flag = True
        logger.info("Setting shutdown flag for Waitress")
        def exit_process():
            time.sleep(1)
            logger.info("Exiting Python process")
            os._exit(0)
        threading.Thread(target=exit_process, daemon=True).start()
        return jsonify({"message": "Server shutting down"}), 200
    except Exception as e:
        logger.error(f"Shutdown error: {str(e)}")
        return jsonify({"message": "Error during shutdown", "error": str(e)}), 500

@app.route('/api/danger/clear-company-data', methods=['POST'])
def clear_company_data():
    """Wipes all transactional and master data for the caller's identified company."""
    try:
        user_id, role = get_request_user_info()
        if role != 'admin':
            return jsonify({"error": "Admin access required"}), 403
            
        active_company = request.headers.get('X-Company-Name') or request.args.get('company')
        if not active_company:
             user_doc = users_collection.find_one({'_id': user_id})
             if user_doc:
                 active_company = user_doc.get('company')
        
        if not active_company:
            return jsonify({"error": "No company identified to clear"}), 400
            
        collection_names = [
            'active_orders', 'attendance', 'brands', 'tax_master', 'combo_offers', 
            'customers', 'employee_designations', 'employees', 'item_groups',
            'items', 'kitchens', 'leave_applications', 'pos_closing_entries',
            'pos_opening_entries', 'purchase_invoices', 'purchase_orders', 
            'purchase_receipts', 'purchase_sales', 'salary_slips', 'sales',
            'tables', 'variants', 'customer_groups', 'supplier_groups', 'suppliers'
        ]
        
        counts = {}
        for cname in collection_names:
            coll = SQLiteCollection(conn, cname)
            result = coll.delete_many({"company_name": active_company})
            counts[cname] = result.deleted_count
            
        logger.warning(f"DANGER: Company data cleared for {active_company} by user {user_id}. Counts: {counts}")
        return jsonify({"message": f"Data cleared for company: {active_company}", "details": counts}), 200
    except Exception as e:
        logger.error(f"Error in clear_company_data: {e}")
        return jsonify({"error": str(e)}), 500

