@app.route('/api/admin/migrate-branch-tags', methods=['POST'])
def migrate_branch_tags():
    """
    Admin-only: Tags all existing documents that have a company_name but NO branch_name
    with the branch_name provided. Use this to fix data created before strict branch
    isolation was enforced.
    
    Body: { "company_name": "Kyle Solution", "branch_name": "Kyle 1" }
    """
    try:
        user_id, role = get_request_user_info()
        if role not in ['admin', 'company_admin']:
            return jsonify({"error": "Admin access required"}), 403

        data = request.get_json()
        company_name = data.get('company_name', '').strip()
        branch_name = data.get('branch_name', '').strip()

        if not company_name or not branch_name:
            return jsonify({"error": "company_name and branch_name are required"}), 400

        # All transactional collections that should have branch_name
        transactional_collections = [
            items_collection, customers_collection, sales_collection, tables_collection,
            pos_closing_collection, opening_collection, kitchens_collection,
            item_groups_collection, picked_up_collection, variants_collection,
            employees_collection, activeorders_collection, tripreports_collection,
            purchase_items_collection, suppliers_collection, purchase_orders_collection,
            purchase_receipts_collection, purchase_invoices_collection, purchase_sales_collection,
            print_settings_collection, combo_offers_collection, vat_collection,
            customer_groups_collection, logo_details_collection, supplier_group_collection,
            attendance_collection, brands_collection, leave_apply_collection,
            salary_slips_collection, notifications_collection
        ]

        results = {}
        company_aliases = [company_name, company_name.lower(), company_name.title(), company_name.upper()]

        for col in transactional_collections:
            try:
                col_name = col.collection_name if hasattr(col, 'collection_name') else str(col)
                # Find docs with matching company but missing/empty branch_name
                all_docs = col.find({'$or': [{'company_name': {'$in': company_aliases}}, {'company': {'$in': company_aliases}}]})
                updated = 0
                for doc in all_docs:
                    existing_branch = doc.get('branch_name') or doc.get('branch')
                    if not existing_branch:
                        col.update_one({'_id': doc['_id']}, {'$set': {'branch_name': branch_name}})
                        updated += 1
                results[col_name] = updated
            except Exception as ce:
                results[str(col)] = f"Error: {str(ce)}"

        total = sum(v for v in results.values() if isinstance(v, int))
        logger.info(f"Branch migration: Tagged {total} docs with branch_name='{branch_name}' for company='{company_name}'")
        return jsonify({
            "message": f"Migration complete. Tagged {total} documents with branch '{branch_name}'.",
            "details": results
        }), 200

    except Exception as e:
        logger.error(f"Error in migrate_branch_tags: {e}\n{traceback.format_exc()}")
        return jsonify({"error": str(e)}), 500

# NEW: Endpoint to get hidden items with sales details
@app.route('/api/hidden-items', methods=['GET'])
def get_hidden_items():
    try:
        hidden_items = items_collection.find({'is_hidden': True})
        enhanced_items = []
        for item in hidden_items:
            item_name = item.get('item_name')
            sales = get_sales_for_item(item_name)
            enhanced_item = convert_objectid_to_str(item)
            if sales:
                enhanced_item['sales'] = [convert_objectid_to_str(sale) for sale in sales]
                total_records = len(sales)
                total_qty_sold = sum(sum(item_obj.get('quantity', 0) for item_obj in sale.get('items', []) if item_obj.get('item_name') == item_name) for sale in sales)
                subtotal = sum(float(sale.get('total', 0)) for sale in sales)
                vat_total = sum(float(sale.get('vat_amount', 0)) for sale in sales)
                grand_total = sum(float(sale.get('grand_total', 0)) for sale in sales)
                currency = sales[0].get('invoice_currency', 'AED')
            else:
                enhanced_item['sales'] = []
                total_records = 0
                total_qty_sold = 0
                subtotal = 0
                vat_total = 0
                grand_total = 0
                currency = 'AED'
            enhanced_item['summary'] = {
                'total_records': total_records,
                'total_qty_sold': total_qty_sold,
                'currency': currency,
                'subtotal': round(subtotal, 2),
                'vat': round(vat_total, 2),
                'grand_total': round(grand_total, 2)
            }
            enhanced_items.append(enhanced_item)
        return jsonify(enhanced_items), 200
    except Exception as e:
        logger.error(f"Error fetching hidden items: {str(e)}")
        return jsonify({"error": str(e)}), 500
