@app.route('/api/sales/<invoice_no>', methods=['DELETE'])
def delete_sale(invoice_no):
    try:
        # Check Permission
        user_id, role = get_request_user_info()
        if not check_user_permission(role, 'sales_report', 'canDelete') and not check_user_permission(role, 'pos', 'canDelete'):
             logger.warning(f"Permission denied: User {user_id} ({role}) tried to delete sale")
             return jsonify({"error": "You do not have permission to delete sales"}), 403

        result = sales_collection.delete_one({'invoice_no': invoice_no.strip()})
        if result.deleted_count == 0:
            return jsonify({"error": "Sale not found"}), 404
        logger.info(f"Sale deleted: {invoice_no}")
        return jsonify({"message": "Sale deleted successfully"}), 200
    except Exception as e:
        logger.error(f"Error deleting sale {invoice_no}: {str(e)}")
        return jsonify({"error": str(e)}), 500
