    @app.route('/api/login', methods=['POST'])
    def login():
        try:
            # Force bypass tenancy filter for login to ignore any existing old tokens
            g.skip_tenancy = True
            
            data = request.get_json()
            email = data.get('email')
            password = data.get('password')
            
            logger.info(f"DEBUG: Attempting login for raw email: '{email}'")

            if not email or not password:
                logger.error("Email or password missing in login request")
                return jsonify({"error": "Email and password are required"}), 400

            email_lower = email.strip().lower()

            # Super Admin hardcoded bypass
            if email_lower == "admin@kylesolution.com" and password == "admin123":
                # Gather all tenants and companies to send back for Super Admin
                all_tenants = list(tenants_collection.find({}, {'_id': 1, 'tenant_name': 1}))
                all_companies = list(companies_collection.find({}, {'_id': 1, 'company_name': 1, 'tenant_id': 1}))
                all_branches = list(branches_collection.find({}, {'_id': 1, 'branch_name': 1, 'company_id': 1, 'tenant_id': 1}))
                return jsonify({
                    "success": True,
                    "message": "Login successful",
                    "user": {
                        "id": "super-admin-001",
                        "email": email_lower,
                        "username": "Super Admin",
                        "role": "Super Admin"
                    },
                    "tenants": all_tenants,
                    "companies": all_companies,
                    "branches": all_branches,
                    "token": "fake-jwt-token-for-superadmin"
                }), 200

            # Step 1: Find user exclusively by Email (Globally Unique)
            email_lower = email.strip().lower()
            logger.info(f"DEBUG: Stripped lowercase email: '{email_lower}'")
            user = users_collection.find_one({"email": email_lower})
            logger.info(f"DEBUG: Found user in DB: {user is not None}")
            if user:
                logger.info(f"DEBUG: User doc keys: {list(user.keys())}")
            
            # If not found in users_collection, it might be an employee from worker_collection
            if not user:
                emp_record = worker_collection.find_one({"email": email_lower})
                if emp_record:
                    # Map employee fields to user-like structure for the login session
                    user = {
                        "_id": str(emp_record.get('_id')),
                        "email": emp_record.get('email'),
                        "password": emp_record.get('password'),
                        "role": "employee",
                        "username": emp_record.get('username'),
                        "firstName": emp_record.get('name'),
                        "phone_number": emp_record.get('phoneNumber'),
                        "company": emp_record.get('company_name') or emp_record.get('company'),
                        "companies": emp_record.get('company_name') if isinstance(emp_record.get('company_name'), list) else [emp_record.get('company_name')] if emp_record.get('company_name') else [],
                        "branches": emp_record.get('branch_names', [])
                    }

            if not user:
                logger.warning(f"Login attempt failed: Email '{email}' not found in system.")
                return jsonify({"error": "Invalid credentials"}), 401

            # Step 2: Verify Password
            try:
                pwd_doc = user.get('password')
                if not pwd_doc or not bcrypt.checkpw(password.encode('utf-8'), str(pwd_doc).encode('utf-8')):
                    logger.warning(f"Password mismatch for user: {email}")
                    return jsonify({"error": "Invalid credentials"}), 401
            except Exception as e:
                logger.error(f"Password comparison error for {email}: {e}")
                return jsonify({"error": "Internal authentication error"}), 500

            # Login Success
            logger.info(f"Login successful for {email} (Role: {user.get('role')})")

            # Compute consistent user_identifier
            user_identifier = user.get('email', '').split('@')[0] if '@' in user.get('email', '') else user.get('email', '')

            # FIXED: Compute consistent user_identifier to match frontend logic - Use email as key for consistency
            user_identifier = user.get('email', '').split('@')[0] if '@' in user.get('email', '') else user.get('email', '')
            logger.info(f"Computed user_identifier for query: '{user_identifier}' from user doc: email='{user.get('email')}', username='{user.get('username')}'")

            token_payload = {
                'user_id': user['_id'],
                'role': user.get('role', 'bearer'), # FIXED: Include role for permission checks
                'exp': datetime.now(timezone.utc) + timedelta(seconds=JWT_EXP_DELTA_SECONDS)
            }
            token = jwt.encode(token_payload, JWT_SECRET, algorithm=JWT_ALGORITHM)
            user_converted = convert_objectid_to_str(user)

            # Enhanced logic for requires_opening_entry and requires_closing_entry
            # Find any 'Open' session for this user
            active_opening = opening_collection.find_one({
                "user": user_identifier,
                "status": "Open"
            })
            
            logger.info(f"Active opening check for {user_identifier}: {'Found' if active_opening else 'None'}")

            requires_opening_entry = active_opening is None
            requires_closing_entry = False
            pos_opening_entry = None

            if active_opening:
                pos_opening_entry = active_opening.get('name')
                # Optional: Only require closing if sales exist (current logic)
                sales = list(sales_collection.find({
                    "pos_opening_entry": active_opening['name']
                }))
                requires_closing_entry = len(sales) > 0
                logger.info(f"Opening {pos_opening_entry} found. Sales count: {len(sales)}. Requires closing: {requires_closing_entry}")

            # NEW: Fetch linked Employee Record to provide IDs for filtering
            employee_id_val = None
            employee_id_code = None
            try:
                emp_record = worker_collection.find_one({'email': user.get('email')})
                if emp_record:
                    employee_id_val = str(emp_record.get('_id'))
                    employee_id_code = emp_record.get('employeeId')
            except Exception as e:
                logger.warning(f"Failed to fetch employee record for {user.get('email')}: {e}")

            # NEW: SAAS Multi-Tenant Context Building
            role_name = user.get('role', 'Branch Admin')
            tenant_id = user.get('tenant_id')
            company_id = user.get('company_id')
            branch_id = user.get('branch_id')

            assigned_tenants = []
            assigned_companies = []
            assigned_branches = []

            if role_name == 'Super Admin' or user.get('email') == 'admin@kylesolution.com':
                role_name = 'Super Admin'
                assigned_tenants = list(tenants_collection.find({}))
                assigned_companies = list(companies_collection.find({}))
                assigned_branches = list(branches_collection.find({}))
            elif role_name == 'Tenant Admin':
                assigned_companies = list(companies_collection.find({'tenant_id': tenant_id}))
                assigned_branches = list(branches_collection.find({'tenant_id': tenant_id}))
            elif role_name == 'Company Admin':
                assigned_branches = list(branches_collection.find({'company_id': company_id}))
            # Branch Admin gets no extra lists, just the context

            response = {
                "message": "Login successful",
                "token": token,
                "user": {
                    "id": user_converted['_id'],
                    "username": user_identifier,
                    "email": user.get('email', ''),
                    "role": role_name,
                    "tenant_id": tenant_id,
                    "company_id": company_id,
                    "branch_id": branch_id,
                    "tenant_name": user.get('tenant_name'),
                    "company_name": user.get('company_name'),
                    "branch_name": user.get('branch_name'),
                    "tenants": assigned_tenants,
                    "companies": assigned_companies,
                    "branches": assigned_branches
                },
                "requires_opening_entry": requires_opening_entry,
                "requires_closing_entry": requires_closing_entry,
                "pos_opening_entry": pos_opening_entry
            }
            return jsonify(response), 200

        except KeyError as ke:
            logger.error(f"KeyError during login response building: {str(ke)}")
            return jsonify({"error": f"Internal error: Missing user field {str(ke)}"}), 500
        except Exception as e:
            logger.error(f"Login error: {e}\n{traceback.format_exc()}")
            return jsonify({"error": f"An internal server error occurred during login: {str(e)}"}), 500

