    @app.route('/api/companies-public', methods=['GET'])
    def get_public_companies():
        try:
            if company_details_collection is None or companies_collection is None:
                logger.error("collections are None in get_public_companies")
                return jsonify({"error": "Database initialization in progress"}), 503
            
            # Unconditional public listing: Always show all companies
            all_companies = list(company_details_collection.find({}))
            onboarded_companies = list(companies_collection.find({}))
            
            # Merge both collections securely
            all_companies.extend(onboarded_companies)
            
            # Use unique names to avoid duplicates
            companies = []
            seen_names = set()
            
            for c in all_companies:
                name = c.get("company_name")
                if name and name not in seen_names:
                    seen_names.add(name)
                    
                    parent_company_name = c.get("parent_company") or c.get("parent")
                    if not parent_company_name and c.get("company_type") == "group_member":
                        created_by = c.get("created_by")
                        if created_by:
                            parent_doc = company_details_collection.find_one({
                                "created_by": created_by,
                                "company_type": "group_admin"
                            })
                            if parent_doc:
                                parent_company_name = parent_doc.get("company_name")

                    companies.append({
                        "name": name,
                        "type": c.get("company_type") or c.get("type") or "single",
                        "created_at": c.get("created_at") or c.get("created_at", datetime.now(timezone.utc).isoformat()),
                        "parent_company": parent_company_name,
                        "created_by": str(c.get("created_by")) if c.get("created_by") else None
                    })
            
            # Sort chronologically so newly added companies appear at the bottom
            companies.sort(key=lambda x: x.get('created_at', ''))
            return jsonify(companies), 200
        except Exception as e:
            logger.error(f"Error fetching public companies: {str(e)}\n{traceback.format_exc()}")
            return jsonify({"error": "Failed to fetch companies", "message": str(e)}), 500

