    @app.route('/api/companies-public', methods=['POST'])
    def create_public_company():
        try:
            data = request.get_json()
            comp_name = data.get('company_name')
            admin_username = data.get('adminUsername')
            admin_password = data.get('adminPassword')
            admin_email = data.get('email')
            
            if not all([comp_name, admin_username, admin_password, admin_email]):
                return jsonify({"message": "Missing required fields (including Email)"}), 400
            
            if company_details_collection.find_one({"company_name": comp_name}):
                return jsonify({"message": "Company already exists"}), 400
            
            # Step 1: Global Email Uniqueness Check
            if not is_email_unique(admin_email):
                return jsonify({"message": "Email address is already in use globally. Please use a unique email."}), 400
            
            
            # 1. Create Company Details with type 'single'
            company_details_collection.insert_one({
                "company_name": comp_name,
                "company_type": "single",
                "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
            })
            
            # 2. Create Company Admin User
            hashed_password = bcrypt.hashpw(admin_password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
            c_email = admin_email
            
            company_admin_user = {
                "email": c_email,
                "password": hashed_password,
                "plain_password": admin_password,
                "role": "company_admin",
                "username": admin_username,
                "firstName": f"{comp_name} Admin",
                "phone_number": "",
                "company": comp_name,
                "companies": [comp_name],
                "branches": [],
                "pos_profile": "POS-001",
                "status": "Active",
                "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
            }
            users_collection.insert_one(company_admin_user)
            
            # 3. Seed Permissions for this master user
            all_pages = ALL_SYSTEM_PAGES
            permissions_list = [
                {"pageId": pid, "canRead": True, "canWrite": True, "canDelete": True, "dataAccess": "ALL"} 
                for pid in all_pages
            ]
            
            if not role_permissions_collection.find_one({'role': 'company_admin'}):
                role_permissions_collection.insert_one({
                    "role": "company_admin",
                    "permissions": permissions_list,
                    "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
                })

            logger.info(f"Quick Company Created: {comp_name} with admin {admin_username}")
            return jsonify({"message": "Company and Admin created successfully"}), 201
        except Exception as e:
            logger.error(f"Error in quick company creation: {str(e)}")
            return jsonify({"error": str(e)}), 500
    @app.route('/api/branches-public/<company_name>', methods=['GET'])
    def get_branches_public(company_name):
        try:
            if branches_collection is None:
                logger.error("branches_collection is None in get_branches_public")
                return jsonify({"error": "Database initialization in progress"}), 503

            # ROBUST: Handle case-insensitivity, spelling typos (KyleSolution/KyleSoution), and both 'company_name' and 'company' fields
            target_comp = str(company_name).strip()
            
            # Find the company_ids from both collections
            comp_ids = []
            if companies_collection is not None:
                comps = companies_collection.find({"company_name": {"$regex": f"^{target_comp}$", "$options": "i"}})
                comp_ids.extend([c.get("_id") for c in comps if c.get("_id")])
            
            if company_details_collection is not None:
                comps = company_details_collection.find({"$or": [
                    {"company_name": {"$regex": f"^{target_comp}$", "$options": "i"}},
                    {"company": {"$regex": f"^{target_comp}$", "$options": "i"}}
                ]})
                comp_ids.extend([c.get("_id") for c in comps if c.get("_id")])
                
            if 'kylesolution' in target_comp.lower().replace(" ", "") or 'kylesoution' in target_comp.lower().replace(" ", ""):
                query = {
                    "$or": [
                        {"company_name": {"$regex": "^KyleSolution$", "$options": "i"}},
                        {"company_name": {"$regex": "^KyleSoution$", "$options": "i"}},
                        {"company": {"$regex": "^KyleSolution$", "$options": "i"}},
                        {"company": {"$regex": "^KyleSoution$", "$options": "i"}},
                        {"company_id": {"$in": comp_ids}}
                    ],
                    "auto_synced": {"$ne": True}
                }
            else:
                query = {
                    "$or": [
                        {"company_name": {"$regex": f"^{target_comp}$", "$options": "i"}},
                        {"company": {"$regex": f"^{target_comp}$", "$options": "i"}},
                        {"company_id": {"$in": comp_ids}}
                    ],
                    "auto_synced": {"$ne": True}
                }
            branches = branches_collection.find(query)
            branch_names = sorted(list(set(b.get('branch_name') for b in branches if b.get('branch_name'))))
            return jsonify(branch_names), 200
        except Exception as e:
            logger.error(f"Error fetching public branches for {company_name}: {str(e)}\n{traceback.format_exc()}")
            return jsonify({"error": "Failed to fetch branches", "message": str(e)}), 500
    @app.route('/api/branches', methods=['GET'])
    def get_branches():
        try:
            company_name = request.headers.get('X-Company-Name') or request.args.get('company_name')
            
            if not company_name:
                return jsonify([]), 200

            target_comps = [c.strip() for c in str(company_name).split(',') if c.strip()]
            
            unique_names = set()

            for tc in target_comps:
                if tc.lower() in ['all', 'all companies']:
                    # Return all branches the authenticated user is allowed to see
                    user_id, role = get_request_user_info()
                    user_doc = users_collection.find_one({'_id': user_id})
                    if user_doc:
                        tenant_id = user_doc.get('tenant_id')
                        company_id = user_doc.get('company_id')
                        if role in ['Tenant Admin', 'Super Admin', 'Group Admin'] and tenant_id:
                            all_branches = list(branches_collection.find({'tenant_id': tenant_id}))
                        elif role == 'Company Admin' and company_id:
                            all_branches = list(branches_collection.find({'company_id': company_id}))
                        else:
                            all_branches = list(branches_collection.find({}))
                        for b in all_branches:
                            name = b.get('branch_name') or b.get('branch') or b.get('name')
                            if name:
                                unique_names.add(name)
                    continue

                # Step 1: Try to resolve company ΓåÆ company_id via SaaS companies table
                import re
                escaped = re.escape(tc)
                company_doc = companies_collection.find_one({
                    '$or': [
                        {'company_name': {'$regex': f'^{escaped}$', '$options': 'i'}},
                        {'company': {'$regex': f'^{escaped}$', '$options': 'i'}}
                    ]
                })

                if company_doc:
                    # NEW: query branches by company_id (correct SaaS way)
                    cid = company_doc.get('_id')
                    matched = list(branches_collection.find({'company_id': cid}))
                    for b in matched:
                        name = b.get('branch_name') or b.get('branch') or b.get('name')
                        if name:
                            unique_names.add(name)
                else:
                    # LEGACY FALLBACK: query by company_name field
                    conditions = [
                        {'company_name': {'$regex': f'^{escaped}$', '$options': 'i'}},
                        {'company': {'$regex': f'^{escaped}$', '$options': 'i'}}
                    ]
                    matched = list(branches_collection.find({'$or': conditions}))
                    for b in matched:
                        name = b.get('branch_name') or b.get('branch') or b.get('name')
                        if name:
                            unique_names.add(name)

            return jsonify(sorted(list(unique_names))), 200
        except Exception as e:
            logger.error(f"Error fetching branches: {str(e)}")
            return jsonify({"error": "Failed to fetch branches"}), 500


    @app.route('/api/branches-public/<company_name>', methods=['POST'])
    def add_public_branch(company_name):
        try:
            data = request.get_json()
            branch_name = data.get('branch_name')
            branch_username = data.get('username')
            branch_password = data.get('password')
            branch_email = data.get('email')
            
            if not all([branch_name, branch_username, branch_password]):
                return jsonify({"message": "Missing required fields: branch_name, username, password"}), 400
            
            # 1. Check if company exists
            if not company_details_collection.find_one({"company_name": company_name}):
                return jsonify({"message": f"Company '{company_name}' not found"}), 404
                
            # 2. Check if branch already exists for this company
            if branches_collection.find_one({"company_name": company_name, "branch_name": branch_name}):
                return jsonify({"message": "Branch already exists for this company"}), 400
                
            # Username Uniqueness removed: Allow duplicate usernames across companies/branches
            # if users_collection.find_one({"username": branch_username}):
            #     return jsonify({"message": "Username already taken"}), 400
            

            # 4. Create Branch Record
            branches_collection.insert_one({
                "branch_name": branch_name,
                "company_name": company_name,
                "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
            })
            
            # 5. Create Branch User (Cashier)
            hashed_password = bcrypt.hashpw(branch_password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
            safe_email = branch_email if branch_email else f"{branch_username}_{branch_name.replace(' ', '')}@temp.com"
            safe_email = safe_email.strip().lower()
            
            if users_collection.find_one({"email": safe_email}):
                 # If email exists, try to make it unique
                 safe_email = f"{branch_username}_{int(datetime.now().timestamp())}@temp.com"

            branch_user = {
                "email": safe_email,
                "password": hashed_password,
                "role": "branch_admin",
                "username": branch_username,
                "firstName": f"{branch_name} Admin",
                "phone_number": data.get('phone_number', ''),
                "company": company_name,
                "companies": [company_name],
                "branches": [{"company": company_name, "branch": branch_name}],
                "status": "Active",
                "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
            }
            users_collection.insert_one(branch_user)
            
            logger.info(f"Branch Created: {branch_name} for company {company_name} with user {branch_username}")
            return jsonify({"message": "Branch and User created successfully"}), 201
        except Exception as e:
            logger.error(f"Error in add_public_branch: {str(e)}")
            return jsonify({"error": str(e)}), 500

    @app.route('/api/branches-detailed/<company_name>', methods=['GET'])
    def get_branches_detailed(company_name):
        try:
            # --- New: Support 'All' for Group Admins ---
            if company_name.lower() == 'all':
                user_id, role = get_request_user_info()
                user_doc = users_collection.find_one({'_id': user_id})
                if not user_doc:
                     return jsonify([]), 200
                
                # Normalize role for check
                role_norm = str(user_doc.get('role', '')).lower().replace(' ', '').replace('_', '')
                if role_norm not in ['groupadmin', 'superadmin', 'admin']:
                     # If not a master admin, fall back to their primary company
                     company_name = user_doc.get('company') or user_doc.get('company_name')
                     query = {"company_name": company_name, "auto_synced": {"$ne": True}}
                else:
                    # Get all authorized companies
                    allowed_companies = list(user_doc.get('companies', []))
                    primary_comp = user_doc.get('company') or user_doc.get('company_name')
                    if primary_comp and primary_comp not in allowed_companies:
                        allowed_companies.append(primary_comp)
                    
                    query = {"company_name": {"$in": allowed_companies}, "auto_synced": {"$ne": True}}
            else:
                # ROBUST: Handle case-insensitivity, spelling typos, and both fields
                target_comp = str(company_name).strip()
                if 'kylesolution' in target_comp.lower().replace(" ", "") or 'kylesoution' in target_comp.lower().replace(" ", ""):
                    query = {
                        "$or": [
                            {"company_name": {"$regex": "^KyleSolution$", "$options": "i"}},
                            {"company_name": {"$regex": "^KyleSoution$", "$options": "i"}},
                            {"company": {"$regex": "^KyleSolution$", "$options": "i"}},
                            {"company": {"$regex": "^KyleSoution$", "$options": "i"}}
                        ],
                        "auto_synced": {"$ne": True}
                    }
                else:
                    query = {
                        "$or": [
                            {"company_name": {"$regex": f"^{target_comp}$", "$options": "i"}},
                            {"company": {"$regex": f"^{target_comp}$", "$options": "i"}}
                        ],
                        "auto_synced": {"$ne": True}
                    }
            
            branches = branches_collection.find(query)
            detailed_branches = []
            for b in branches:
                b_converted = convert_objectid_to_str(b)
                # Count users in this branch - use the branch's specific company
                current_b_company = b.get('company_name')
                branch_users = users_collection.find({"company": current_b_company})
                user_count = 0
                for u in branch_users:
                    user_branches = u.get('branches', [])
                    if isinstance(user_branches, str):
                        try:
                            import ast
                            user_branches = ast.literal_eval(user_branches)
                        except:
                            user_branches = []
                    
                    if not isinstance(user_branches, list):
                        user_branches = []

                    for ub in user_branches:
                        if isinstance(ub, dict) and ub.get('branch') == b.get('branch_name'):
                            user_count += 1
                            break
                b_converted['user_count'] = user_count
                detailed_branches.append(b_converted)
            
            return jsonify(detailed_branches), 200
        except Exception as e:
            logger.error(f"Error fetching detailed branches for {company_name}: {str(e)}")
            return jsonify({"error": "Failed to fetch detailed branches"}), 500

    @app.route('/api/branch-user-details/<company_name>/<branch_name>', methods=['GET'])
    def get_branch_user_details(company_name, branch_name):
        try:
            # Check new schema first
            branch_user = users_collection.find_one({
                "company_name": company_name,
                "branch_name": branch_name,
                "role": "Branch Admin"
            })
            
            if not branch_user:
                # Fallback to old schema
                all_users = users_collection.find({"company": company_name})
                for user in all_users:
                    user_branches = ensure_list(user.get("branches", []))
                    is_assigned = any(isinstance(b, dict) and b.get("company") == company_name and b.get("branch") == branch_name for b in user_branches)
                    if not is_assigned:
                        user_branch_names = ensure_list(user.get("branch_names", []))
                        is_assigned = branch_name in user_branch_names
                    if is_assigned:
                        branch_user = user
                        break
            
            if not branch_user:
                return jsonify({"message": "No user found for this branch"}), 404
            
            return jsonify({
                "firstName": branch_user.get("firstName", ""),
                "email": branch_user.get("email", branch_user.get("username", "")),
                "phone_number": branch_user.get("phone_number", ""),
                "username": branch_user.get("username", ""),
                "password": branch_user.get("plain_password", "") # Return plain password for UI
            }), 200
        except Exception as e:
            logger.error(f"Error fetching branch user details: {str(e)}")
            return jsonify({"error": str(e)}), 500

    @app.route('/api/branches-public/<company_name>/<branch_name>', methods=['DELETE'])
    def delete_public_branch(company_name, branch_name):
        try:
            # 1. Delete from branches_collection (all matching records)
            branches_collection.delete_many({"company_name": company_name, "branch_name": branch_name})
            
            # 2. Clean up ALL user records that reference this branch to prevent auto-sync resurrection
            # We must be very aggressive here.
            all_users = users_collection.find() 
            
            # Helper for fuzzy company match (e.g. "KyleSolution" == "Kyle Solution")
            def fuzzy_match(c1, c2):
                if not c1 or not c2: return True # If company not specified, assume match
                return c1.replace(" ", "").lower() == c2.replace(" ", "").lower()

            for user in all_users:
                modified = False
                
                # Handle 'branches' list of dicts
                user_branches = ensure_list(user.get("branches", []))
                original_branches_len = len(user_branches)
                new_branches = [b for b in user_branches if not (isinstance(b, dict) and b.get("branch") == branch_name and fuzzy_match(b.get("company"), company_name))]
                if len(new_branches) != original_branches_len:
                    user["branches"] = new_branches
                    modified = True
                
                # Handle 'branch_names' list of strings
                user_branch_names = ensure_list(user.get("branch_names", []))
                original_names_len = len(user_branch_names)
                new_branch_names = [b for b in user_branch_names if b != branch_name]
                if len(new_branch_names) != original_names_len:
                    user["branch_names"] = new_branch_names
                    modified = True
                
                # Singular 'branch_name' override
                if user.get("branch_name") == branch_name:
                    user["branch_name"] = ""
                    modified = True
                
                if modified:
                    # If the user is a branch-level login and has NO branch info left, delete it
                    has_any_branch = len(user.get("branches", [])) > 0 or len(user.get("branch_names", [])) > 0 or user.get("branch_name")
                    if not has_any_branch and user.get("role") != "company_admin" and user.get("role") != "admin":
                        users_collection.delete_one({"_id": user["_id"]})
                    else:
                        users_collection.replace_one({"_id": user["_id"]}, user)
            
            logger.info(f"Deleted branch: {branch_name} for {company_name} and cleaned up user references.")
            return jsonify({"message": "Branch deleted successfully"}), 200
        except Exception as e:
            logger.error(f"Error deleting branch: {str(e)}\n{traceback.format_exc()}")
            return jsonify({"error": str(e)}), 500

    @app.route('/api/companies-public/<company_name>', methods=['DELETE'])
    def delete_public_company(company_name):
        try:
            # Delete from company_details_collection
            company_result = company_details_collection.delete_many({"company_name": company_name})
            
            # Delete associated branches
            branches_result = branches_collection.delete_many({"company_name": company_name})
            
            # Delete associated users
            users_result = users_collection.delete_many({"company": company_name})
            
            # Note: We don't delete data from all transactional collections here as it might be too destructive.
            # Usually, archive or soft-delete is better, but following the "delete branch" pattern.
            
            if company_result.deleted_count > 0:
                logger.info(f"Company deleted: {company_name}. Associated branches and users removed.")
                return jsonify({"message": "Company and all associated data deleted successfully"}), 200
            else:
                return jsonify({"message": "Company not found"}), 404
        except Exception as e:
            logger.error(f"Error deleting company: {str(e)}")
            return jsonify({"error": str(e)}), 500

    @app.route('/api/companies-public/<old_name>', methods=['PUT'])
    def update_public_company(old_name):
        logger.info(f"=== UPDATE_PUBLIC_COMPANY START: {old_name} ===")
        try:
            data = request.get_json()
            logger.info(f"Payload: {data}")
            new_name = data.get('new_name')
            admin_username = data.get('adminUsername')
            admin_password = data.get('adminPassword')
            admin_email = data.get('email')
            
            if not any([new_name, admin_username, admin_password, admin_email]):
                return jsonify({"message": "At least one field (name, username, password, or email) is required"}), 400
            
            
            effective_company_name = old_name

            # 1. Update Company Name if provided
            if new_name and new_name != old_name:
                if company_details_collection.find_one({"company_name": new_name}):
                    return jsonify({"message": "Company name already exists"}), 400
                
                # Update Company and Branches collections
                company_details_collection.update_many({"company_name": old_name}, {"$set": {"company_name": new_name}})
                branches_collection.update_many({"company_name": old_name}, {"$set": {"company_name": new_name}})
                
                # Update users (Iteration required for SQLiteCollection compatibility)
                all_users = users_collection.find()
                for user in all_users:
                    modified = False
                    if user.get("company") == old_name:
                        user["company"] = new_name
                        modified = True
                    
                    if old_name in user.get("companies", []):
                        user["companies"] = [new_name if c == old_name else c for c in user["companies"]]
                        modified = True
                    
                    branches = user.get("branches", [])
                    for b in branches:
                        if b.get("company") == old_name:
                            b["company"] = new_name
                            modified = True
                    
                    if modified:
                        users_collection.replace_one({"_id": user["_id"]}, user)
                
                # Update other transactional collections (top-level company_name)
                collections_to_update = [
                    items_collection, customers_collection, sales_collection, tables_collection,
                    pos_closing_collection, opening_collection, kitchens_collection, item_groups_collection,
                    kitchen_saved_collection if 'kitchen_saved_collection' in globals() else None, 
                    picked_up_collection, variants_collection, employees_collection,
                    activeorders_collection, tripreports_collection, purchase_items_collection, suppliers_collection,
                    purchase_orders_collection, purchase_receipts_collection, purchase_invoices_collection,
                    purchase_sales_collection, print_settings_collection, combo_offers_collection, vat_collection,
                    customer_groups_collection, logo_details_collection, supplier_group_collection,
                    attendance_collection, brands_collection, leave_apply_collection, salary_slips_collection,
                    notifications_collection
                ]
                
                for col in collections_to_update:
                    if col:
                        col.update_many({"company_name": old_name}, {"$set": {"company_name": new_name}})
                
                logger.info(f"Renamed company from {old_name} to {new_name}")
                effective_company_name = new_name

            # 2. Update Admin Credentials if provided
            if admin_username or admin_password or admin_email:
                # Find any administrative user for this company
                admin_roles = ["company_admin", "group_admin", "admin"]
                c_admin = users_collection.find_one({
                    "role": {"$in": admin_roles},
                    "$or": [
                        {"company": effective_company_name},
                        {"company_name": effective_company_name}
                    ]
                })
                
                # If still not found, search by username similarity as fallback
                if not c_admin:
                    c_admin = users_collection.find_one({
                        "role": {"$in": admin_roles},
                        "username": {"$regex": f"^{admin_username or 'admin'}", "$options": "i"}
                    })
                
                logger.info(f"Admin search result for {effective_company_name}: {c_admin.get('_id') if c_admin else 'None'}")
                
                if c_admin:
                    update_fields = {}
                    # Username Uniqueness removed
                    if admin_username:
                        logger.info(f"Checking uniqueness for new username: {admin_username} (current: {c_admin.get('username')})")
                        # if admin_username != c_admin.get('username'):
                        #     existing = users_collection.find_one({"username": admin_username})
                        #     if existing and existing.get("company") != effective_company_name and existing.get("company_name") != effective_company_name:
                        #         logger.warning(f"Username {admin_username} taken by user {existing['_id']} from company {existing.get('company')}")
                        #         return jsonify({"message": "Username already taken"}), 400
                        update_fields["username"] = admin_username
                    
                    if admin_password:
                        # FIX: Define hashed_password here
                        hashed_password = bcrypt.hashpw(admin_password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
                        update_fields["password"] = hashed_password
                        update_fields["plain_password"] = admin_password # Update plain text record
                    
                    if admin_email and admin_email.strip().lower() != c_admin.get('email', '').strip().lower():
                        if not is_email_unique(admin_email, exclude_id=c_admin["_id"]):
                            return jsonify({"message": "Email already in use globally"}), 400
                        update_fields["email"] = admin_email.strip().lower()
                    
                    if update_fields:
                        users_collection.update_one({"_id": c_admin["_id"]}, {"$set": update_fields})
                        logger.info(f"Updated admin credentials for company {effective_company_name}")
                else:
                    # FALLBACK: Create company_admin if missing
                    if not admin_username or not admin_password:
                        return jsonify({"message": "Both username and password are required to initialize master login"}), 400
                    
                    # if users_collection.find_one({"username": admin_username}):
                    #     return jsonify({"message": "Username already taken"}), 400
                    
                    # Create the record with all standard fields
                    new_id = str(uuid.uuid4())
                    hashed_password = bcrypt.hashpw(admin_password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
                    c_email = admin_email if admin_email else f"admin_{effective_company_name.replace(' ', '_').lower()}@internal.com"
                    
                    new_admin = {
                        "_id": new_id,
                        "email": c_email,
                        "password": hashed_password,
                        "plain_password": admin_password, # Store for management visibility
                        "role": "company_admin",
                        "username": admin_username,
                        "firstName": f"{effective_company_name} Admin",
                        "phone_number": "",
                        "company": effective_company_name,
                        "company_name": effective_company_name,
                        "companies": [effective_company_name],
                        "branches": [], 
                        "pos_profile": "POS-001",
                        "status": "Active",
                        "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
                    }
                    users_collection.insert_one(new_admin)
                    logger.info(f"Created new company_admin for {effective_company_name}")
                    
                    # Ensure permissions seeded
                    all_pages = ALL_SYSTEM_PAGES
                    permissions_list = [
                        {"pageId": pid, "canRead": True, "canWrite": True, "canDelete": True, "dataAccess": "ALL"} 
                        for pid in all_pages
                    ]
                    if not role_permissions_collection.find_one({'role': 'company_admin'}):
                        role_permissions_collection.insert_one({
                            "role": "company_admin", "permissions": permissions_list,
                            "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
                        })

                    logger.info(f"Created missing company_admin for {effective_company_name}")

            return jsonify({"message": "Company updated successfully"}), 200
        except Exception as e:
            logger.error(f"Error updating company: {str(e)}")
            return jsonify({"error": str(e)}), 500

    @app.route('/api/branches-public/<company_name>/<old_branch_name>', methods=['PUT'])
    def update_public_branch(company_name, old_branch_name):
        try:
            data = request.get_json()
            new_branch_name = data.get('new_branch_name')
            
            # User detail fields
            first_name = data.get('firstName')
            phone = data.get('phone_number')
            email = data.get('email')
            username = data.get('username')
            password = data.get('password')

            if not any([new_branch_name, first_name, phone, email, username, password]):
                return jsonify({"message": "At least one field is required for update"}), 400

            
            effective_branch_name = old_branch_name

            if new_branch_name and new_branch_name != old_branch_name:
                # Check if new branch name exists for this company
                if branches_collection.find_one({"company_name": company_name, "branch_name": new_branch_name}):
                    return jsonify({"message": "Branch name already exists for this company"}), 400

                # Update branches collection
                branches_collection.update_many(
                    {"company_name": company_name, "branch_name": old_branch_name},
                    {"$set": {"branch_name": new_branch_name}}
                )
                
                # Update users' branch lists
                all_users = users_collection.find({"company": company_name})
                for user in all_users:
                    modified = False
                    branches = user.get("branches", [])
                    for b in branches:
                        if b.get("company") == company_name and b.get("branch") == old_branch_name:
                            b["branch"] = new_branch_name
                            modified = True
                    
                    if modified:
                        users_collection.replace_one({"_id": user["_id"]}, user)

                # Update other collections (transactional)
                collections_to_update = [
                    items_collection, customers_collection, sales_collection, tables_collection,
                    pos_closing_collection, opening_collection, kitchens_collection, item_groups_collection,
                    kitchen_saved_collection, picked_up_collection, variants_collection, employees_collection,
                    activeorders_collection, tripreports_collection, purchase_items_collection, suppliers_collection,
                    purchase_orders_collection, purchase_receipts_collection, purchase_invoices_collection,
                    purchase_sales_collection, print_settings_collection, combo_offers_collection, vat_collection,
                    customer_groups_collection, logo_details_collection, supplier_group_collection,
                    attendance_collection, brands_collection, leave_apply_collection, salary_slips_collection,
                    notifications_collection
                ]
                
                for col in collections_to_update:
                    try:
                        col.update_many(
                            {"company_name": company_name, "branch_name": old_branch_name},
                            {"$set": {"branch_name": new_branch_name}}
                        )
                    except:
                        pass
                
                effective_branch_name = new_branch_name

            # Update associated branch user (Cashier) if details provided
            if first_name or phone or email or username or password:
                # Find the user associated with this branch
                branch_user = None
                
                # 1. Search by email first (Primary unique identifier)
                if email:
                    branch_user = users_collection.find_one({"email": email.strip().lower()})
                
                # 2. Fallback: Search by branch name within company
                if not branch_user:
                    all_company_users = users_collection.find({"company": company_name})
                    for u in all_company_users:
                        for b in u.get('branches', []):
                            if b.get('branch') == effective_branch_name:
                                branch_user = u
                                break
                        if branch_user: break
                
                # 3. Fallback: Search by username
                if not branch_user and username:
                    branch_user = users_collection.find_one({"username": username.strip()})
                
                if branch_user:
                    update_fields = {}
                    if first_name: update_fields["firstName"] = first_name
                    if phone: update_fields["phone_number"] = phone
                    
                    # Email/Username update with conflict check (excluding current user)
                    if email and email.strip().lower() != branch_user.get('email', '').strip().lower():
                        if not is_email_unique(email.strip().lower(), exclude_id=branch_user["_id"]):
                            return jsonify({"message": f"Email {email} already in use globally"}), 400
                        update_fields["email"] = email.strip().lower()
                    
                    if username and username.strip() != branch_user.get('username', '').strip():
                        # Username Uniqueness removed
                        # if users_collection.find_one({"username": username.strip()}):
                        #     return jsonify({"message": f"Username {username} already in use"}), 400
                        update_fields["username"] = username.strip()
                        
                    if password:
                        update_fields["password"] = bcrypt.hashpw(password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
                        update_fields["plain_password"] = password # Update plain text record
                    
                    # Ensure branch is correctly linked if it was a fallback match
                    existing_branches = branch_user.get('branches', [])
                    branch_linked = any(b.get('branch') == effective_branch_name and b.get('company') == company_name for b in existing_branches)
                    if not branch_linked:
                        existing_branches.append({"company": company_name, "branch": effective_branch_name})
                        update_fields["branches"] = existing_branches
                        update_fields["company"] = company_name # Ensure company is also set

                    if update_fields:
                        users_collection.update_one({"_id": branch_user["_id"]}, {"$set": update_fields})
                        logger.info(f"Updated/Linked user details for branch {effective_branch_name}")
                else:
                    # 3. Last Resort: Create the user if they don't exist yet but details were sent
                    if username and (password or email):
                        logger.info(f"Creating missing branch user record for {effective_branch_name}")
                        safe_email = email if email else f"{username}_{effective_branch_name.replace(' ', '')}@temp.com"
                        safe_email = safe_email.strip().lower()
                        
                        if not is_email_unique(safe_email):
                             return jsonify({"message": "Cannot create user: Email already exists globally"}), 400
                             
                        new_branch_user = {
                            "email": safe_email,
                            "password": bcrypt.hashpw(password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8') if password else "123", # default if missing
                            "plain_password": password if password else "123",
                            "role": "Cashier", 
                            "username": username.strip(),
                            "firstName": first_name or username,
                            "phone_number": phone or "",
                            "company": company_name,
                            "companies": [company_name],
                            "branches": [{"company": company_name, "branch": effective_branch_name}],
                            "status": "Active",
                            "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
                        }
                        users_collection.insert_one(new_branch_user)
                        logger.info(f"Auto-created missing branch user on update: {username}")

            return jsonify({"message": "Branch updated successfully"}), 200
        except Exception as e:
            logger.error(f"Error updating branch: {str(e)}")
            return jsonify({"error": str(e)}), 500

    @app.route('/api/register', methods=['POST'])
    def register():
        try:
            data = request.get_json()
            required_fields = ['email', 'password', 'firstName', 'phone_number']
            if not all(field in data for field in required_fields):
                return jsonify({"message": "Missing required fields"}), 400
            
            email = data['email'].strip().lower()
            if not email:
                return jsonify({"message": "Valid email is required"}), 400

            if not is_email_unique(email):
                return jsonify({"message": "Email already registered globally"}), 400
            
            
            # Check company admin passwords and emails if provided
            companies_data = data.get('companies', [])
            for comp_obj in companies_data:
                c_email = comp_obj.get('email', '').strip().lower()
                if c_email and not is_email_unique(c_email):
                    return jsonify({"error": f"The email address '{c_email}' for company '{comp_obj.get('name')}' is already in use globally."}), 400

            hashed_password = bcrypt.hashpw(data['password'].encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
            
            # Extract companies and branches from data
            companies_data = data.get('companies', []) # List of objects {name, adminUsername, adminPassword}
            branches_data = data.get('branches', []) # List of objects {company: '', branch: ''}
            
            # Extract names for legacy/simple fields
            company_names = [c.get('name') for c in companies_data if c.get('name')]
            
            # FIXED: Prioritize explicit main_company (HQ) for group admins
            main_company = data.get('main_company') or (company_names[0] if company_names else data.get('company', 'POS 8'))
            
            new_user = {
                "email": data['email'],
                "password": hashed_password,
                "plain_password": data['password'], # Store for management visibility
                "role": data.get('role', 'admin'), # Default to admin for registered users
                "username": data.get('username', data['firstName']),
                "firstName": data['firstName'],
                "phone_number": data['phone_number'],
                "company": main_company,
                "companies": company_names,
                "branches": branches_data,
                "pos_profile": data.get('pos_profile', 'POS-001'),
                "status": "Active",
                "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
            }
            
            result = users_collection.insert_one(new_user)
            user_id = new_user['_id']
            
            # Automatically create company details and company_admin users
            is_group_admin = data.get('role') == 'group_admin'
            
            # NEW: Create Parent / HQ Company record for Group Admin
            req_main_company = data.get('main_company', '').strip()
            if is_group_admin and req_main_company:
                if not company_details_collection.find_one({"company_name": req_main_company}):
                    company_details_collection.insert_one({
                        "company_name": req_main_company,
                        "company_type": "group_admin",
                        "created_by": user_id,
                        "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
                    })
                    logger.info(f"Created Parent Group Company: {req_main_company}")

            for comp_obj in companies_data:
                comp_name = comp_obj.get('name')
                if not comp_name: continue
                
                # Create/Update Company Details with type 'group_member'
                if not company_details_collection.find_one({"company_name": comp_name}):
                    company_details_collection.insert_one({
                        "company_name": comp_name,
                        "company_type": "group_member" if is_group_admin else "single",
                        "created_by": user_id,
                        "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
                    })
                
                # Create individual company_admin accounts if credentials provided
                c_username = comp_obj.get('adminUsername')
                c_password = comp_obj.get('adminPassword')
                c_email_input = comp_obj.get('email')
                
                if c_username and c_password:
                        # Check if company admin already exists FOR THIS COMPANY (prevent duplicate creation)
                        if not users_collection.find_one({"role": "company_admin", "company": comp_name}):
                            c_hashed_password = bcrypt.hashpw(c_password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
                            
                            # Use provided email if available, otherwise fallback
                            c_email = c_email_input if c_email_input else f"admin_{comp_name.replace(' ', '_').lower()}@internal.com"
                            c_email = c_email.strip().lower()
                            
                            company_admin_user = {
                                "email": c_email,
                                "password": c_hashed_password,
                                "plain_password": c_password, # Store for management visibility
                                "role": "company_admin",
                                "username": c_username,
                                "firstName": f"{comp_name} Admin",
                                "phone_number": data['phone_number'],
                                "company": comp_name,
                                "companies": company_names,
                                "branches": [], # Company admin sees all branches (aggregated view)
                                "pos_profile": data.get('pos_profile', 'POS-001'),
                                "status": "Active",
                                "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
                            }
                            users_collection.insert_one(company_admin_user)
                            logger.info(f"Created company_admin user: {c_username} for company {comp_name}")
            
            # Automatically create branch records and specific users if provided
            for branch_item in branches_data:
                branch_name = branch_item.get('branch')
                parent_comp = branch_item.get('company')
                if branch_name and parent_comp:
                    # Check if the branch already exists for this company
                    if not branches_collection.find_one({"branch_name": branch_name, "company_name": parent_comp}):
                        branches_collection.insert_one({
                            "branch_name": branch_name,
                            "company_name": parent_comp,
                            "created_by": user_id,
                            "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
                        })
                    
                    # Create a specific user for this branch if details were provided
                    b_username = branch_item.get('username', '').strip()
                    b_password = branch_item.get('password', '').strip()
                    b_email = branch_item.get('email', '').strip()
                    
                    if b_username and b_password:
                        # Use a fallback email if none provided to avoid db collisions
                        safe_email = b_email if b_email else f"{b_username}_{branch_name.replace(' ', '')}@temp.com"
                        safe_email = safe_email.strip().lower()
                        
                        # Only insert if username or email doesn't strictly conflict
                        email_available = is_email_unique(safe_email)
                        user_conflict = users_collection.find_one({"username": b_username})
                        
                        if email_available and not user_conflict:
                            b_hashed_password = bcrypt.hashpw(b_password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
                            b_firstName = branch_item.get('firstName', '').strip() or b_username
                            
                            branch_user = {
                                "email": safe_email,
                                "password": b_hashed_password,
                                "role": "Cashier", 
                                "username": b_username,
                                "firstName": b_firstName,
                                "phone_number": branch_item.get('phone_number', '').strip(),
                                "company": parent_comp,
                                "companies": [parent_comp],
                                "branches": [{"company": parent_comp, "branch": branch_name}],
                                "pos_profile": data.get('pos_profile', 'POS-001'),
                                "status": "Active",
                                "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
                            }
                            users_collection.insert_one(branch_user)
                            logger.info(f"Successfully created branch user: {b_username} for branch {branch_name}")
                        else:
                            # Log the conflict but don't fail the whole registration
                            conflict_type = "email" if not email_available else "username"
                            logger.warning(f"Skipped branch user creation due to {conflict_type} conflict: {safe_email if not email_available else b_username}")

            logger.info(f"User registered with {len(company_names)} companies and {len(branches_data)} branches: {data['email']}")

            # --- AUTOMATIC ROLE PERMISSIONS ---
            # Automatically grant 'admin' and 'company_admin' roles all permissions
            all_pages = ALL_SYSTEM_PAGES
            
            permissions_list = [
                {
                    "pageId": pid,
                    "canRead": True,
                    "canWrite": True,
                    "canCreate": True,
                    "canDelete": True,
                    "dataAccess": "ALL"
                } for pid in all_pages
            ]
            
            roles_to_seed = set(['admin', 'company_admin', 'group_admin', 'Cashier', 'Bearer', 'Cook'])
            roles_to_seed.add(new_user.get('role', 'admin'))
            
            for role_name in roles_to_seed:
                if not role_permissions_collection.find_one({'role': role_name}):
                    role_permissions_collection.insert_one({
                        "role": role_name,
                        "permissions": permissions_list,
                        "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
                    })
                    logger.info(f"Created default full permissions for role: {role_name}")

            # --- SEED DEFAULT DATA ---
            default_groups = ["Food", "Beverage", "Dessert"]
            for gname in default_groups:
                if not item_groups_collection.find_one({"group_name": gname, "company_name": main_company}):
                    item_groups_collection.insert_one({
                        "group_name": gname,
                        "company_name": main_company,
                        "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
                    })
            logger.info(f"Seeded default item groups for company: {main_company}")

            return jsonify({"message": "Registration successful", "userId": user_id}), 201
        except Exception as e:
            logger.error(f"Registration failed: {str(e)}\n{traceback.format_exc()}")
            return jsonify({"message": f"Registration failed: {str(e)}"}), 500
    @app.route('/api/register/group/<group_name>', methods=['PUT'])
    def update_register_group(group_name):
        try:
            data = request.get_json()
            # Update Group Admin
            group_admin = users_collection.find_one({"role": "group_admin", "company": group_name})
            if group_admin:
                update_fields = {}
                if data.get('firstName'): update_fields['firstName'] = data['firstName']
                if data.get('phone_number'): update_fields['phone_number'] = data['phone_number']
                if data.get('username'): update_fields['username'] = data['username']
                if data.get('email'): update_fields['email'] = data['email']
                if data.get('password') and data.get('password') != group_admin.get('plain_password'):
                    update_fields['plain_password'] = data['password']
                    update_fields['password'] = bcrypt.hashpw(data['password'].encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
                # Always update companies array so parent has access to any newly added child companies
                update_fields['companies'] = [c.get('name') for c in data.get('companies', []) if c.get('name')]
                
                if update_fields:
                    users_collection.update_one({"_id": group_admin["_id"]}, {"$set": update_fields})
                    
            # Handle child companies
            companies_data = data.get('companies', [])
            company_names = [c.get('name') for c in companies_data if c.get('name')]
            
            for comp_obj in companies_data:
                comp_name = comp_obj.get('name')
                if not comp_name: continue
                
                # Check if company exists
                existing_company = company_details_collection.find_one({"company_name": comp_name})
                if not existing_company:
                    # Create new company
                    company_details_collection.insert_one({
                        "company_name": comp_name,
                        "company_type": "group_member",
                        "created_by": group_admin["_id"] if group_admin else None,
                        "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
                    })
                
                c_username = comp_obj.get('adminUsername')
                c_password = comp_obj.get('adminPassword')
                c_email = comp_obj.get('email')
                
                if c_username and c_password:
                    existing_admin = users_collection.find_one({"role": "company_admin", "company": comp_name})
                    if existing_admin:
                        # Update
                        c_update = {}
                        if c_username: c_update['username'] = c_username
                        if c_email: c_update['email'] = c_email
                        if c_password != existing_admin.get('plain_password'):
                            c_update['plain_password'] = c_password
                            c_update['password'] = bcrypt.hashpw(c_password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
                        
                        # Ensure the child company admin's companies array is also synced
                        if existing_admin.get('companies') != company_names:
                            c_update['companies'] = company_names
                            
                        if c_update:
                            users_collection.update_one({"_id": existing_admin["_id"]}, {"$set": c_update})
                    else:
                        # Create new admin
                        c_hashed_password = bcrypt.hashpw(c_password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
                        c_email_final = c_email if c_email else f"admin_{comp_name.replace(' ', '_').lower()}@internal.com"
                        users_collection.insert_one({
                            "email": c_email_final.strip().lower(),
                            "password": c_hashed_password,
                            "plain_password": c_password,
                            "role": "company_admin",
                            "username": c_username,
                            "firstName": f"{comp_name} Admin",
                            "phone_number": data.get('phone_number', ''),
                            "company": comp_name,
                            "companies": company_names,
                            "branches": [],
                            "status": "Active",
                            "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
                        })

            return jsonify({"message": "Group updated successfully"}), 200
        except Exception as e:
            logger.error(f"Group update failed: {str(e)}\n{traceback.format_exc()}")
            return jsonify({"message": f"Update failed: {str(e)}"}), 500

    @app.route('/api/users', methods=['GET'])
    def get_users():
        try:
            # --- Centralized Permission Filtering ---
            # 1. Fetch official login users
            can_access, data_scope_filter = get_data_scope_filter('user_management')
            if not can_access:
                return jsonify([]), 200

            users_list = list(users_collection.find(data_scope_filter))
            
            # 2. Fetch all employees to ensure the list is synchronized
            # We use 'employee_list' permission context for employees
            can_access_emp, employee_filter = get_data_scope_filter('employee_list')
            employees_list = []
            if can_access_emp:
                employees_list = list(worker_collection.find(employee_filter))

            # --- Logic to Merge and Deduplicate ---
            # Priority: User record (has login/status info) > Employee record
            merged_users_map = {}
            
            # First, add all employees as base records
            for emp in employees_list:
                email = (emp.get('email') or '').lower().strip()
                if not email: continue
                
                # Normalize employee to user-like structure
                merged_users_map[email] = {
                    'email': email,
                    'firstName': emp.get('employeeName') or emp.get('name') or 'Unknown',
                    'role': emp.get('employeeDesignation') or 'Staff',
                    'phone_number': emp.get('phone') or 'N/A',
                    'company_name': emp.get('company_name') or emp.get('company') or 'All',
                    'status': emp.get('status') or 'Active',
                    'is_employee_only': True # Metadata for client
                }

            # Second, overlay/add official user accounts
            for user in users_list:
                email = (user.get('email') or '').lower().strip()
                if not email: continue
                
                # Use User info as source of truth for status and role if it exists
                # But keep the Designation if we enriched it previously
                existing_role = merged_users_map.get(email, {}).get('role')
                
                user_record = {**user}
                if existing_role and user.get('role') in ['staff', 'employee', 'Bearer', None]:
                    # Keep the more specific designation from employee table if user role is generic
                    user_record['role'] = existing_role
                
                user_record['is_employee_only'] = False
                merged_users_map[email] = user_record

            final_list = list(merged_users_map.values())
            return jsonify(convert_objectid_to_str(final_list)), 200
        except Exception as e:
            logger.error(f"Error fetching users: {str(e)}\n{traceback.format_exc()}")
            return jsonify({"error": str(e)}), 500

    @app.route('/api/users/<email>', methods=['DELETE'])
    def delete_user(email):
        try:
            # Check Permission
            user_id, role = get_request_user_info()
            if not check_user_permission(role, 'user_management', 'canDelete'):
                logger.warning(f"Permission denied: User {user_id} ({role}) tried to delete user")
                return jsonify({"error": "You do not have permission to delete users"}), 403

            if email in [u['email'] for u in TEST_USERS]:
                return jsonify({"message": "Cannot delete test users"}), 400
            # --- Multi-Tenant Safe Deletion Logic ---
            active_company = request.headers.get('X-Company-Name')
            active_branch = request.headers.get('X-Branch-Name')
            
            # Security: Ensure user is authorized to delete in this scope
            can_access, data_scope_filter = get_data_scope_filter('user_management')
            if not can_access:
                return jsonify({"error": "Access denied"}), 403
            
            # --- UNIFIED LOOKUP (Users and Employees) ---
            # Retrieve all matching records across both collections to handle duplicates/context-splits
            matches = [] # list of (collection, record)
            
            # 1. Search in Users Collection
            found_users = list(users_collection.find({"$and": [{"email": email}, data_scope_filter]}))
            for u in found_users:
                matches.append((users_collection, u))
            
            # 2. Search in Employee (Worker) Collection
            found_workers = list(worker_collection.find({"$and": [{"email": email}, data_scope_filter]}))
            for w in found_workers:
                matches.append((worker_collection, w))

            if not matches:
                logger.warning(f"Delete attempt failed: {email} not found in users or employees via data_scope_filter")
                return jsonify({"error": "No matching records found (User or Employee) or you do not have permission"}), 404

            # --- CENTRALIZED MULTI-TENANT SAFE DELETION (Process ALL matches) ---
            last_message = ""
            for target_coll, record_to_del in matches:
                is_partial, last_message = perform_tenant_aware_delete(
                    target_coll, 
                    {"_id": record_to_del["_id"]}, # Target the specific document ID
                    active_company, 
                    record_to_del, 
                    sync_user=True, 
                    active_branch=active_branch
                )
            
            summary = f"Processed {len(matches)} records: {last_message}"
            return jsonify({"message": summary}), 200
        except Exception as e:
            logger.error(f"Error deleting user {email}: {str(e)}")
            return jsonify({"error": str(e)}), 500
