# @app.route('/api/customers', methods=['GET'])
def get_all_customers():
    try:
        # --- Centralized Permission Filtering ---
        can_access, filter_query = get_data_scope_filter('customer_list', owner_field='createdBy')
        if not can_access:
            return jsonify([]), 200

        # Enhance with explicit ID-based filtering for strict isolation
        user_id, role = get_request_user_info()
        user_doc = users_collection.find_one({'_id': user_id}) if user_id else {}
        
        # 1. Resolve active tenant, company, branch from context
        active_company = get_request_company()
        active_branch = get_request_branch()
        
        tenant_id = user_doc.get('tenant_id') if user_doc else None
        
        # Build strict scope query
        strict_scope_clauses = []
        
        # Tenant filter (baseline)
        if tenant_id:
            strict_scope_clauses.append({'tenant_id': tenant_id})
            
        # Company filter
        if active_company and active_company.lower() not in ['all', 'all companies', 'none', 'null']:
            company_doc = company_details_collection.find_one({'restaurantName': active_company})
            c_id = company_doc.get('_id') if company_doc else None
            c_clause = {'$or': [
                {'company_name': active_company},
                {'company': active_company},
                {'company_names': {'$in': [active_company]}}
            ]}
            if c_id:
                c_clause['$or'].append({'company_id': str(c_id)})
            strict_scope_clauses.append(c_clause)
            
        # Branch filter
        if active_branch and active_branch.lower() not in ['all', 'all branches', 'any']:
            branch_doc = branches_collection.find_one({'branch_name': active_branch})
            b_id = branch_doc.get('_id') if branch_doc else None
            b_clause = {'$or': [
                {'branch_name': active_branch},
                {'branch': active_branch},
                {'branch_names': {'$in': [active_branch]}}
            ]}
            if b_id:
                b_clause['$or'].append({'branch_id': str(b_id)})
            strict_scope_clauses.append(b_clause)
            
        if strict_scope_clauses:
            if filter_query:
                filter_query = {'$and': [filter_query] + strict_scope_clauses}
            else:
                filter_query = {'$and': strict_scope_clauses}

        logger.info(f"DEBUG CUSTOMERS: active_company={active_company}, active_branch={active_branch}, filter_query={filter_query}")

        # SAAS ENHANCEMENT: If Company Admin, also filter by company_id (UUID-based)
        if role == 'Company Admin' and user_id and user_doc and user_doc.get('company_id'):
            company_id = user_doc['company_id']
            comp_name = user_doc.get('company_name')
            company_or_clauses = [
                {'company_id': company_id},
                {'company_id': {'$exists': False}}  # legacy records without company_id still visible
            ]
            if comp_name:
                company_or_clauses.extend([
                    {'company_name': comp_name},
                    {'company_names': {'$in': [comp_name]}}
                ])
            filter_query = {
                '$and': [
                    filter_query,
                    {'$or': company_or_clauses}
                ]
            } if filter_query else {'$or': company_or_clauses}

        customers = customers_collection.find(filter_query)
        customers = [convert_objectid_to_str(customer) for customer in customers]
        logger.info(f"Fetched {len(customers)} customers with strict scope filter")
        return jsonify(customers), 200
    except Exception as e:
        logger.error(f"Error fetching customers: {str(e)}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/customers/<customer_id>', methods=['GET', 'PUT', 'DELETE'])
def customer_operations(customer_id):
    try:
        if not customer_id or customer_id == "undefined":
            logger.error("Invalid customer_id: 'undefined' or empty")
            return jsonify({"error": "Invalid customer ID"}), 400
        
        # --- Centralized Permission Filtering ---
        can_access, data_scope_filter = get_data_scope_filter('customer_list')
        if not can_access:
            return jsonify({"error": "Access denied"}), 403
        
        op_filter = data_scope_filter.copy()
        op_filter['_id'] = customer_id
    
        if request.method == 'GET':
            customer = customers_collection.find_one(op_filter)
            if not customer:
                logger.warning(f"Customer not found or access denied: {customer_id}")
                return jsonify({"error": "Customer not found"}), 404
            customer = convert_objectid_to_str(customer)
            logger.info(f"Fetched customer: {customer_id}")
            return jsonify(customer), 200
        elif request.method == 'PUT':
            customer_data = request.get_json()
            if not customer_data:
                logger.error("No data provided for customer update")
                return jsonify({"error": "No data provided"}), 400
            
            # Prepare update object with all provided fields
            update_fields = customer_data.copy()
            update_fields.pop('_id', None)
            update_fields['modified_at'] = datetime.now(ZoneInfo("UTC")).isoformat()

            result = customers_collection.update_one(
                op_filter,
                {'$set': update_fields}
            )
            if result.matched_count == 0:
                logger.warning(f"Customer not found or access denied for update: {customer_id}")
                return jsonify({"error": "Customer not found"}), 404
            # Fetch and return the updated customer
            updated_customer = customers_collection.find_one({'_id': customer_id})
            updated_customer = convert_objectid_to_str(updated_customer)
            logger.info(f"Customer updated: {customer_id}")
            return jsonify(updated_customer), 200
        elif request.method == 'DELETE':
            # Check Explicit Permission for Delete
            user_id, role = get_request_user_info()
            if not check_user_permission(role, 'customer_list', 'canDelete'):
                logger.warning(f"Permission denied: User {user_id} ({role}) tried to delete customer")
                return jsonify({"error": "You do not have permission to delete customers"}), 403

            result = customers_collection.delete_one(op_filter)
            if result.deleted_count == 0:
                logger.warning(f"Customer not found or access denied for deletion: {customer_id}")
                return jsonify({"error": "Customer not found"}), 404
            logger.info(f"Customer deleted: {customer_id}")
            return jsonify({"message": "Customer deleted successfully"}), 200
    except Exception as e:
        logger.error(f"Error in customer operations for {customer_id}: {str(e)}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/customer-groups', methods=['GET'])
def get_customer_groups():
    try:
        user_id, role = get_request_user_info()
        user_doc = users_collection.find_one({'_id': user_id}) if user_id else {}
        tenant_id = user_doc.get('tenant_id') if user_doc else None

        active_company = request.headers.get('X-Company-Name', '').strip()
        active_branch  = request.headers.get('X-Branch-Name', '').strip()

        filter_query = {}
        if tenant_id:
            filter_query['tenant_id'] = tenant_id

        # Company-scope filter:
        #   - Include groups assigned to active_company
        #   - Also include groups with NO company (treated as global, visible everywhere)
        if active_company and active_company.lower() not in ('all', 'all companies'):
            filter_query['$or'] = [
                # Specifically assigned to this company
                {'company_names': {'$in': [active_company]}},
                {'company_name':  active_company},
                # No company assigned at all ΓåÆ global group (visible to all)
                {'company_names': {'$exists': False}},
                {'company_names': None},
                {'company_names': []},
                {'company_name':  {'$in': ['', None]}},
            ]

        groups = list(customer_groups_collection.find(filter_query))

        # Branch-scope filter in Python:
        #   - Groups with no branch assigned ΓåÆ visible to everyone in the company
        #   - Groups with specific branches ΓåÆ only show if branch matches
        if active_branch and active_branch.lower() not in ('all branches', 'all', ''):
            def branch_match(g):
                bnames = g.get('branch_names') or []
                bname  = g.get('branch_name') or ''
                all_branches = list(bnames) if isinstance(bnames, list) else ([bnames] if bnames else [])
                if bname and bname not in all_branches:
                    all_branches.append(bname)
                # Remove empty strings
                all_branches = [b for b in all_branches if b and b.strip()]
                # No branch assigned ΓåÆ show to everyone in company (global within company)
                if not all_branches:
                    return True
                return any(b.strip().lower() == active_branch.lower() for b in all_branches)
            groups = [g for g in groups if branch_match(g)]

        groups = convert_objectid_to_str(groups)
        logger.info(f"Fetched {len(groups)} customer groups for tenant={tenant_id} company={active_company} branch={active_branch}")
        return jsonify(groups), 200
    except Exception as e:
        logger.error(f"Error fetching customer groups: {str(e)}")
        return jsonify({"error": str(e)}), 500

