@app.route('/api/doctypes', methods=['POST'])
def save_doctype():
    try:
        data = request.get_json()
        if not data or 'name' not in data:
            return jsonify({"error": "DocType name is required"}), 400
        
        name = data['name']
        company_names = data.get('company_names', ['All'])
        
        # CLEANUP: Remove legacy top-level fields that might contaminate company_names
        # via the SQLiteCollection._sync_tenancy auto-correction.
        data.pop('company', None)
        data.pop('company_name', None)
        
        # Sort company names to ensure consistent keying
        if not isinstance(company_names, list):
            company_names = [company_names]
        company_names.sort()
        data['company_names'] = company_names # Update in data too
        
        # Search for an existing DocType record that matches exactly this company set
        existing = doctypes_collection.find_one({
            "name": name, 
            "company_names": company_names
        })
        
        if existing:
            # Update the existing record for this specific company set
            doctypes_collection.update_one(
                {"_id": existing['_id']}, 
                {"$set": data}
            )
        else:
            # Create a NEW isolated record
            # IMPORTANT: Remove any existing _id to avoid UNIQUE constraint conflicts 
            # if we are branching off from a Global/other config
            if '_id' in data:
                del data['_id']
            
            data['_id'] = str(uuid.uuid4())
            doctypes_collection.insert_one(data)
            
        # NEW: Automatically update JSON file in doctypes/ folder with isolation
        try:
            doctypes_dir = os.path.join(os.getcwd(), 'doctypes')
            if not os.path.exists(doctypes_dir):
                os.makedirs(doctypes_dir)
            
            # Use a prefix if it's not a Global config
            is_global = "All" in company_names
            prefix = "Global" if is_global else "_".join(company_names[:2]) # Keep filename reasonably short
            if not is_global and len(company_names) > 2:
                prefix += "_Multi"
                
            filename = f"{prefix}_{name.lower().replace(' ', '_')}.json"
            filepath = os.path.join(doctypes_dir, filename)
            
            # Remove MongoDB internal _id if present for the JSON file
            json_data = {k: v for k, v in data.items() if k != '_id'}
            
            with open(filepath, 'w', encoding='utf-8') as f:
                json.dump(json_data, f, indent=2)
            logger.info(f"Updated DocType JSON file: {filepath}")
        except Exception as e:
            logger.error(f"Failed to update DocType JSON file: {str(e)}")
            
        return jsonify({"message": f"DocType {name} saved successfully"}), 200
    except Exception as e:
        logger.error(f"Error saving doctype: {str(e)}")
        return jsonify({"error": str(e)}), 500
