@app.route('/api/employees/<employee_id>', methods=['GET'])
def get_employee(employee_id):
    try:
        # --- Permission & Isolation Check ---
        can_access, data_scope_filter = get_data_scope_filter('employee_list')
        if not can_access:
             return jsonify({"error": "Access denied"}), 403

        # Try finding by employeeId first with data scope
        query = {"$and": [data_scope_filter, {"employeeId": employee_id}]}
        employee = worker_collection.find_one(query)
        
        if not employee:
            # Fallback to _id (string match for SQLite)
            query = {"$and": [data_scope_filter, {"_id": employee_id}]}
            employee = worker_collection.find_one(query)
        if not employee:
            # Fallback to generalEmployeeId
            query = {"$and": [data_scope_filter, {"generalEmployeeId": employee_id}]}
            employee = worker_collection.find_one(query)
        
        if not employee:
            return jsonify({'error': 'Employee not found'}), 404
            
        return jsonify(convert_objectid_to_str(employee)), 200
    except Exception as e:
        logger.error(f"Error fetching employee {employee_id}: {str(e)}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/employees/<employee_id>', methods=['DELETE'])
def delete_employee(employee_id):
    try:
        # Check Permission
        user_id, role = get_request_user_info()
        if not check_user_permission(role, 'employee_list', 'canDelete'):
            logger.warning(f"Permission denied: User {user_id} ({role}) tried to delete employee")
            return jsonify({"error": "You do not have permission to delete employees"}), 403

        # --- Permission & Isolation Check ---
        can_access, data_scope_filter = get_data_scope_filter('employee_list')
        if not can_access:
             return jsonify({"error": "Access denied"}), 403

        # Try finding by employeeId first with data scope
        query = {"$and": [data_scope_filter, {"employeeId": employee_id}]}
        employee = worker_collection.find_one(query)
        
        if not employee:
            # Fallback to _id (string match for SQLite)
            query = {"$and": [data_scope_filter, {"_id": employee_id}]}
            employee = worker_collection.find_one(query)

        if not employee:
             # Fallback to generalEmployeeId
            query = {"$and": [data_scope_filter, {"generalEmployeeId": employee_id}]}
            employee = worker_collection.find_one(query)
                
        if not employee:
            return jsonify({'error': 'Employee not found'}), 404
            
        # --- UNIFIED LOOKUP (Handle duplicates by email) ---
        email = employee.get('email')
        matches = []
        if email:
            # Find all matching employee records with the same email in the authorized scope
            found_workers = list(worker_collection.find({"$and": [{"email": email}, data_scope_filter]}))
            for w in found_workers:
                matches.append((worker_collection, w))
            
            # Also process matching login users if any (keep it synced)
            found_users = list(users_collection.find({"$and": [{"email": email}, data_scope_filter]}))
            for u in found_users:
                matches.append((users_collection, u))
        else:
            # Fallback if no email: just process the identified record
            matches.append((worker_collection, employee))

        # --- CENTRALIZED MULTI-TENANT SAFE DELETION (Process ALL matches) ---
        active_company = request.headers.get('X-Company-Name')
        active_branch = request.headers.get('X-Branch-Name')
        
        last_message = ""
        for target_coll, record_to_del in matches:
            is_partial, last_message = perform_tenant_aware_delete(
                target_coll, 
                {"_id": record_to_del["_id"]}, 
                active_company, 
                record_to_del, 
                sync_user=True,
                active_branch=active_branch
            )
        
        summary = f"Processed {len(matches)} records: {last_message}"
        return jsonify({"message": summary}), 200
    except Exception as e:
        logger.error(f"Error deleting employee: {str(e)}")
        return jsonify({"error": str(e)}), 500
    
