@app.route('/api/purchase_orders', methods=['POST'])
def add_purchase_order():
    try:
        can_access, data_scope_filter = get_data_scope_filter('purchase')
        if not can_access:
            return jsonify({'error': 'Unauthorized'}), 403
            
        data = request.json
        # Fallback for company if missing in payload (common for non-Group Admins)
        if 'company' not in data or not data['company']:
            header_company = request.headers.get('X-Company-Name') or request.headers.get('company_name')
            if header_company:
                data['company'] = header_company

        required_fields = ['series', 'date', 'company', 'supplierId', 'name', 'supplierCompany', 'supplierCode', 'supplierGroup', 'address', 'phone', 'email', 'currency', 'items', 'taxes', 'subtotal', 'totalQuantity', 'totalTaxes', 'grandTotal', 'status']
        if not all(key in data for key in required_fields):
            missing = [k for k in required_fields if k not in data]
            return jsonify({'error': f'Missing required fields: {", ".join(missing)}'}), 400
        if purchase_orders_collection.find_one({'series': data['series'] , **data_scope_filter}):
            return jsonify({'error': 'Series already exists'}), 400
        supplier = suppliers_collection.find_one({'_id': data['supplierId'], **data_scope_filter})
        if not supplier:
            return jsonify({'error': 'Supplier not found'}), 404
        items = []
        for item_data in data['items']:
            item_doc = purchase_items_collection.find_one({'_id': item_data['itemId'], **data_scope_filter})
            if not item_doc:
                return jsonify({'error': f"Item {item_data['itemId']} not found"}), 404
            
            item_suppliers = item_doc.get('suppliers', [])
            if isinstance(item_suppliers, str):
                import ast
                try: item_suppliers = ast.literal_eval(item_suppliers)
                except Exception: item_suppliers = []
            target_supplier_id = data['supplierId']
            target_supplier_name = data.get('supplierCompany', '')

            matches_id = any(s.get('supplierId') == target_supplier_id for s in item_suppliers)
            matches_name = any(extreme_norm(s.get('supplierName')) == extreme_norm(target_supplier_name) for s in item_suppliers) if target_supplier_name else False

            if item_suppliers and not (matches_id or matches_name):
                 return jsonify({'error': f"Item '{item_doc['name']}' is not accepted by the selected supplier."}), 400

            items.append({
                'itemId': item_data['itemId'],
                'quantity': float(item_data['quantity']),
                'uom': item_data['uom'],
                'rate': float(item_data.get('rate', 0)),
                'amount': float(item_data.get('amount', 0))
            })
        order = {
            'series': data['series'],
            'date': datetime.fromisoformat(str(data['date']).replace('Z', '+00:00')),
            'company': data['company'],
            'supplierId': data['supplierId'],
            'name': data['name'],
            'supplierCompany': data['supplierCompany'],
            'supplierCode': data.get('supplierCode', ''),
            'supplierGroup': data.get('supplierGroup', ''),
            'address': data['address'],
            'phone': data['phone'],
            'email': data['email'],
            'currency': data['currency'],
            'targetWarehouse': data.get('targetWarehouse', ''),
            'items': items,
            'taxes': data['taxes'],
            'subtotal': float(data['subtotal']),
            'totalQuantity': float(data['totalQuantity']),
            'totalTaxes': float(data['totalTaxes']),
            'grandTotal': float(data['grandTotal']),
            'status': data['status'],
            'branch_name': data.get('branch_name', request.headers.get('X-Branch-Name')),
            'created_at': datetime.now(timezone.utc).isoformat()
        }
        result = purchase_orders_collection.insert_one(order)
        inserted_order = purchase_orders_collection.find_one({'_id': result.inserted_id, **data_scope_filter})
        return jsonify(convert_objectid_to_str(inserted_order)), 201
    except ValueError as e:
        return jsonify({'error': f"Invalid data format: {str(e)}"}), 400
    except Exception as e:
        return jsonify({'error': f"Failed to create purchase order: {str(e)}"}), 500

@app.route('/api/purchase_orders/<id>', methods=['PUT'])
def update_purchase_order(id):
    try:
        data = request.json
        if not data:
            return jsonify({'error': 'No input data provided'}), 400
        can_access, data_scope_filter = get_data_scope_filter('purchase')
        if not can_access:
            return jsonify({'error': 'Unauthorized'}), 403
        old_order = purchase_orders_collection.find_one({'_id': id, **data_scope_filter})
        if not old_order:
            return jsonify({'error': 'Purchase Order not found'}), 404
        update_data = {}
        for field in ['series', 'date', 'company', 'supplierId', 'name', 'supplierCompany', 'supplierCode', 'supplierGroup', 'address', 'phone', 'email', 'currency', 'targetWarehouse', 'items', 'taxes', 'subtotal', 'totalQuantity', 'totalTaxes', 'grandTotal', 'status']:
            if field in data:
                if field == 'date':
                    update_data[field] = datetime.fromisoformat(str(data[field]).replace('Z', '+00:00'))
                elif field in ['subtotal', 'totalQuantity', 'totalTaxes', 'grandTotal']:
                    update_data[field] = float(data[field])
                elif field == 'items':
                    items = []
                    # Fetch current supplierId if not in data (to validate against correct supplier)
                    current_supplier_id = data.get('supplierId')
                    if not current_supplier_id:
                        current_supplier_id = old_order['supplierId']
                        
                    for item_data in data[field]:
                        # Validate Item-Supplier Mapping (Strong fallback to name matching)
                        item_doc = purchase_items_collection.find_one({'_id': item_data['itemId'], **data_scope_filter})
                        if item_doc:
                            item_suppliers = item_doc.get('suppliers', [])
                            if isinstance(item_suppliers, str):
                                import ast
                                try: item_suppliers = ast.literal_eval(item_suppliers)
                                except Exception: item_suppliers = []
                            target_supplier_name = data.get('supplierCompany', '')
                            
                            matches_id = any(s.get('supplierId') == current_supplier_id for s in item_suppliers)
                            matches_name = any(extreme_norm(s.get('supplierName')) == extreme_norm(target_supplier_name) for s in item_suppliers) if target_supplier_name else False
                            
                            if item_suppliers and not (matches_id or matches_name):
                                return jsonify({'error': f"Item '{item_doc['name']}' is not accepted by the selected supplier."}), 400

                        items.append({
                            'itemId': item_data['itemId'],
                            'quantity': float(item_data['quantity']),
                            'uom': item_data['uom'],
                            'rate': float(item_data.get('rate', 0)),
                            'amount': float(item_data.get('amount', 0))
                        })
                    update_data[field] = items
                else:
                    update_data[field] = data[field]
        if not update_data:
            return jsonify({'error': 'No fields to update'}), 400
        result = purchase_orders_collection.update_one({'_id': id, **data_scope_filter}, {'$set': update_data})
        if result.matched_count == 0:
            return jsonify({'error': 'Purchase Order not found'}), 404
        return jsonify({'message': 'Purchase Order updated successfully'}), 200
    except ValueError as e:
        return jsonify({'error': f"Invalid data format: {str(e)}"}), 400
    except Exception as e:
        return jsonify({'error': f"Failed to update purchase order: {str(e)}"}), 500

@app.route('/api/purchase_orders/<id>', methods=['DELETE'])
def delete_purchase_order(id):
    try:
        user_id, role = get_request_user_info()
        if not user_id:
            return jsonify({'error': 'Unauthorized'}), 403
        # Try deleting by ID directly (scope filter can cause false 404 for valid records)
        result = purchase_orders_collection.delete_one({'_id': id})
        if result.deleted_count == 0:
            # Try with ObjectId fallback
            try:
                from bson import ObjectId
                result = purchase_orders_collection.delete_one({'_id': ObjectId(id)})
            except Exception:
                pass
        if result.deleted_count == 0:
            return jsonify({'error': 'Purchase Order not found'}), 404
        return jsonify({'message': 'Purchase Order deleted successfully'}), 200
    except Exception as e:
        return jsonify({'error': f"Failed to delete purchase order: {str(e)}"}), 500

