@app.route('/api/purchase_receipts/<series>', methods=['DELETE'])
def delete_purchase_receipt(series):
    try:
        can_access, data_scope_filter = get_data_scope_filter('purchase')
        if not can_access:
            return jsonify({'error': 'Unauthorized'}), 403
        old_receipt = purchase_receipts_collection.find_one({'series': series, **data_scope_filter})
        if not old_receipt:
            return jsonify({'error': 'Purchase Receipt not found'}), 404
        if old_receipt['status'] == 'Submitted':
            for item in old_receipt['items']:
                item_obj = purchase_items_collection.find_one({'_id': item['itemId'], **data_scope_filter})
                sub_master = 0
                sub_outer = 0
                sub_nos = 0
                if item['unit'] == 'master':
                    sub_master = item['acceptedQuantity']
                elif item['unit'] == 'outer':
                    sub_outer = item['acceptedQuantity']
                elif item['unit'] == 'nos':
                    sub_nos = item['acceptedQuantity']
                total_sub_in_nos = (sub_master * item_obj.get('masterToOuter', item_obj.get('packets_per_box', 1)) * item_obj.get('outerToNos', item_obj.get('units_per_packet', 1))) + (sub_outer * item_obj.get('outerToNos', item_obj.get('units_per_packet', 1))) + sub_nos
                purchase_items_collection.update_one(
                    {'_id': item['itemId'], **data_scope_filter},
                    {'$inc': {
                        'stockMaster': -sub_master,
                        'stockOuter': -sub_outer,
                        'stockNos': -sub_nos,
                        'totalStock': -total_sub_in_nos,
                        'totalPurchased': -total_sub_in_nos
                    }}
                )
        result = purchase_receipts_collection.delete_one({'series': series, **data_scope_filter})
        if result.deleted_count == 0:
            return jsonify({'error': 'Purchase Receipt not found'}), 404
        return jsonify({'message': 'Purchase Receipt deleted successfully'}), 200
    except Exception as e:
        return jsonify({'error': f"Failed to delete purchase receipt: {str(e)}"}), 500

