@app.route('/api/purchase_invoices', methods=['POST'])
def add_purchase_invoice():
    try:
        can_access, data_scope_filter = get_data_scope_filter('purchase')
        if not can_access:
            return jsonify({'error': 'Unauthorized'}), 403
            
        data = request.json
        # Fallback for company if missing in payload
        if 'company' not in data or not data['company']:
            header_company = request.headers.get('X-Company-Name') or request.headers.get('company_name')
            if header_company:
                data['company'] = header_company

        required_fields = ['series', 'date', 'company', 'supplierId', 'name', 'supplierCompany', 'supplierCode', 'supplierGroup', 'address', 'phone', 'email', 'currency', 'items', 'taxes', 'totalQuantity', 'subtotal', 'taxesAdded', 'grandTotal', 'status']
        if not all(key in data for key in required_fields):
            missing = [k for k in required_fields if k not in data]
            return jsonify({'error': f'Missing required fields: {", ".join(missing)}'}), 400
        if purchase_invoices_collection.find_one({'series': data['series'], **data_scope_filter}):
            return jsonify({'error': 'Series already exists'}), 400

        is_direct = data.get('isDirectPurchase', False)

        if not is_direct:
            if 'prId' not in data or not data['prId']:
                return jsonify({'error': 'Purchase Receipt is required'}), 400
            pr = purchase_receipts_collection.find_one({'series': data['prId'], **data_scope_filter})
            if not pr:
                return jsonify({'error': 'Purchase Receipt not found'}), 404
        elif 'supplierId' not in data or not data['supplierId']:
             return jsonify({'error': 'Supplier is required for Direct Purchase'}), 400

        items = []
        for item_data in data['items']:
            item_doc = purchase_items_collection.find_one({'_id': item_data['itemId'], **data_scope_filter})
            if not item_doc:
                return jsonify({'error': f"Item {item_data['itemId']} not found"}), 404
            
            if is_direct:
                # Validate Item-Supplier Mapping for Direct Purchase (Strong fallback to name matching)
                item_suppliers = item_doc.get('suppliers', [])
                if isinstance(item_suppliers, str):
                    import ast
                    try: item_suppliers = ast.literal_eval(item_suppliers)
                    except Exception: item_suppliers = []
                target_supplier_id = data['supplierId']
                target_supplier_name = data.get('supplierCompany', '')
                
                matches_id = any(s.get('supplierId') == target_supplier_id for s in item_suppliers)
                matches_name = any(extreme_norm(s.get('supplierName')) == extreme_norm(target_supplier_name) for s in item_suppliers) if target_supplier_name else False
                
                if item_suppliers and not (matches_id or matches_name):
                     return jsonify({'error': f"Item '{item_doc['name']}' is not accepted by the selected supplier."}), 400

            
            # Use 'quantity' if 'acceptedQuantity' is missing/zero (Direct Purchase flow uses quantity)
            qty = float(item_data.get('acceptedQuantity', 0))
            if qty == 0 and 'quantity' in item_data:
                qty = float(item_data['quantity'])
                
            items.append({
                'itemId': item_data['itemId'],
                'acceptedQuantity': qty,
                'rate': float(item_data.get('rate', 0)),
                'amount': float(item_data.get('amount', 0)),
                'unit': item_data.get('unit', 'master') # Default to master if missing
            })

        invoice = {
            'series': data['series'],
            'date': datetime.fromisoformat(str(data['date']).replace('Z', '+00:00')),
            'company': data['company'],
            'supplierId': data['supplierId'],
            'name': data['name'],
            'supplierCompany': data['supplierCompany'],
            'supplierCode': data.get('supplierCode', ''),
            'supplierGroup': data.get('supplierGroup', ''),
            'address': data['address'],
            'phone': data['phone'],
            'email': data['email'],
            'poId': data.get('poId', ''),
            'prId': data.get('prId', ''),
            'isDirectPurchase': is_direct,
            'currency': data['currency'],
            'items': items,
            'taxes': data['taxes'],
            'totalQuantity': float(data['totalQuantity']),
            'subtotal': float(data['subtotal']),
            'taxesAdded': float(data['taxesAdded']),
            'grandTotal': float(data['grandTotal']),
            'status': data['status'],
            'branch_name': data.get('branch_name', request.headers.get('X-Branch-Name')),
            'created_at': datetime.now(timezone.utc).isoformat()
        }
        result = purchase_invoices_collection.insert_one(invoice)
        inserted_invoice = purchase_invoices_collection.find_one({'_id': result.inserted_id, **data_scope_filter})
        
        if data['status'] == 'Submitted':
            suppliers_collection.update_one(
                {'_id': data['supplierId'], **data_scope_filter},
                {'$set': {
                    'lastPurchaseDate': invoice['date'],
                    'lastPurchaseValue': invoice['grandTotal']
                }}
            )
            
            # Stock Update for Direct Purchase (Simulating Receipt Logic)
            if is_direct:
                for item in items:
                    item_obj = purchase_items_collection.find_one({'_id': item['itemId'], **data_scope_filter})
                    add_master = 0
                    add_outer = 0
                    add_nos = 0
                    qty = item['acceptedQuantity']
                    unit = item.get('unit', 'master')
                    
                    if unit == 'master':
                        add_master = qty
                    elif unit == 'outer':
                        add_outer = qty
                    elif unit == 'nos':
                        add_nos = qty
                        
                    total_added_in_nos = (add_master * item_obj.get('masterToOuter', item_obj.get('packets_per_box', 1)) * item_obj.get('outerToNos', item_obj.get('units_per_packet', 1))) + (add_outer * item_obj.get('outerToNos', item_obj.get('units_per_packet', 1))) + add_nos
                    
                    purchase_items_collection.update_one(
                        {'_id': item['itemId'], **data_scope_filter},
                        {'$inc': {
                            'stockMaster': add_master,
                            'stockOuter': add_outer,
                            'stockNos': add_nos,
                            'totalStock': total_added_in_nos,
                            'totalPurchased': total_added_in_nos
                        }}
                    )

        return jsonify(convert_objectid_to_str(inserted_invoice)), 201
    except ValueError as e:
        return jsonify({'error': f"Invalid data format: {str(e)}"}), 400
    except Exception as e:
        return jsonify({'error': f"Failed to create purchase invoice: {str(e)}"}), 500

@app.route('/api/purchase_invoices/<series>', methods=['PUT'])
def update_purchase_invoice(series):
    try:
        data = request.json
        if not data:
            return jsonify({'error': 'No input data provided'}), 400
        can_access, data_scope_filter = get_data_scope_filter('purchase')
        if not can_access:
            return jsonify({'error': 'Unauthorized'}), 403
        old_invoice = purchase_invoices_collection.find_one({'series': series, **data_scope_filter})
        if not old_invoice:
            return jsonify({'error': 'Purchase Invoice not found'}), 404
        update_fields = {}
        for field in ['date', 'company', 'supplierId', 'name', 'supplierCompany', 'supplierCode', 'supplierGroup', 'address', 'phone', 'email', 'poId', 'prId', 'currency', 'items', 'taxes', 'totalQuantity', 'subtotal', 'taxesAdded', 'grandTotal', 'status']:
            if field in data:
                if field == 'date':
                    update_fields[field] = datetime.fromisoformat(str(data[field]).replace('Z', '+00:00'))
                elif field in ['totalQuantity', 'subtotal', 'taxesAdded', 'grandTotal']:
                    update_fields[field] = float(data[field])
                elif field == 'items':
                    items = []
                    for item_data in data[field]:
                        items.append({
                            'itemId': item_data['itemId'],
                            'acceptedQuantity': float(item_data['acceptedQuantity']),
                            'rate': float(item_data.get('rate', 0)),
                            'amount': float(item_data.get('amount', 0)),
                            'unit': item_data['unit']
                        })
                    update_fields[field] = items
                else:
                    update_fields[field] = data[field]
        if not update_fields:
            return jsonify({'error': 'No fields to update'}), 400
        result = purchase_invoices_collection.update_one({'series': series, **data_scope_filter}, {'$set': update_fields})
        if result.matched_count == 0:
            return jsonify({'error': 'Purchase Invoice not found'}), 404
        new_status = data.get('status', old_invoice['status'])
        supplier_id = data.get('supplierId', old_invoice.get('supplierId'))
        if new_status == 'Submitted' and supplier_id:
            suppliers_collection.update_one(
                {'_id': supplier_id, **data_scope_filter},
                {'$set': {
                    'lastPurchaseDate': data.get('date', old_invoice['date']),
                    'lastPurchaseValue': float(data.get('grandTotal', old_invoice['grandTotal']))
                }}
            )
        return jsonify({'message': 'Purchase Invoice updated successfully'}), 200
    except ValueError as e:
        return jsonify({'error': f"Invalid data format: {str(e)}"}), 400
    except Exception as e:
        return jsonify({'error': f"Failed to update purchase invoice: {str(e)}"}), 500

