@app.route('/api/purchase_sales', methods=['POST'])
def add_purchase_sale():
    try:
        can_access, data_scope_filter = get_data_scope_filter('purchase')
        if not can_access:
            return jsonify({'error': 'Unauthorized'}), 403
            
        data = request.json
        required_fields = ['itemId', 'quantity']
        if not all(key in data for key in required_fields):
            return jsonify({'error': 'Missing required fields'}), 400
        item = purchase_items_collection.find_one({'_id': data['itemId'], **data_scope_filter})
        if not item:
            return jsonify({'error': 'Item not found'}), 404
        quantity = float(data['quantity'])
        if quantity > item['totalStock']:
            return jsonify({'error': 'Insufficient stock'}), 400
        sale = {
            'itemId': data['itemId'],
            'quantity': quantity,
            'date': datetime.now(timezone.utc).isoformat(),
            'created_at': datetime.now(timezone.utc).isoformat()
        }
        result = purchase_sales_collection.insert_one(sale)
        purchase_items_collection.update_one(
            {'_id': data['itemId'], **data_scope_filter},
            {'$inc': {
                'soldNos': quantity,
                'totalStock': -quantity
            }}
        )
        inserted_sale = purchase_sales_collection.find_one({'_id': result.inserted_id, **data_scope_filter})
        return jsonify(convert_objectid_to_str(inserted_sale)), 201
    except ValueError as e:
        return jsonify({'error': f"Invalid data format: {str(e)}"}), 400
    except Exception as e:
        return jsonify({'error': f"Failed to record sale: {str(e)}"}), 500

