@app.route('/api/supplier_groups', methods=['POST'])
def add_supplier_group():
    try:
        # --- Centralized Permission Filtering ---
        can_access, _ = get_data_scope_filter('supplier_groups')
        if not can_access:
            return jsonify({'error': 'Unauthorized'}), 403

        data = request.json
        if not data or 'group_name' not in data or not data['group_name'].strip():
            return jsonify({'error': 'Invalid group name'}), 400
            
        # --- Context Resolution ---
        raw_company = request.headers.get('X-Company-Name')
        # If multiple companies selected (group admin), default to the first one for creation
        active_company = raw_company.split(',')[0].strip() if raw_company else None
        active_branch = request.headers.get('X-Branch-Name')
        if active_branch and ',' in str(active_branch):
             active_branch = str(active_branch).split(',')[0].strip()
        
        # --- Duplicate Check (Company-Scoped) ---
        duplicate_filter = {
            'group_name': data['group_name'].strip(),
            'company': active_company
        }
        
        if supplier_group_collection.find_one(duplicate_filter):
            return jsonify({'error': f"Supplier group '{data['group_name']}' already exists for this company"}), 400
            
        # --- Branch Normalization ---
        incoming_branch = data.get('branch_name') or data.get('branch_names') or active_branch
        if isinstance(incoming_branch, list):
            branch_names = incoming_branch
            primary_branch = branch_names[0] if branch_names else ""
        else:
            primary_branch = incoming_branch or ""
            branch_names = [primary_branch] if primary_branch else []

        group = {
            '_id': str(uuid.uuid4()),
            'group_name': data['group_name'].strip(),
            'company': active_company,
            'company_name': active_company,
            'branch_name': primary_branch,
            'branch_names': branch_names,
            'created_at': datetime.now(ZoneInfo("UTC")).isoformat(),
            'updated_at': datetime.now(ZoneInfo("UTC")).isoformat()
        }
        
        supplier_group_collection.insert_one(group)
        logger.info(f"Supplier group added: {data['group_name']} for {active_company}")
        return jsonify(convert_objectid_to_str(group)), 201
    except Exception as e:
        logger.error(f"Error adding supplier group: {str(e)}\n{traceback.format_exc()}")
        return jsonify({'error': f"Failed to add supplier group: {str(e)}"}), 500

@app.route('/api/supplier_groups/<id>', methods=['PUT'])
def update_supplier_group(id):
    try:
        data = request.json
        if not data or 'group_name' not in data or not data['group_name'].strip():
            return jsonify({'error': 'Invalid group name'}), 400
            
        active_company = request.headers.get('X-Company-Name')
        
        # --- Duplicate Check (Company-Scoped) ---
        duplicate_filter = {
            'group_name': data['group_name'].strip(),
            '_id': {'$ne': id},
            '$or': [
                {'company': active_company},
                {'company_name': active_company}
            ]
        }
        
        if supplier_group_collection.find_one(duplicate_filter):
            return jsonify({'error': 'Group name already exists for this company'}), 400
            
        update_data = {
            'group_name': data['group_name'].strip(),
            'updated_at': datetime.now(ZoneInfo("UTC")).isoformat()
        }
        
        # Branch Updates
        incoming_branch = data.get('branch_name') or data.get('branch_names')
        if incoming_branch:
            if isinstance(incoming_branch, list):
                update_data['branch_names'] = incoming_branch
                update_data['branch_name'] = incoming_branch[0] if incoming_branch else ""
            else:
                update_data['branch_name'] = incoming_branch
                update_data['branch_names'] = [incoming_branch]

        result = supplier_group_collection.update_one({'_id': id}, {'$set': update_data})
        if result.matched_count == 0:
            return jsonify({'error': 'Supplier group not found'}), 404
            
        logger.info(f"Supplier group updated: {id}")
        return jsonify({'message': 'Supplier group updated successfully'}), 200
    except Exception as e:
        logger.error(f"Error updating supplier group {id}: {str(e)}")
        return jsonify({'error': f"Failed to update supplier group: {str(e)}"}), 500

