@app.route('/api/print_settings', methods=['POST'])
def create_print_settings():
    try:
        data = request.get_json()
        if not data:
            return jsonify({"error": "No data provided"}), 400
        
        # Ensure branch isolation on create
        can_access, filter_query = get_data_scope_filter('print_settings')
        if not can_access:
            return jsonify({"error": "Access denied"}), 403
        
        branch_name = data.get('branch_name')
        if filter_query and 'branch_name' in filter_query and branch_name:
            allowed_branches = filter_query['branch_name']
            if isinstance(allowed_branches, dict) and '$in' in allowed_branches:
                if branch_name not in allowed_branches['$in']:
                     return jsonify({"error": f"Access denied for branch: {branch_name}"}), 403
            elif allowed_branches != branch_name:
                 return jsonify({"error": f"Access denied for branch: {branch_name}"}), 403
        
        data['created_at'] = datetime.now(ZoneInfo("UTC")).isoformat()
        
        # Ensure active is False by default if not provided
        if 'active' not in data:
            data['active'] = False
            
        result = print_settings_collection.insert_one(data)
        
        # If this new setting is active, deactivate other settings FOR THIS BRANCH
        if data.get('active'):
            deactivate_query = {"_id": {"$ne": result.inserted_id}}
            if branch_name:
                deactivate_query["branch_name"] = branch_name
            print_settings_collection.update_many(deactivate_query, {"$set": {"active": False}})
            
        logger.info(f"Print settings created with ID: {result.inserted_id} for branch: {branch_name}")
        return jsonify({"message": "Print settings created successfully", "id": result.inserted_id}), 201
    except Exception as e:
        logger.error(f"Error creating print settings: {str(e)}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/print_settings/<id>', methods=['GET', 'PUT', 'DELETE', 'OPTIONS'])
def print_setting(id):
    if request.method == 'OPTIONS':
        response = jsonify({"success": True})
        response.headers['Access-Control-Allow-Origin'] = '*'
        response.headers['Access-Control-Allow-Methods'] = 'GET, PUT, DELETE, OPTIONS'
        response.headers['Access-Control-Allow-Headers'] = 'Content-Type'
        return response, 200
    
    can_access, filter_query = get_data_scope_filter('print_settings')
    if not can_access:
        return jsonify({"error": "Access denied"}), 403
    
    query = {"_id": id}
    query.update(filter_query)
    
    if request.method == 'GET':
        setting = print_settings_collection.find_one(query)
        if not setting:
            return jsonify({"error": "Setting not found or access denied"}), 404
        return jsonify(convert_objectid_to_str(setting)), 200
    
    if request.method == 'PUT':
        data = request.get_json()
        if not data:
            return jsonify({"error": "No data provided"}), 400
        
        update_data = {k: v for k, v in data.items() if k != '_id' and k != 'active'}
        
        result = print_settings_collection.update_one(query, {"$set": update_data})
        if result.matched_count == 0:
            return jsonify({"error": "Setting not found or access denied"}), 404
        return jsonify({"message": "Print settings updated successfully"}), 200
    
    if request.method == 'DELETE':
        result = print_settings_collection.delete_one(query)
        if result.deleted_count == 0:
            return jsonify({"error": "Setting not found or access denied"}), 404
        return jsonify({"message": "Print settings deleted successfully"}), 200

@app.route('/api/print_settings/set_active/<id>', methods=['PUT'])
def set_active_print_settings(id):
    try:
        can_access, filter_query = get_data_scope_filter('print_settings')
        if not can_access:
            return jsonify({"error": "Access denied"}), 403
            
        # First, find the setting to know its branch_name
        query = {"_id": id}
        query.update(filter_query)
        target_setting = print_settings_collection.find_one(query)
        
        if not target_setting:
            return jsonify({"error": "Setting not found or access denied"}), 404
            
        branch_name = target_setting.get('branch_name')
        
        # Deactivate all settings for THIS branch
        deactivate_query = {"branch_name": branch_name} if branch_name else {}
        # Also apply the scope filter to deactivation for extra safety
        deactivate_query.update(filter_query)
        
        print_settings_collection.update_many(deactivate_query, {"$set": {"active": False}})
        
        # Now activate the specific one
        print_settings_collection.update_one({"_id": id}, {"$set": {"active": True}})
        
        return jsonify({"message": "Active print settings set successfully"}), 200
    except Exception as e:
        logger.error(f"Error activating print setting: {str(e)}")
        return jsonify({"error": "Internal server error"}), 500
    except Exception as e:
        logger.error(f"Error setting active print settings: {str(e)}")
        return jsonify({"error": "Internal server error"}), 500

@app.route('/api/upload-combo-image', methods=['POST', 'OPTIONS'])
def upload_combo_image():
    if request.method == 'OPTIONS':
        return jsonify({"success": True}), 200
    try:
        if 'file' not in request.files:
            logger.error("No file provided for combo image upload")
            return jsonify({"error": "No file provided"}), 400
        
        file = request.files['file']
        if file.filename == '':
            logger.error("No file selected for combo image upload")
            return jsonify({"error": "No file selected"}), 400
        
        if file:
            filename = secure_filename(file.filename)
            if not filename:
                logger.error("Invalid filename for combo image upload")
                return jsonify({"error": "Invalid filename"}), 400
            
            # UPDATED: Use dynamic COMBO_IMAGES_DIR (writable via UPLOAD_FOLDER in EXE)
            upload_dir = COMBO_IMAGES_DIR
            os.makedirs(upload_dir, exist_ok=True)  # Safe create if not exists
            
            filepath = os.path.join(upload_dir, filename)
            
            # Check if file already exists, append timestamp if needed to avoid overwrite
            if os.path.exists(filepath):
                name, ext = os.path.splitext(filename)
                timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
                filename = f"{name}_{timestamp}{ext}"
                filepath = os.path.join(upload_dir, filename)
                logger.info(f"Filename collision detected, renamed to: {filename}")
            
            file.save(filepath)
            logger.info(f"Combo image uploaded successfully: {filename} to {upload_dir}")
            return jsonify({"filename": filename}), 200
        
        return jsonify({"error": "Upload failed - no file processed"}), 500
    
    except Exception as e:
        error_msg = f"Error uploading combo image: {str(e)}\n{traceback.format_exc()}"
        logger.error(error_msg)
        return jsonify({"error": str(e)}), 500

# UPDATED: Serve combo images from dynamic directory
@app.route('/api/combo-images/<filename>')
def serve_combo_image(filename):
    try:
        mode = config.get("mode", "server")
        if mode == 'client':
            server_url = f"http://{config['server_ip']}:6034/api/combo-images/{filename}"
            response = requests.get(server_url, stream=True)
            if response.status_code == 200:
                headers = {k: v for k, v in response.headers.items() if k.lower() in ('content-type', 'content-length')}
                return Response(response.iter_content(chunk_size=8192), headers=headers, status=200)
            else:
                return "Image not found", 404
        
        # 1. Check Primary Combo Directory
        if os.path.exists(os.path.join(COMBO_IMAGES_DIR, filename)):
            return send_from_directory(COMBO_IMAGES_DIR, filename)
            
        # 2. Fallback to Standard Uploads Directory (Legacy Support)
        if os.path.exists(os.path.join(app.config['UPLOAD_FOLDER'], filename)):
            return send_from_directory(app.config['UPLOAD_FOLDER'], filename)
            
        return "Image not found", 404
    except Exception as e:
        # Import NotFound here to check if it's a werkzeug exception
        from werkzeug.exceptions import NotFound
        if isinstance(e, NotFound):
            return "Image not found", 404
        logger.error(f"Error serving combo image {filename}: {str(e)}\n{traceback.format_exc()}")
        return f"Server error: {str(e)}", 500

@app.route('/api/combo-offer', methods=['GET'])
def get_combo_offers():
    try:
        # --- Centralized Permission Filtering ---
        can_access, data_scope_filter = get_data_scope_filter('combo_offers')
        if not can_access:
            # Fallback to frontpage permission
            can_access, data_scope_filter = get_data_scope_filter('frontpage')
            
        if not can_access:
            return jsonify([]), 200

        # NEW: Run cleanup before fetching (in addition to scheduler) - only for current company
        clean_expired_combo_offers(data_scope_filter)
        
        offers = combo_offers_collection.find(data_scope_filter)
        current_time = datetime.now(timezone.utc)  # FIXED: Use timezone.utc for awareness
        offers_list = []
        for offer in offers:
            if 'offer_end_time' in offer and offer['offer_end_time']:
                try:
                    end_time_str = str(offer['offer_end_time'])
                    if end_time_str.endswith('Z'):
                        end_time_str = end_time_str.replace('Z', '+00:00')
                    end_time = datetime.fromisoformat(end_time_str)
                    # FIXED: Ensure end_time is timezone-aware (UTC)
                    if end_time.tzinfo is None:
                        end_time = end_time.replace(tzinfo=timezone.utc)
                    if current_time > end_time:
                        combo_offers_collection.delete_one({'_id': offer['_id']})
                        logger.info(f"Deleted expired combo offer on fetch: {offer['_id']} (ended {end_time})")
                        continue
                except (ValueError, TypeError) as e:
                    logger.error(f"Invalid offer_end_time for combo offer {offer['_id']}: {str(e)}")
            offer = convert_objectid_to_str(offer)
            offers_list.append(offer)
        logger.info(f"Fetched {len(offers_list)} active combo offers")
        return jsonify(offers_list), 200
    except Exception as e:
        logger.error(f"Error fetching combo offers: {str(e)}\n{traceback.format_exc()}")
        return jsonify({"error": str(e)}), 500

