def manage_offers():
    """Check all items and update offer status based on current time."""
    try:
        current_time = datetime.now(ZoneInfo("UTC"))
        items = items_collection.find()
        for item in items:
            item_id = item['_id']
            offer_start_time = item.get('offer_start_time')
            offer_end_time = item.get('offer_end_time')
            should_unset = False
            if offer_start_time and offer_end_time:
                try:
                    start_time = datetime.fromisoformat(str(offer_start_time).replace('Z', '+00:00'))
                    end_time = datetime.fromisoformat(str(offer_end_time).replace('Z', '+00:00'))
                    if current_time > end_time:
                        should_unset = True
                        logger.info(f"Offer expired for item {item.get('item_name')} (ID: {item_id})")
                    elif start_time > end_time:
                        should_unset = True
                        logger.warning(f"Invalid offer times for item {item_id}: start after end")
                    else:
                        logger.debug(f"Offer for item {item.get('item_name')} (ID: {item_id}) is active or pending")
                except (ValueError, TypeError) as e:
                    logger.warning(f"Invalid offer time format for item {item_id}: {str(e)}")
                    should_unset = True
            elif offer_end_time:
                try:
                    end_time = datetime.fromisoformat(str(offer_end_time).replace('Z', '+00:00'))
                    if current_time > end_time:
                        should_unset = True
                        logger.info(f"Offer expired for item {item.get('item_name')} (ID: {item_id})")
                except (ValueError, TypeError) as e:
                    logger.warning(f"Invalid offer_end_time for item {item_id}: {str(e)}")
                    should_unset = True
            if should_unset:
                items_collection.update_one(
                    {'_id': item_id},
                    {'$unset': {'offer_price': "", 'offer_start_time': "", 'offer_end_time': ""}}
                )
                logger.info(f"Unset offer fields for item {item.get('item_name')} (ID: {item_id})")
    except Exception as e:
        logger.error(f"Error in manage_offers: {str(e)}")
def manage_combo_offers():
    """Check all combo offers and delete them when end time is reached."""
    try:
        current_time = datetime.now(ZoneInfo("UTC"))
        offers = combo_offers_collection.find()
        for offer in offers:
            offer_id = offer['_id']
            offer_end_time = offer.get('offer_end_time')
            if offer_end_time:
                try:
                    end_time = datetime.fromisoformat(str(offer_end_time).replace('Z', '+00:00'))
                    if end_time.tzinfo is None:
                        end_time = end_time.replace(tzinfo=timezone.utc)
                    if current_time > end_time:
                        combo_offers_collection.delete_one({'_id': offer_id})
                        logger.info(f"Deleted expired combo offer: {offer_id}")
                except (ValueError, TypeError) as e:
                    logger.warning(f"Invalid offer_end_time for combo offer {offer_id}: {str(e)}")
    except Exception as e:
        logger.error(f"Error in manage_combo_offers: {str(e)}")
def schedule_tasks():
    if schedule:
        schedule.every(1).minutes.do(manage_offers)
        schedule.every(1).minutes.do(manage_combo_offers)
        while True:
            schedule.run_pending()
            time.sleep(1)
def start_scheduler():
    scheduler_thread = threading.Thread(target=schedule_tasks, daemon=True)
    scheduler_thread.start()
    logger.info("Automatic backup, offer, and combo offer scheduler started")
    # Schedule backup with initial interval
    settings = get_system_settings()
    interval = settings.get('backup_interval_hours', 6)
    if schedule:
        schedule.every(interval).hours.do(create_backup).tag('backup')
        logger.info(f"Scheduled automatic backups every {interval} hours")

@app.route('/api/company-details', methods=['POST', 'GET', 'OPTIONS'])
def manage_company_details():
    if request.method == 'OPTIONS':
        response = jsonify({"success": True})
        response.headers['Access-Control-Allow-Origin'] = '*'
        response.headers['Access-Control-Allow-Methods'] = 'GET, POST, OPTIONS'
        response.headers['Access-Control-Allow-Headers'] = 'Content-Type'
        return response, 200
    if request.method == 'POST':
        try:
            data = request.get_json()
            if not data:
                logger.error("No data provided in POST request")
                return jsonify({"error": "No data provided"}), 400
            # UPDATED: Handle new contact structure - ensure each contact has phoneCountryCode, whatsappCountryCode, and websites array
            contacts = data.get('contacts', [])
            for contact in contacts:
                if 'phoneCountryCode' not in contact:
                    contact['phoneCountryCode'] = '+91' # Default
                if 'whatsappCountryCode' not in contact:
                    contact['whatsappCountryCode'] = '+91' # Default
                if 'websites' not in contact:
                    contact['websites'] = [] # Ensure array for multiple websites
                if 'websites' in contact and not isinstance(contact['websites'], list):
                    contact['websites'] = [contact['websites']] if contact['websites'] else []
            # NEW: Ensure specialTimings is an array
            special_timings = data.get('specialTimings', [])
            if not isinstance(special_timings, list):
                special_timings = []
            
            # Sanitize times to 24-hour format
            opening_time = convert_to_24h(data.get('openingTime', ''))
            closing_time = convert_to_24h(data.get('closingTime', ''))
            
            for special in special_timings:
                if 'startTime' in special:
                    special['startTime'] = convert_to_24h(special['startTime'])
                if 'endTime' in special:
                    special['endTime'] = convert_to_24h(special['endTime'])

            # Multi-branch support: Extract from headers or data
            company_name = request.headers.get('X-Company-Name') or data.get('company_name', '')
            branch_name = request.headers.get('X-Branch-Name') or data.get('branch_name', '') or 'All Branches'

            company_data = {
                '_id': str(uuid.uuid4()),
                'company_name': company_name,
                'branch_name': branch_name,
                'restaurantName': data.get('restaurantName', ''),
                'ownerName': data.get('ownerName', ''),
                # NEW: Company Licence field
                'companyLicence': data.get('companyLicence', ''),
                'businessType': data.get('businessType', ''),
                'otherBusinessType': data.get('otherBusinessType', ''),
                'taxType': data.get('taxType', ''),
                'taxPercentage': data.get('taxPercentage', ''),
                'taxNumber': data.get('taxNumber', ''),
                'fssaiNumber': data.get('fssaiNumber', ''),
                'panNumber': data.get('panNumber', ''),
                'openingTime': opening_time,
                'closingTime': closing_time,
                'totalTime': data.get('totalTime', ''),
                # NEW: Special Timings
                'specialTimings': special_timings,
                # UPDATED: Addresses now use dynamic fields
                'addresses': data.get('addresses', [{'country': '', 'field1': '', 'field2': '', 'field3': '', 'flat_villa_no': '', 'building_name': ''}]),
                'contacts': contacts, 
                'bankName': data.get('bankName', ''),
                'accountHolderName': data.get('accountHolderName', ''),
                'accountNumber': data.get('accountNumber', ''),
                'ifscCode': data.get('ifscCode', ''),
                'upiId': data.get('upiId', ''),
                'currencyType': data.get('currencyType', ''), 
                'created_at': datetime.now(ZoneInfo("Asia/Kolkata")).isoformat()
            }
            
            # Upsert logic: If a record exists for this exact company and branch, update it.
            # Otherwise insert a new one. This keeps history clean.
            existing = company_details_collection.find_one({
                'company_name': company_name,
                'branch_name': branch_name
            })
            
            if existing:
                company_details_collection.update_one({'_id': existing['_id']}, {'$set': company_data})
                inserted_id = existing['_id']
            else:
                result = company_details_collection.insert_one(company_data)
                inserted_id = result.inserted_id

            logger.info(f"Company details saved with ID: {inserted_id}")
            return jsonify({
                "message": "Company details saved successfully",
                "id": inserted_id,
                "companyDetails": company_data
            }), 201
        except Exception as e:
            logger.error(f"Error saving company details: {str(e)}\n{traceback.format_exc()}")
            return jsonify({"error": f"Failed to save company details: {str(e)}"}), 500
    if request.method == 'GET':
        try:
            can_access, filter_query = get_data_scope_filter('company_details')
            if not can_access:
                return jsonify({"companyDetails": []}), 200
            
            # For Group Admins, we might want to see unique companies
            details = list(company_details_collection.find(filter_query))
            serialized_details = []
            for detail in details:
                detail['_id'] = str(detail['_id'])
                if 'contacts' in detail:
                    for contact in detail['contacts']:
                        if 'phoneCountryCode' not in contact: contact['phoneCountryCode'] = '+91'
                        if 'whatsappCountryCode' not in contact: contact['whatsappCountryCode'] = '+91'
                        if 'websites' not in contact: contact['websites'] = []
                if 'specialTimings' not in detail: detail['specialTimings'] = []
                if 'companyLicence' not in detail: detail['companyLicence'] = ''
                serialized_details.append(detail)
            
            return jsonify({"companyDetails": serialized_details}), 200
        except Exception as e:
            logger.error(f"Error retrieving company details: {str(e)}")
            return jsonify({"error": f"Failed to retrieve company details: {str(e)}"}), 500

@app.route('/api/user-companies', methods=['GET'])
def get_user_companies():
    """
    Returns the list of onboarded companies the authenticated user has access to.
    Unlike company-details, this returns the foundational structural companies.
    """
    try:
        user_id, role = get_request_user_info()
        if not user_id:
            return jsonify({"companies": []}), 200
            
        user = users_collection.find_one({"_id": user_id})
        if not user:
            # Check worker collection as fallback
            user = worker_collection.find_one({"_id": user_id})
            if not user:
                return jsonify({"companies": []}), 200
            
        role_norm = str(role).lower().replace(' ', '').replace('_', '')
        tenant_id = user.get("tenant_id")
        
        comps = []
        if role_norm in ['superadmin', 'groupadmin', 'masteradmin']:
            comps = list(companies_collection.find({}))
        elif role_norm == 'tenantadmin' and tenant_id:
            comps = list(companies_collection.find({"tenant_id": tenant_id}))
        else:
            comp_id = user.get("company_id")
            if comp_id:
                comps = list(companies_collection.find({"_id": comp_id}))
            else:
                # Try by name if ID is missing
                comp_name = user.get("company_name") or user.get("company")
                if comp_name:
                    comps = list(companies_collection.find({"company_name": comp_name}))
                    
        for c in comps:
            c['_id'] = str(c['_id'])
            
        return jsonify({"companies": comps}), 200
    except Exception as e:
        logger.error(f"Error fetching user companies: {str(e)}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/company-overview', methods=['GET'])
def get_company_overview():
    """
    Overview endpoint to provide a list of unique companies and their latest details.
    Same pattern as System Settings multi-company selection.
    """
    try:
        # Get all company details reachable by the user
        can_access, filter_query = get_data_scope_filter('company_details')
        if not can_access:
            return jsonify({"companies": []}), 200
            
        all_details = list(company_details_collection.find(filter_query))
        
        # 1. Get unique companies from details
        company_records = {}
        for d in all_details:
            c_name = d.get('company_name')
            if not c_name: continue
            
            # Keep newest record per company (or specifically 'All Branches' record)
            # This is a simplified overview.
            if c_name not in company_records:
                company_records[c_name] = d
            else:
                # Preference: 'All Branches' record or newer timestamp
                if d.get('branch_name') == 'All Branches':
                    company_records[c_name] = d
                elif company_records[c_name].get('branch_name') != 'All Branches':
                    # Compare timestamps if available
                    d_time = d.get('created_at', '')
                    r_time = company_records[c_name].get('created_at', '')
                    if d_time > r_time:
                        company_records[c_name] = d
        
        # 2. Cross-reference with all known companies in the system (from roles/users if needed)
        # But usually company_details is the source of truth for these profiles.
        
        result = []
        for c_name, record in company_records.items():
            record['_id'] = str(record['_id'])
            result.append(record)
            
        return jsonify({"companies": result}), 200
    except Exception as e:
        logger.error(f"Error in company-overview: {str(e)}")
        return jsonify({"error": str(e)}), 500

# Reusing global get_company_id_prefix defined above

def generate_order_number(order_type, branch_name=None, company_name=None):
    if order_counters_collection is None:
        raise Exception("Database not initialized correctly. Order counters collection is missing.")
    
    # NEW: Resolve branch/company from headers if not provided
    if not branch_name or not company_name:
        req_user_id, req_role = get_request_user_info()
        user_doc = users_collection.find_one({'_id': req_user_id}) if req_user_id else None
        
        branch_name = branch_name or request.headers.get('X-Branch-Name') or (user_doc.get('branch_name') if user_doc else None)
        company_name = company_name or request.headers.get('X-Company-Name') or (user_doc.get('company_name') if user_doc else None)

    # NEW: Robust mapping for shorthand prefixes (handles 'Take Away', 'Takeaway', etc.)
    normalized_type = str(order_type).strip().lower()
    type_prefix_map = {
        'takeaway': 'TAK',
        'take away': 'TAK',
        'dine in': 'DIN',
        'dine-in': 'DIN',
        'online delivery': 'OND',
        'delivery': 'OND'
    }
    type_prefix = type_prefix_map.get(normalized_type, order_type)[:3].upper()

    # NEW: Generate company-specific prefix using the same method as employees
    company_prefix = get_company_id_prefix(company_name, order_counters_collection)
    
    full_prefix = f"{company_prefix}-{type_prefix}"

    # NEW: Branch-specific counter ID
    counter_id = f"{company_name}_{branch_name}_{full_prefix}" if company_name and branch_name else full_prefix

    counter_doc = order_counters_collection.find_one_and_update(
        {'_id': counter_id}, 
        {'$inc': {'count': 1}},
        upsert=True,
        return_document=True
    )
    return f"{full_prefix}-{counter_doc['count']:04d}"
@app.route('/api/activeorders', methods=['POST'])
def save_active_order():
    try:
        data = request.get_json()
        order_type = data.get('orderType', 'Dine In')
        active_branch = request.headers.get('X-Branch-Name') or data.get('branch')
        active_company = request.headers.get('X-Company-Name') or data.get('company')
        order_no = generate_order_number(order_type, active_branch, active_company)
        cart_items = data.get('cartItems', [])
        for item in cart_items:
            required_kitchens = set()
            if item.get('kitchen'):
                required_kitchens.add(item['kitchen'])
            for addon_name, qty in item.get('addonQuantities', {}).items():
                if qty > 0 and 'addonVariants' in item and addon_name in item['addonVariants']:
                    if item['addonVariants'][addon_name].get('kitchen'):
                        required_kitchens.add(item['addonVariants'][addon_name]['kitchen'])
            for combo_name, qty in item.get('comboQuantities', {}).items():
                if qty > 0 and 'comboVariants' in item and combo_name in item['comboVariants']:
                    if item['comboVariants'][combo_name].get('kitchen'):
                        required_kitchens.add(item['comboVariants'][combo_name]['kitchen'])
            item['requiredKitchens'] = list(required_kitchens)
            item['kitchenStatuses'] = {kitchen: 'Pending' for kitchen in required_kitchens}
            item['served'] = False

            # Ensure category is present
            if 'category' not in item or not item['category']:
                try:
                    # Try to find the item in the database to get the category (item_group)
                    db_item = items_collection.find_one({'item_name': item.get('name')})
                    if db_item:
                        item['category'] = db_item.get('item_group', 'N/A')
                    else:
                        item['category'] = 'N/A'
                except Exception as e:
                    logger.error(f"Error fetching category for item {item.get('name')}: {str(e)}")
                    item['category'] = 'N/A'
        active_order = {
            'orderId': str(uuid.uuid4()),
            'orderNo': order_no,
            'customerName': data.get('customerName', 'N/A'),
            'tableNumber': data.get('tableNumber', 'N/A'),
            'floor': data.get('floor', 'N/A'),
            'chairsBooked': data.get('chairsBooked', []),
            'phoneNumber': data.get('phoneNumber', ''),
            'deliveryAddress': data.get('deliveryAddress', {}),
            'whatsappNumber': data.get('whatsappNumber', ''),
            'email': data.get('email', ''),
            'cartItems': cart_items,
            'timestamp': data.get('timestamp', datetime.now(timezone.utc).isoformat()),
            'orderType': order_type,
            'status': 'Pending', # New status field
            'paid': False,
            'created_at': datetime.now(timezone.utc),
            'deliveryPersonId': data.get('deliveryPersonId', ''),
            'deliveryPersonName': data.get('deliveryPersonName', ''),
            'pickedUpTime': data.get('pickedUpTime', None),
            'kitchenPreparedAt': data.get('kitchenPreparedAt', {}) # NEW: Track when items are prepared per kitchen
        }
        activeorders_collection.insert_one(active_order)
        kitchen_saved_collection.insert_one(active_order.copy())
        logger.info(f"Created order: {active_order['orderId']} with order number: {order_no}")
        socketio.emit('order_update', {'order_id': active_order['orderId'], 'status': 'New'})
        return jsonify({'success': True, 'orderId': active_order['orderId'], 'orderNo': order_no}), 201
    except Exception as e:
        logger.error(f"Error saving active order: {str(e)}")
        logger.error(traceback.format_exc())
        return jsonify({'error': str(e)}), 500
def get_hierarchical_users(current_user_id, role):
    """
    Returns a list of User IDs, Emails, and Names that the current user is allowed to access
    based on their Role and 'accessible_designations'.
    Always includes the current user's own identifiers.
    """
    # Use robust self-identification
    allowed_ids, allowed_emails, allowed_names = get_own_identifiers(current_user_id)
    allowed_ids = set(str(i) for i in (allowed_ids or []) if i is not None)
    allowed_emails = set(str(e).lower().strip() for e in (allowed_emails or []) if e)
    allowed_names = set(str(n).strip() for n in (allowed_names or []) if n)
    
    logger.info(f"=== HIERARCHY ACCESS DEBUG START ===")
    logger.info(f"Current User ID: {current_user_id}, Role: {role}")
    
    # 1. Resolve Company context for the user to optimize searches
    active_company = None
    # Robust lookup handling both string and ObjectId
    user_doc = users_collection.find_one({'_id': current_user_id})
    if not user_doc and isinstance(current_user_id, str) and ObjectId.is_valid(current_user_id):
        user_doc = users_collection.find_one({'_id': ObjectId(current_user_id)})
        
    if user_doc:
        raw_company = user_doc.get('company') or user_doc.get('company_name')
        if raw_company and isinstance(raw_company, str) and ',' in raw_company:
            parts = [p.strip() for p in raw_company.split(',') if p.strip().lower() != 'all']
            active_company = parts[0] if parts else 'All'
        else:
            active_company = raw_company

        # Ensure the manager's own designation (if stored in their user profile) is included
        my_desig = str(user_doc.get('designation', user_doc.get('role', ''))).strip()
        if my_desig:
            allowed_names.add(my_desig)
            allowed_names.add(my_desig.lower())
            allowed_names.add(my_desig.title())

    # Fetch accessible designations from BOTH the specific user and their role
    # This allows individual overrides (e.g., Arjun being mapped to "Cook" specifically)
    user_designations = []
    if user_doc:
        user_designations = user_doc.get('accessible_designations', []) or user_doc.get('accessibleDesignations', [])
        if not isinstance(user_designations, list): user_designations = []

    # Fetch accessible designations for this role
    role_search = (role or '').strip()
    target_designations = list(user_designations) # Start with user-specific ones
    
    if role_search:
        # Use active_company context resolved at start of function
        comp_filter = active_company if active_company else 'All'
        import re
        role_regex = {'$regex': f"^{re.escape(role_search)}$", '$options': 'i'}
        
        role_perm = role_permissions_collection.find_one({'role': role_regex, 'company': comp_filter})
        if not role_perm:
            # Fallback for 'All' or Title/Lower
            role_perm = role_permissions_collection.find_one({'role': role_regex})
        
        if role_perm:
            role_designations = role_perm.get('accessible_designations', [])
            if role_designations:
                target_designations.extend(role_designations)
    
    if user_doc:
        my_desig = str(user_doc.get('designation', user_doc.get('role', ''))).strip().lower()
        # Add the user's own designation if it isn't already in the list
        if my_desig and my_desig not in [str(d).strip().lower() for d in target_designations]:
            target_designations.append(my_desig)

    if target_designations:
        target_designations = [str(d).strip().lower() for d in target_designations]
        logger.info(f"Hierarchy Access for {role_search}: Targets = {target_designations}")

        # Find all workers with these designations (Filtered by Company with robust matching)
        worker_query = {}
        if active_company:
            import re
            # Robust company matching for string, array, or stringified array (e.g. "['All', 'companyone']")
            # This regex matches the company name as a whole word within any string structure.
            c_pattern = f"(^|['\"\\s,\\[]){re.escape(active_company)}(['\"\\s,\\]]|$)"
            worker_query['$or'] = [
                {'company': {'$regex': c_pattern, '$options': 'i'}}, 
                {'company_name': {'$regex': c_pattern, '$options': 'i'}},
                {'company_names': {'$regex': c_pattern, '$options': 'i'}}
            ]
        
        all_workers = list(worker_collection.find(worker_query))
        matched_worker_emails = set()
        matched_worker_ids = set()
        
        for w in all_workers:
            desig = str(w.get('employeeDesignation', w.get('designation', ''))).strip()
            desig_lower = desig.lower()
            if "all designations (system bypass)" in target_designations or desig_lower in target_designations:
                # Add the designation name itself to allowed_names
                if desig:
                    allowed_names.add(desig)
                    allowed_names.add(desig_lower)
                    
                w_id = str(w.get('_id', ''))
                # Support multiple ID variations for subordinates
                w_emp_id = str(w.get('employeeId') or w.get('employee_id') or w.get('employeeCode') or '')
                w_email = str(w.get('email', '')).strip().lower()
                w_name = w.get('name') or w.get('employeeName')
                
                if w_id: allowed_ids.add(w_id)
                if w_emp_id: 
                    allowed_ids.add(w_emp_id)
                    matched_worker_ids.add(w_emp_id)
                if w_email: 
                    allowed_emails.add(w_email)
                    matched_worker_emails.add(w_email)
                if w_name:
                    allowed_names.add(str(w_name))

        # Now find Users (Login accounts) that correspond to these matched workers
        if matched_worker_emails or matched_worker_ids:
            user_auth_query = {'$or': []}
            if matched_worker_emails:
                user_auth_query['$or'].append({'email': {'$in': list(matched_worker_emails)}})
            if matched_worker_ids:
                user_auth_query['$or'].append({'employeeId': {'$in': list(matched_worker_ids)}})
                user_auth_query['$or'].append({'employee_id': {'$in': list(matched_worker_ids)}})
                user_auth_query['$or'].append({'workerId': {'$in': list(matched_worker_ids)}})
            
            matched_users = list(users_collection.find(user_auth_query))
            for u in matched_users:
                u_id = str(u.get('_id', ''))
                u_emp_id = str(u.get('employeeId', ''))
                u_email = str(u.get('email', '')).strip().lower()
                u_name = u.get('username')
                
                if u_id: allowed_ids.add(u_id)
                if u_emp_id: allowed_ids.add(u_emp_id)
                if u_email: allowed_emails.add(u_email)
                if u_name: allowed_names.add(str(u_name))
                logger.debug(f"  Γ£ô HIERARCHY MATCH: Resolved to user {u_email}")

    logger.info(f"Hierarchy resolution: {len(allowed_ids)} IDs, {len(allowed_emails)} Emails, {len(allowed_names)} Names")
    logger.info(f"=== HIERARCHY ACCESS DEBUG END ===")
    
    return list(allowed_ids), list(allowed_emails), list(allowed_names)

@app.route('/api/activeorders', methods=['GET'])
def get_active_orders():
    try:
        # --- Centralized Permission Filtering ---
        can_access, filter_query = get_data_scope_filter('active_orders')
        if not can_access:
            # Fallback to tables page permission
            can_access, filter_query = get_data_scope_filter('tables')
            
        if not can_access:
            # Fallback to frontpage permission
            can_access, filter_query = get_data_scope_filter('frontpage')
            
        if not can_access:
            return jsonify([]), 200
        
        # Note: Previous manual hierarchy logic removed in favor of get_data_scope_filter
        
        # Apply filter to activeorders_collection
        orders = list(activeorders_collection.find(filter_query))
        
        # NEW: Populate categories for items, addons, and combos
        for order in orders:
            if 'cartItems' in order and isinstance(order['cartItems'], list):
                for item in order['cartItems']:
                    # 1. Main Item Category
                    item_name = item.get('name')
                    current_category = item.get('category')
                    
                    if item_name:
                        item_data = items_collection.find_one({'name': item_name})
                        if item_data:
                            # Use DB value if exists, else fallback to current, else "N/A"
                            item['category'] = item_data.get('category') or item_data.get('item_group') or current_category or "N/A"
                        else:
                            # Fallback to current if DB lookup fails
                            item['category'] = current_category or "N/A"
                    else:
                        item['category'] = current_category or "N/A"
                    
                    # 2. Addon Categories
                    if 'addonQuantities' in item and isinstance(item['addonQuantities'], dict):
                        item['addonCategories'] = {}
                        for addon_name in item['addonQuantities']:
                             addon_data = items_collection.find_one({'name': addon_name})
                             if addon_data:
                                 item['addonCategories'][addon_name] = addon_data.get('category') or addon_data.get('item_group') or "Addon"
                             else:
                                 item['addonCategories'][addon_name] = "Addon"

                    # 3. Combo Categories
                    if 'comboQuantities' in item and isinstance(item['comboQuantities'], dict):
                        item['comboCategories'] = {}
                        for combo_name in item['comboQuantities']:
                             combo_data = items_collection.find_one({'name': combo_name})
                             if combo_data:
                                 item['comboCategories'][combo_name] = combo_data.get('category') or combo_data.get('item_group') or "Combo"
                             else:
                                 item['comboCategories'][combo_name] = "Combo"

                    # 4. Combo Offer Sub-Items Categories
                    if 'comboItems' in item and isinstance(item['comboItems'], list):
                        for sub_item in item['comboItems']:
                            sub_item_name = sub_item.get('name')
                            sub_current_cat = sub_item.get('category')
                            
                            if sub_item_name:
                                sub_item_data = items_collection.find_one({'name': sub_item_name})
                                if sub_item_data:
                                    sub_item['category'] = sub_item_data.get('category') or sub_item_data.get('item_group') or sub_current_cat or "Combo Sub-Item"
                                else:
                                    sub_item['category'] = sub_current_cat or "Combo Sub-Item"
                            else:
                                sub_item['category'] = sub_current_cat or "Combo Sub-Item"

        return jsonify(convert_objectid_to_str(orders)), 200
    except Exception as e:
        logger.error(f"Error fetching active orders: {str(e)}")
        logger.error(traceback.format_exc())
        return jsonify({'error': str(e)}), 500
@app.route('/api/activeorders/<order_id>/items/<item_id>/mark-prepared', methods=['POST'])
def mark_item_prepared_active(order_id, item_id):
    try:
        data = request.get_json()
        kitchen = data.get('kitchen')
        if not kitchen:
            return jsonify({'success': False, 'error': 'Kitchen not provided'}), 400
        for collection in [activeorders_collection, kitchen_saved_collection]:
            order = collection.find_one({'orderId': order_id})
            if not order:
                return jsonify({'success': False, 'error': 'Order not found'}), 404
            found = False
            for item in order['cartItems']:
                if item['id'] == item_id:
                    if 'kitchenStatuses' not in item:
                        item['kitchenStatuses'] = {}
                    if item['kitchenStatuses'].get(kitchen) in ['Prepared', 'PickedUp']:
                        return jsonify({'success': False, 'error': 'Kitchen already marked as prepared or picked up'}), 400
                    item['kitchenStatuses'][kitchen] = 'Prepared'
                    # NEW: Record timestamp
                    if 'kitchenPreparedAt' not in item:
                        item['kitchenPreparedAt'] = {}
                    item['kitchenPreparedAt'][kitchen] = datetime.now(timezone.utc).isoformat()
                    
                    found = True
                    break
            if not found:
                return jsonify({'success': False, 'error': 'Item not found'}), 404
            collection.replace_one({'orderId': order_id}, order)
        logger.info(f"Marked item {item_id} in order {order_id} as Prepared for kitchen {kitchen}")
        socketio.emit('order_update', {'order_id': order_id, 'item_id': item_id, 'status': 'Prepared'})
        return jsonify({'success': True, 'status': 'Prepared'}), 200
    except Exception as e:
        logger.error(f"Error in mark-prepared: {str(e)}")
        logger.error(traceback.format_exc())
        return jsonify({'success': False, 'error': str(e)}), 500
@app.route('/api/activeorders/<order_id>/items/<item_id>/mark-pickedup', methods=['POST'])
def mark_item_pickedup_active(order_id, item_id):
    try:
        data = request.get_json()
        kitchen = data.get('kitchen')
        if not kitchen:
            return jsonify({'success': False, 'error': 'Kitchen not provided'}), 400
        for collection in [activeorders_collection, kitchen_saved_collection]:
            order = collection.find_one({'orderId': order_id})
            if not order:
                return jsonify({'success': False, 'error': 'Order not found'}), 404
            found = False
            for item in order['cartItems']:
                if item['id'] == item_id:
                    if 'kitchenStatuses' not in item:
                        item['kitchenStatuses'] = {}
                    status = item['kitchenStatuses'].get(kitchen)
                    if status == 'Pending':
                        logger.warning(f"Item {item_id} in order {order_id} was Pending, setting to Prepared automatically for kitchen {kitchen}")
                        item['kitchenStatuses'][kitchen] = 'Prepared'
                    elif status != 'Prepared':
                        return jsonify({'success': False, 'error': 'Item must be prepared before picking up'}), 400
                    item['kitchenStatuses'][kitchen] = 'PickedUp'
                    # NEW: Track Picked Up Timestamp
                    if 'kitchenPickedUpAt' not in item:
                        item['kitchenPickedUpAt'] = {}
                    item['kitchenPickedUpAt'][kitchen] = datetime.now(timezone.utc).isoformat()
                    
                    found = True
                    found = True
                    break
            if not found:
                return jsonify({'success': False, 'error': 'Item not found'}), 404
            collection.replace_one({'orderId': order_id}, order)
        order = activeorders_collection.find_one({'orderId': order_id})
        picked_up_data = {
            'customerName': order.get('customerName', 'Unknown'),
            'tableNumber': order.get('tableNumber', 'N/A'),
            'items': order.get('cartItems', []),
            'pickupTime': datetime.now(timezone.utc).isoformat(),
            'orderType': order.get('orderType', 'Dine In')
        }
        picked_up_collection.insert_one(picked_up_data)
        logger.info(f"Marked item {item_id} in order {order_id} as PickedUp for kitchen {kitchen}")
        socketio.emit('order_update', {'order_id': order_id, 'item_id': item_id, 'status': 'PickedUp'})
        return jsonify({'success': True, 'status': 'PickedUp'}), 200
    except Exception as e:
        logger.error(f"Error in mark-pickedup: {str(e)}")
        logger.error(traceback.format_exc())
        return jsonify({'success': False, 'error': str(e)}), 500
@app.route('/api/activeorders/<order_id>/items/<item_id>/mark-served', methods=['POST'])
def mark_item_served(order_id, item_id):
    try:
        data = request.get_json()
        served = data.get('served', True)
        if served is None:
            return jsonify({'success': False, 'error': 'Served status not provided'}), 400
        for collection in [activeorders_collection, kitchen_saved_collection]:
            order = collection.find_one({'orderId': order_id})
            if not order:
                return jsonify({'success': False, 'error': 'Order not found'}), 404
            found = False
            for item in order['cartItems']:
                if item['id'] == item_id:
                    if not all(s == 'PickedUp' for s in item['kitchenStatuses'].values()):
                        return jsonify({'success': False, 'error': 'Item must be picked up before serving'}), 400
                    item['served'] = bool(served)
                    found = True
                    break
            if not found:
                return jsonify({'success': False, 'error': 'Item not found'}), 404
            collection.replace_one({'orderId': order_id}, order)
        logger.info(f"Marked item {item_id} in order {order_id} as {'Served' if served else 'Unserved'}")
        socketio.emit('order_update', {'order_id': order_id, 'item_id': item_id, 'status': 'Served'})
        return jsonify({'success': True, 'served': served}), 200
    except Exception as e:
        logger.error(f"Error in mark-served: {str(e)}")
        logger.error(traceback.format_exc())
        return jsonify({'success': False, 'error': str(e)}), 500
@app.route('/api/activeorders/<order_id>/items/<item_id>', methods=['DELETE'])
def delete_order_item(order_id, item_id):
    try:
        for collection in [activeorders_collection, kitchen_saved_collection]:
            order = collection.find_one({'orderId': order_id})
            if not order:
                return jsonify({'success': False, 'error': 'Order not found'}), 404
            order['cartItems'] = [i for i in order['cartItems'] if i['id'] != item_id]
            if not order['cartItems']:
                collection.delete_one({'orderId': order_id})
            else:
                collection.replace_one({'orderId': order_id}, order)
        logger.info(f"Deleted item {item_id} from order {order_id}")
        return jsonify({'success': True}), 200
    except Exception as e:
        logger.error(f"Error deleting item: {str(e)}")
        logger.error(traceback.format_exc())
        return jsonify({'error': str(e)}), 500
@app.route('/api/activeorders/<order_id>', methods=['PUT'])
def update_active_order(order_id):
    try:
        data = request.get_json()
        if '_id' in data:
            del data['_id']
        order_in_db = activeorders_collection.find_one({'orderId': order_id})
        if not order_in_db:
            logger.warning(f"Order not found for update: {order_id}")
            return jsonify({'error': 'Order not found'}), 404
        old_statuses_map = {
            item['id']: {
                'kitchenStatuses': item.get('kitchenStatuses', {}),
                'served': item.get('served', False)
            }
            for item in order_in_db.get('cartItems', []) if 'id' in item
        }
        if 'cartItems' in data:
            for item in data['cartItems']:
                item_id = item.get('id')
                if item_id and item_id in old_statuses_map:
                    old_data = old_statuses_map[item_id]
                    item['kitchenStatuses'] = old_data['kitchenStatuses']
                    item['served'] = old_data['served']
                else:
                    required_kitchens = set()
                    if item.get('kitchen'):
                        required_kitchens.add(item['kitchen'])
                    for addon_name, qty in item.get('addonQuantities', {}).items():
                        if qty > 0 and 'addonVariants' in data and addon_name in data['addonVariants']:
                            if data['addonVariants'][addon_name].get('kitchen'):
                                required_kitchens.add(data['addonVariants'][addon_name]['kitchen'])
                    for combo_name, qty in item.get('comboQuantities', {}).items():
                        if qty > 0 and 'comboVariants' in data and combo_name in data['comboVariants']:
                            if data['comboVariants'][combo_name].get('kitchen'):
                                required_kitchens.add(data['comboVariants'][combo_name]['kitchen'])
                    item['requiredKitchens'] = list(required_kitchens)
                    item['kitchenStatuses'] = {kitchen: 'Pending' for kitchen in required_kitchens}
                    item['served'] = False
        updated_order = {**order_in_db, **data}
        if 'cartItems' in data:
            updated_order['cartItems'] = data['cartItems']
        if 'deliveryPersonId' in updated_order and updated_order['deliveryPersonId']:
            employee = employees_collection.find_one({'employeeId': updated_order['deliveryPersonId']})
            if not employee:
                logger.warning(f"Delivery person not found: {updated_order['deliveryPersonId']}")
                return jsonify({'error': 'Delivery person not found'}), 404
            updated_order['status'] = 'assigned' # Set to assigned instead of deleting
            updated_order['deliveryPersonName'] = employee.get('name', 'N/A')
            # Optional: Move to tripreports if needed, but per requirement, keep in activeorders with status
            logger.info(f"Assigned delivery person {updated_order['deliveryPersonId']} ({updated_order['deliveryPersonName']}) to order {order_id}")
        if updated_order.get('paid', False) and all(item.get('served', False) for item in updated_order.get('cartItems', [])) and updated_order.get('orderType') != 'Online Delivery':
            updated_order['status'] = 'Completed'
        result = activeorders_collection.replace_one({'orderId': order_id}, updated_order)
        kitchen_result = kitchen_saved_collection.replace_one({'orderId': order_id}, updated_order)
        updated_order = activeorders_collection.find_one({'orderId': order_id})
        if result.matched_count > 0 or kitchen_result.matched_count > 0:
            logger.info(f"Updated order: {order_id}")
            return jsonify({'success': True, 'message': 'Order updated', 'order': convert_objectid_to_str(updated_order)}), 200
        logger.info(f"No changes made to order: {order_id}")
        return jsonify({'success': True, 'message': 'No changes made', 'order': convert_objectid_to_str(updated_order)}), 200
    except Exception as e:
        logger.error(f"Error updating active order: {str(e)}")
        logger.error(traceback.format_exc())
        return jsonify({'error': str(e)}), 500
