@app.route('/api/employee-designations/<designation_id>', methods=['PUT', 'DELETE'])
def manage_employee_designation(designation_id):
    # --- Centralized Permission Filtering ---
    can_access, data_scope_filter = get_data_scope_filter('employee_designations')
    if not can_access:
        return jsonify({"error": "Access denied"}), 403

    if request.method == 'PUT':
        try:
            data = request.get_json()
            if not isinstance(data, dict):
                return jsonify({"error": "JSON data must be an object"}), 400
            name = data.get('name')
            if not name or not name.strip():
                return jsonify({"error": "Name is required"}), 400
            
            description = data.get('description', '').strip()
            report_to = data.get('reportTo', '').strip()

            # Check if new name already exists in designations only (scoped to company)
            existing = employee_designations_collection.find_one({"name": name.strip(), **data_scope_filter})
            if existing and str(existing['_id']) != designation_id:
                return jsonify({"error": "Employee designation name already exists"}), 400
            # Match by ID AND tenancy (if added later)
            update_filter = {'_id': designation_id}
            
            # For branch_names, we prefer what's sent in data. 
            # If not sent, we fall back to existing value if found.
            new_branch_names = data.get('branch_names')
            if new_branch_names is None:
                existing_doc = employee_designations_collection.find_one({'_id': designation_id})
                new_branch_names = existing_doc.get('branch_names', []) if existing_doc else []

            result = employee_designations_collection.update_one(
                update_filter,
                {'$set': {
                    'name': name.strip(), 
                    'description': description, 
                    'reportTo': report_to,
                    'show_in_sales_filter': data.get('show_in_sales_filter', False),
                    'branch_names': new_branch_names,
                    'company_names': data.get('company_names', []),
                    'company_name': data.get('company_name', ''),
                    'company': data.get('company_name', '')
                }}
            )
            if result.modified_count == 0:
                return jsonify({"error": "Employee designation not found"}), 404
            logger.info(f"Employee designation updated: {designation_id} to {name}")
            return jsonify({"message": "Employee designation updated successfully"}), 200
        except Exception as e:
            logger.error(f"Error updating employee designation: {str(e)}")
            return jsonify({"error": str(e)}), 500
    elif request.method == 'DELETE':
        try:
            # Check if designation is used in employees
            designation_doc = employee_designations_collection.find_one({'_id': designation_id})
            if not designation_doc:
                return jsonify({"error": "Employee designation not found"}), 404
            used_in_employees = worker_collection.find({'employeeDesignation': designation_doc['name']})
            if list(used_in_employees):
                return jsonify({"error": "Cannot delete: This designation is used by existing employees"}), 400
            # --- CENTRALIZED MULTI-TENANT SAFE DELETION ---
            active_company = request.headers.get('X-Company-Name')
            active_branch = request.headers.get('X-Branch-Name')
            
            is_partial, message = perform_tenant_aware_delete(
                employee_designations_collection, 
                {'_id': designation_id}, 
                active_company, 
                designation_doc, 
                active_branch=active_branch
            )
            
            return jsonify({"message": message}), 200
        except Exception as e:
            logger.error(f"Error deleting employee designation: {str(e)}")
            return jsonify({"error": str(e)}), 500

# Separate Employee Types Endpoints
@app.route('/api/employee-types', methods=['GET', 'POST'])
def employee_types():
    # --- Centralized Permission Filtering ---
    can_access, data_scope_filter = get_data_scope_filter('employee_types')
    if not can_access:
        return jsonify([] if request.method == 'GET' else {"error": "Access denied"}), (200 if request.method == 'GET' else 403)

    if request.method == 'GET':
        try:
            types = list(employee_type_collection.find(data_scope_filter))
            grouped = {}
            for t in types:
                name_key = t.get('name', '').strip().lower()
                if not name_key: continue
                if name_key not in grouped:
                    grouped[name_key] = {
                        'id': str(t['_id']),
                        'global_ref_id': t.get('global_ref_id'),
                        'name': t['name'],
                        'description': t.get('description', ''),
                        'salaryRange': t.get('salaryRange', ''),
                        'designation': t.get('designation', ''),
                        'reportTo': t.get('reportTo', ''),
                        'grade': t.get('grade', ''),
                        'branch_names': set(t.get('branch_names', [])),
                        'company_names': set(t.get('company_names', []))
                    }
                
                # Merge current flat row's data
                if t.get('company_name'):
                    grouped[name_key]['company_names'].add(t['company_name'])
                if t.get('branch_name'):
                    grouped[name_key]['branch_names'].add(t['branch_name'])

            # Convert sets back to lists
            results = []
            for item in grouped.values():
                item['branch_names'] = list(item['branch_names'])
                item['company_names'] = list(item['company_names'])
                results.append(item)
                
            return jsonify(results), 200
        except Exception as e:
            logger.error(f"Error fetching employee types: {str(e)}")
            return jsonify({"error": str(e)}), 500
    elif request.method == 'POST':
        try:
            data = request.get_json()
            if not isinstance(data, dict):
                return jsonify({"error": "JSON data must be an object"}), 400
            name = data.get('name')
            if not name or not name.strip():
                return jsonify({"error": "Name is required"}), 400
            
            description = data.get('description', '').strip()
            salary_range = data.get('salaryRange', '').strip()
            designation = data.get('designation', '').strip()
            report_to = data.get('reportTo', '').strip()
            grade = data.get('grade', '').strip()
            branch = data.get('branch', '').strip()

            # --- NEW MULTI-TENANT RESOLUTION AND SAVING LOGIC ---
            company_names = data.get('company_names', [])
            branch_names = data.get('branch_names', [])
            active_company = request.headers.get('X-Company-Name') or data.get('company_name', '')
            active_branch = request.headers.get('X-Branch-Name') or data.get('branch_name', '')

            if not company_names and active_company:
                company_names = [active_company]
            if not branch_names and active_branch:
                branch_names = [active_branch]

            if not company_names:
                return jsonify({"error": "At least one company must be selected."}), 400

            created_docs = []
            created_at = datetime.now(ZoneInfo("UTC")).isoformat()

            global_ref_id = str(__import__('uuid').uuid4())
            
            for comp_name in company_names:
                ids = _resolve_tenant_company_branch(comp_name)
                if not ids.get("company_id"): continue
                
                # ALWAYS create the "All Branches" base record
                doc_all = {
                    "_id": str(__import__('uuid').uuid4()),
                    "global_ref_id": global_ref_id,
                    "tenant_id": ids.get("tenant_id"),
                    "company_id": ids.get("company_id"),
                    "company_name": comp_name,
                    "branch_id": None,
                    "branch_name": "All Branches",
                    "name": name.strip(),
                    "description": description,
                    "salaryRange": salary_range,
                    "designation": designation,
                    "reportTo": report_to,
                    "grade": grade,
                    "created_at": created_at
                }
                employee_type_collection.insert_one(doc_all)
                created_docs.append(doc_all)
                
                # Add specific branch records
                if branch_names:
                    for br_name in branch_names:
                        br_ids = _resolve_tenant_company_branch(comp_name, br_name)
                        if not br_ids.get("branch_id"): continue
                        
                        doc_br = {
                            "_id": str(__import__('uuid').uuid4()),
                            "global_ref_id": global_ref_id,
                            "tenant_id": br_ids.get("tenant_id"),
                            "company_id": br_ids.get("company_id"),
                            "company_name": comp_name,
                            "branch_id": br_ids.get("branch_id"),
                            "branch_name": br_name,
                            "name": name.strip(),
                            "description": description,
                            "salaryRange": salary_range,
                            "designation": designation,
                            "reportTo": report_to,
                            "grade": grade,
                            "created_at": created_at
                        }
                        employee_type_collection.insert_one(doc_br)
                        created_docs.append(doc_br)

            logger.info(f"Employee types created: {len(created_docs)} rows for {name}")
            return jsonify(convert_objectid_to_str(created_docs)), 201
        except Exception as e:
            logger.error(f"Error creating employee type: {str(e)}")
            return jsonify({"error": str(e)}), 500

@app.route('/api/employee-types/bulk/<global_ref_id>', methods=['PUT'])
def bulk_update_employee_type(global_ref_id):
    try:
        data = request.get_json()
        can_access, data_scope_filter = get_data_scope_filter('employee_types')
        if not can_access: return jsonify({"error": "Access denied"}), 403

        name = (data.get('name') or '').strip()
        exclude_keys = {'name', 'company_name', 'branch_name', 'company_names', 'branch_names', '_id', 'global_ref_id'}
        update_data = {k: v for k, v in data.items() if k not in exclude_keys}
        if name: update_data['name'] = name
        
        from datetime import datetime
        try:
            from zoneinfo import ZoneInfo
            update_data['modified_at'] = datetime.now(ZoneInfo("UTC")).isoformat()
        except: pass

        ctx = _get_tenant_context_for_update_delete()
        update_filter = {"$and": [data_scope_filter, _build_strict_bulk_filter(global_ref_id, ctx)]}
        
        # --- SYNCHRONIZATION LOGIC FOR ADDED/REMOVED BRANCHES ---
        company_names = data.get('company_names', [])
        branch_names = data.get('branch_names', [])
        if branch_names:
            branch_names = [b for b in branch_names if b and str(b).lower() not in ['all', 'all branches', 'global', 'all companies']]
            
        if company_names:
            existing_records = list(employee_type_collection.find(update_filter))
            if existing_records:
                desired_combinations = set()
                for comp_name in company_names:
                    desired_combinations.add((comp_name, "All Branches"))
                    if branch_names:
                        for br_name in branch_names:
                            br_ids = _resolve_tenant_company_branch(comp_name, br_name)
                            if br_ids.get("branch_id"):
                                desired_combinations.add((comp_name, br_name))
                                
                existing_combinations = {(r.get('company_name'), r.get('branch_name')) for r in existing_records}
                
                combinations_to_add = desired_combinations - existing_combinations
                combinations_to_remove = existing_combinations - desired_combinations
                
                import uuid
                if combinations_to_add:
                    base_record = existing_records[0].copy()
                    for k in ['_id', 'company_name', 'company_id', 'branch_name', 'branch_id', 'tenant_id']:
                        base_record.pop(k, None)
                    base_record.update(update_data)
                    
                    for comp_name, br_name in combinations_to_add:
                        ids = _resolve_tenant_company_branch(comp_name)
                        if not ids.get("company_id"): continue
                        
                        br_id = None
                        if br_name != "All Branches":
                            br_ids = _resolve_tenant_company_branch(comp_name, br_name)
                            if not br_ids.get("branch_id"): continue
                            br_id = br_ids.get("branch_id")
                            tenant_id = br_ids.get("tenant_id")
                        else:
                            tenant_id = ids.get("tenant_id")
                            
                        new_doc = {
                            "_id": str(uuid.uuid4()),
                            "global_ref_id": global_ref_id,
                            "tenant_id": tenant_id,
                            "company_id": ids.get("company_id"),
                            "company_name": comp_name,
                            "branch_id": br_id,
                            "branch_name": br_name,
                            **base_record
                        }
                        employee_type_collection.insert_one(new_doc)
                        
                if combinations_to_remove:
                    for comp_name, br_name in combinations_to_remove:
                        employee_type_collection.delete_one({"$and": [
                            update_filter, 
                            {"company_name": comp_name, "branch_name": br_name}
                        ]})
        # --- END SYNCHRONIZATION LOGIC ---
        
        result = employee_type_collection.update_many(update_filter, {'$set': update_data})
        if result.matched_count == 0: return jsonify({"error": "No linked types found or access denied"}), 404
        return jsonify({"message": f"{result.modified_count} linked types updated successfully"}), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 500

