@app.route('/api/next-employee-id', methods=['GET'])
def get_next_employee_id():
    try:
        import re
        # NEW: Resolve the most relevant company for ID generation
        raw_company_name = request.args.get('company_name')
        if not raw_company_name or raw_company_name.lower() == 'all':
            # Fallback to headers or user context
            raw_company_name = request.headers.get('X-Company-Name') or request.args.get('company')
            
        company_name = 'POS 8' # Default
        if raw_company_name:
            if ',' in str(raw_company_name):
                company_list = [c.strip() for c in str(raw_company_name).split(',')]
            elif isinstance(raw_company_name, list):
                company_list = raw_company_name
            else:
                company_list = [str(raw_company_name)]
                
            specific_comps = [c for c in company_list if str(c).lower() != 'all' and str(c) != 'POS 8']
            company_name = specific_comps[0] if specific_comps else company_list[0]
        else:
            # Check users context if company not in args
            auth_header = request.headers.get('Authorization')
            user_id = verify_token(auth_header)
            # Robust lookup handling both string and ObjectId
            user_doc = users_collection.find_one({'_id': user_id}) if user_id else None
            if not user_doc and user_id and isinstance(user_id, str) and ObjectId.is_valid(user_id):
                user_doc = users_collection.find_one({'_id': ObjectId(user_id)})
            if user_doc:
                company_name = user_doc.get('company_name') or user_doc.get('company') or 'POS 8'
                if isinstance(company_name, list) and company_name:
                    specific = [c for c in company_name if str(c).lower() != 'all']
                    company_name = specific[0] if specific else company_name[0]
        
        # Resolve company/branch context for prefix
        import re
        c_name = company_name
        raw_branch_name = request.args.get('branch_name', '').strip()
        # Normalize empty / wildcard branch to None
        if not raw_branch_name or raw_branch_name.lower() in ['all', 'all branches', 'any', 'none']:
            raw_branch_name = (request.headers.get('X-Branch-Name', '') or '').strip() or None
        if raw_branch_name and raw_branch_name.lower() in ['all', 'all branches', 'any', 'none']:
            raw_branch_name = None
            
        prefix = get_employee_id_prefix(c_name, raw_branch_name, worker_collection)
        
        # PERFORMANCE FIX: Use regex filtered query instead of fetching ALL workers
        # worker_collection.find now supports projection
        active_workers = list(worker_collection.find(
            {"employeeId": {"$regex": f"^{re.escape(prefix)}"}}, 
            {"employeeId": 1}
        ))
        
        max_num = 0
        pattern = re.compile(rf"^{re.escape(prefix)}(\d+)$")
        for w in active_workers:
            eid = str(w.get('employeeId', ''))
            match = pattern.match(eid)
            if match:
                try:
                    val = int(match.group(1))
                    if val > max_num: max_num = val
                except: pass
        
        next_val = max_num + 1
        employee_id = f"{prefix}{next_val:04d}"
        return jsonify({"nextId": employee_id, "prefix": prefix}), 200
    except Exception as e:
        logger.error(f"Error fetching next employee ID: {str(e)}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/add-employee', methods=['GET', 'POST'])
def add_employee():
    mode = config.get("mode", "server")
    if mode == 'client':
        if request.method == 'GET':
            try:
                server_url = f"http://{config['server_ip']}:6034/api/add-employee"
                response = requests.get(server_url, timeout=5)
                if response.status_code == 200:
                    return jsonify(response.json()), 200
                else:
                    return jsonify({"error": "Proxy fetch failed"}), response.status_code
            except Exception as e:
                logger.error(f"Proxy GET error: {e}")
                return jsonify({"error": f"Proxy error: {str(e)}"}), 500
        elif request.method == 'POST':
            try:
                server_url = f"http://{config['server_ip']}:6034/api/add-employee"
                response = requests.post(server_url, json=request.get_json(), timeout=5)
                if response.status_code in [200, 201]:
                    return jsonify(response.json()), response.status_code
                else:
                    try:
                        err_data = response.json()
                        return jsonify(err_data), response.status_code
                    except:
                        return jsonify({"error": "Proxy create failed"}), response.status_code
            except Exception as e:
                logger.error(f"Proxy POST error: {e}")
                return jsonify({"error": f"Proxy error: {str(e)}"}), 500
    if request.method == 'GET':
        try:
            # --- Centralized Permission Filtering ---
            # Allow frontend to specify page context for dropdown filtering
            page_id = request.args.get('pageId') or 'employee_list'
            can_access, filter_query = get_data_scope_filter(page_id, owner_field='_id')
            
            if not can_access:
                 return jsonify([]), 200

            # Fetch relevant employees
            # Note: We filter out drafts here as well
            employees = list(worker_collection.find(filter_query))
            employees = [e for e in employees if e.get('isDraft') is not True]
            
            logger.info(f"add-employee scope: resolved_page='{page_id}', count={len(employees)}")

            converted_employees = []
            for emp in employees:
                if '_id' in emp:
                    emp['_id'] = str(emp['_id'])
                # Backward compatibility: Map ifscCode to branchCode if branchCode missing
                if 'branchCode' not in emp and 'ifscCode' in emp:
                    emp['branchCode'] = emp['ifscCode']
                converted_employees.append(emp)
            return jsonify(converted_employees), 200
        except Exception as e:
            logger.error(f"Error fetching employees: {str(e)}")
            logger.error(traceback.format_exc())
            return jsonify({"error": str(e)}), 500
    elif request.method == 'POST':
        try:
            data = request.get_json()
            if not isinstance(data, dict):
                return jsonify({"error": "JSON data must be an object"}), 400
            # Detailed validation supporting both camelCase and snake_case
            required_pairs = [
                ('name', 'name'),
                ('phoneNumber', 'phone_number'),
                ('email', 'email'),
                ('username', 'username'),
                ('password', 'password'),
                ('employeeDesignation', 'employee_designation'),
                ('employeeType', 'employee_type'),
                ('department', 'department')
            ]
            missing_fields = []
            for camel, snake in required_pairs:
                if (camel not in data or not str(data[camel]).strip()) and \
                   (snake not in data or not str(data[snake]).strip()):
                    missing_fields.append(camel)
     
            if missing_fields:
                return jsonify({"error": f"Missing required fields: {', '.join(missing_fields)}"}), 400

            # Check if email exists
            # Reliable Email Check & ID Generation (Fixing SQLite $ne issues)
            all_workers_raw = list(worker_collection.find())
            active_workers = [w for w in all_workers_raw if w.get('isDraft') is not True]

            # Reliable Company Determination
            user_id, _ = get_request_user_info()
            # Robust lookup handling both string and ObjectId
            user_doc = users_collection.find_one({'_id': user_id}) if user_id else None
            if not user_doc and user_id and isinstance(user_id, str) and ObjectId.is_valid(user_id):
                user_doc = users_collection.find_one({'_id': ObjectId(user_id)})
            
            # NEW: Resolve the primary company for IDs (prioritize specific companies from multi-select)
            raw_companies_in = data.get('company_name') or data.get('companies') or data.get('company')
            if isinstance(raw_companies_in, list) and raw_companies_in:
                specific_comps_in = [c for c in raw_companies_in if str(c).lower() != 'all' and str(c) != 'POS 8']
                active_company = specific_comps_in[0] if specific_comps_in else raw_companies_in[0]
            else:
                active_company = raw_companies_in

            # Final fallbacks
            if not active_company or str(active_company) == 'POS 8' or str(active_company).lower() == 'all':
                header_company = request.headers.get('X-Company-Name')
                if header_company and header_company.lower() != 'all' and header_company != 'POS 8':
                    active_company = header_company
                else:
                    active_company = (user_doc.get('company') if user_doc else 'POS 8')
            
            # FINAL CHECK: Ensure active_company is never 'All' if we can help it for ID prefixes
            if str(active_company).lower() == 'all' and user_doc:
                allowed_comps_in = user_doc.get('companies', [])
                valid_allowed_in = [c for c in allowed_comps_in if str(c).lower() != 'all']
                active_company = valid_allowed_in[0] if valid_allowed_in else (allowed_comps_in[0] if allowed_comps_in else 'POS 8')
            
            active_company = str(active_company) # Force string type

            # 1. Global Email Uniqueness Check (Replaces Tenant-Aware check)
            if not is_email_unique(data['email']):
                return jsonify({"error": "This email address is already in use by another user in the system (Company Admin, Branch Admin, or Employee). Please use a unique email."}), 400

            # 1.5 Global Username Uniqueness Check
            username = data.get('username', '')
            if username:
                username = str(username).strip()
            if username:
                import re
                if users_collection.find_one({"username": re.compile(f"^{re.escape(username)}$", re.IGNORECASE)}) or worker_collection.find_one({"username": re.compile(f"^{re.escape(username)}$", re.IGNORECASE)}):
                    return jsonify({"error": f"The username '{username}' is already registered in the database. Please choose a different unique username."}), 400

            # Extract multi-select data from request
            selected_branches = data.get('branch_names', [])
            selected_companies = data.get('company_name', [])
            if not isinstance(selected_companies, list):
                selected_companies = [selected_companies] if selected_companies else []
            
            # Ensure company lists are populated (important for Group Admin 'tick' requirement)
            if not selected_companies:
                selected_companies = [active_company]
            
            # Resolve Branch from context if hidden on frontend
            if not selected_branches:
                active_branch = request.headers.get('X-Branch-Name')
                if not active_branch and user_doc:
                    active_branch = user_doc.get('branch_name') or user_doc.get('branch')
                
                if active_branch and active_branch != 'All Branches':
                    selected_branches = [active_branch]
            
            # 2. Generate ID (Branch/Company Prefix) using Optimized Regex Query
            active_branch_in = selected_branches[0] if selected_branches else None
            prefix = get_employee_id_prefix(active_company, active_branch_in, worker_collection)
            
            # Optimized: Fetch only needed IDs using regex instead of full scan
            matching_workers = worker_collection.find(
                {"employeeId": {"$regex": f"^{re.escape(prefix)}"}}, 
                {"employeeId": 1}
            )
            
            max_num = 0
            pattern = re.compile(rf"^{re.escape(prefix)}(\d+)$")
            for w in matching_workers:
                eid = str(w.get('employeeId', ''))
                match = pattern.match(eid)
                if match:
                    try:
                        val = int(match.group(1))
                        if val > max_num: max_num = val
                    except: pass
            
            employee_id = f"{prefix}{(max_num + 1):04d}"
            logger.info(f"Generated company-based employeeId: {employee_id} for company: {active_company}")
            # Validate dates
            date_of_birth = data.get('dateOfBirth', '')
            if date_of_birth:
                try:
                    datetime.fromisoformat(date_of_birth.split('T')[0])
                except ValueError:
                    logger.warning(f"Invalid DOB: {date_of_birth}")
            id_expiry = data.get('idExpiry', '')
            # Safe float conversion
            def safe_float(val, default=0.0):
                try:
                    return float(val) if val else default
                except (ValueError, TypeError):
                    return default
            basic = safe_float(data.get('basicSalary'))
            hra = safe_float(data.get('hra'))
            ta = safe_float(data.get('ta'))
            oa = safe_float(data.get('oa'))
            total_salary = data.get('totalSalary')
            if not total_salary:
                total_salary = basic + hra + ta + oa
            else:
                 total_salary = safe_float(total_salary)
            # Password Hashing
            try:
                hashed_password = bcrypt.hashpw(str(data['password']).encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
            except Exception as e:
                logger.error(f"Password hashing failed: {e}")
                return jsonify({"error": "Invalid password format"}), 400
            # Resolve the primary company for the record (prioritize form data over admin header)
            record_primary_company = active_company
            if selected_companies and len(selected_companies) > 0:
                # Use the first specific company that isn't 'All' if possible
                specific = [c for c in selected_companies if str(c).lower() != 'all' and str(c) != 'POS 8']
                record_primary_company = specific[0] if specific else selected_companies[0]

            # Resolve IDs for multi-tenancy compliance
            primary_branch = selected_branches[0] if selected_branches else None
            resolved_ids = _resolve_tenant_company_branch(record_primary_company, primary_branch)
            if not resolved_ids.get("company_id"):
                logger.error(f"DEBUG TENANCY: record_primary_company='{record_primary_company}', primary_branch='{primary_branch}', data={data}")
                return jsonify({"error": "Tenancy validation failed. Missing required fields: company_id"}), 400
            
            # Optionally resolve all branch IDs if there are multiple branches
            branch_ids = []
            if selected_branches:
                for br in selected_branches:
                    br_ids = _resolve_tenant_company_branch(record_primary_company, br)
                    if br_ids.get("branch_id"):
                        branch_ids.append(br_ids["branch_id"])

            new_employee = {
                "_id": str(uuid.uuid4()),
                "tenant_id": resolved_ids.get("tenant_id"),
                "company_id": resolved_ids.get("company_id"),
                "branch_id": resolved_ids.get("branch_id"),
                "branch_ids": branch_ids,
                "branch_names": selected_branches, # FIX: store branch_names for filtering
                "employeeId": employee_id,
                "name": data.get('name'),
                "phoneNumber": data.get('phoneNumber') or data.get('phone_number'),
                "email": data.get('email'),
                "gender": data.get('gender', ''),
                "dateOfBirth": date_of_birth or data.get('date_of_birth'),
                "dateOfJoining": data.get('dateOfJoining') or data.get('date_of_joining') or datetime.now(ZoneInfo("UTC")).date().isoformat(),
                "company": record_primary_company, # Correctly isolated to selected company
                "companies": selected_companies, 
                "company_name": record_primary_company,
                "company_names": selected_companies, # Ensure multi-tenant list consistency
                "tenant_id": resolved_ids.get('tenant_id'),
                "company_id": resolved_ids.get('company_id'),
                "branch_id": resolved_ids.get('branch_id'),
                "status": data.get('status', 'Active'),
                "salutation": data.get('salutation', ''),
                "maritalStatus": data.get('maritalStatus') or data.get('marital_status', ''),
                "address": data.get('address', ''),
                "idNumber": data.get('idNumber') or data.get('id_number', ''),
                "idExpiry": id_expiry or data.get('id_expiry'),
                "employeeDesignation": data.get('employeeDesignation') or data.get('employee_designation'),
                "employeeType": data.get('employeeType') or data.get('employee_type'),
                "bankName": data.get('bankName') or data.get('bank_name', ''),
                "accountHolderName": data.get('accountHolderName') or data.get('account_holder_name', ''),
                "accountNumber": data.get('accountNumber') or data.get('account_number', ''),
                "branchCode": data.get('branchCode') or data.get('branch_code', ''),
                "basicSalary": basic or safe_float(data.get('basic_salary')),
                "hra": hra,
                "ta": ta,
                "oa": oa,
                "totalSalary": total_salary or safe_float(data.get('total_salary')),
                "nationality": data.get('nationality', ''),
                "education": data.get('education', ''),
                "previousExperience": data.get('previousExperience') or data.get('previous_experience', ''),
                "skills": data.get('skills', ''),
                "healthInfo": data.get('healthInfo') or data.get('health_info', ''),
                "familyDetails": data.get('familyDetails') or data.get('family_details', ''),
                "username": data.get('username'),
                "password": hashed_password,
                "profileImage": data.get('profileImage') or data.get('profile_image', ''),
                "branch_name": primary_branch,
                "branch_names": selected_branches,
                "created_at": datetime.now(ZoneInfo("UTC")).isoformat(),
                "isDraft": False
            }
            
            # --- Dynamic Metadata Support ---
            # Automatically capture any custom fields (like 'manoj1') from the frontend
            standard_keys = list(new_employee.keys()) + ['password', 'confirmPassword', 'phone_number', 'date_of_birth', 'date_of_joining', 'marital_status', 'id_number', 'id_expiry', 'employee_designation', 'employee_type', 'bank_name', 'account_holder_name', 'account_number', 'branch_code', 'basic_salary', 'total_salary', 'previous_experience', 'health_info', 'family_details', 'profile_image']
            for k, v in data.items():
                if k not in standard_keys and k not in new_employee:
                    new_employee[k] = v
                    
            worker_collection.insert_one(new_employee)
            new_user = {
                "email": data['email'],
                "password": hashed_password,
                "role": data.get('employeeDesignation', ''),
                "username": data['username'],
                "firstName": data['name'],
                "phone_number": data['phoneNumber'],
                "company": record_primary_company,
                "companies": selected_companies,
                "company_name": record_primary_company,
                "company_names": selected_companies,
                "tenant_id": resolved_ids.get('tenant_id'),
                "company_id": resolved_ids.get('company_id'),
                "branch_id": resolved_ids.get('branch_id'),
                "branch_name": (selected_branches[0] if selected_branches else ""), # Backward compat
                "branch_names": selected_branches, # Multi-branch Support
                "pos_profile": "POS-001",
                "status": new_employee['status'],
                "employeeId": employee_id,
                "worker_id": new_employee['_id'],
                "created_at": datetime.now(ZoneInfo("UTC")).isoformat()
            }
            users_collection.insert_one(new_user)
            logger.info(f"Employee created: {data['name']} ({data['email']}) with ID {employee_id}")
            return jsonify({"message": "Employee created successfully", "id": new_employee['_id'], "employeeId": employee_id}), 201
        except Exception as e:
            logger.error(f"Error creating employee: {str(e)}")
            logger.error(traceback.format_exc())
            return jsonify({"error": f"Internal Server Error: {str(e)}"}), 500
@app.route('/api/add-employee/<emp_id>', methods=['GET', 'PUT', 'DELETE'])
def manage_employee(emp_id):
    mode = config.get("mode", "server")
    if mode == 'client':
        server_ip = config.get('server_ip', 'localhost') # Fix explicit IP
        server_url = f"http://{server_ip}:6034/api/add-employee/{emp_id}"
        if request.method == 'GET':
            try:
                response = requests.get(server_url, timeout=5)
                return jsonify(response.json()), response.status_code
            except Exception as e:
                return jsonify({"error": f"Proxy GET error: {str(e)}"}), 500
        elif request.method == 'PUT':
            try:
                data = request.get_json()
                response = requests.put(server_url, json=data, timeout=5)
                return jsonify(response.json()), response.status_code
            except Exception as e:
                return jsonify({"error": f"Proxy PUT error: {str(e)}"}), 500
        elif request.method == 'DELETE':
            try:
                response = requests.delete(server_url, timeout=5)
                return jsonify(response.json()), response.status_code
            except Exception as e:
                return jsonify({"error": f"Proxy DELETE error: {str(e)}"}), 500
    if request.method == 'GET':
        try:
            # Fetch single employee by ID, filter out drafts
            emp = worker_collection.find_one({'_id': emp_id})
            if not emp:
                return jsonify({"error": "Employee not found"}), 404
            if emp.get('isDraft') is True:
                return jsonify({"error": "Employee not found"}), 404
            if '_id' in emp:
                emp['_id'] = str(emp['_id'])
            # NEW: Fetch assigned schedule details for Attendance & Leaves
            # Fetch ALL assignments collection and filter in memory because ID types are inconsistent
            # This mimics frontend logic: assignments.find(a => String(a.employee_id) === String(empId))
            raw_all_assigns = list(employee_schedule_assign_collection.find({}))
            all_assigns = [a for a in raw_all_assigns if str(a.get('employee_id', '')).strip() == str(emp_id).strip()]
            
            # Filter for Query-Active in Python to handle type mismatches (true vs "true")
            # Logic: is_active is True AND (no end_date OR end_date >= today)
            # Simple check for now: is_active truthy
            active_assigns = [a for a in all_assigns if a.get('is_active') in [True, 'true', 'True', 1]]
            
            # Sort by assigned_date desc (newest first)
            active_assigns.sort(key=lambda x: x.get('assigned_date', ''), reverse=True)
            
            assignment = active_assigns[0] if active_assigns else None

            assigned_schedule = None
            if assignment:
                schedule_id = assignment.get('schedule_id')
                if schedule_id:
                    # Try finding rule with raw ID or ObjectId
                    # Try finding rule with raw ID or ObjectId - FIRST in Schedule Master
                    rule = schedule_master_collection.find_one({'_id': schedule_id})
                    if not rule and isinstance(schedule_id, str) and ObjectId.is_valid(schedule_id):
                        rule = schedule_master_collection.find_one({'_id': ObjectId(schedule_id)})
                    
                    # FALLBACK: If not in Schedule Master, check Shift Master (Legacy/Direct Shift Assignment)
                    if not rule:
                         shift_fallback = shift_master_collection.find_one({'_id': schedule_id})
                         if not shift_fallback and isinstance(schedule_id, str) and ObjectId.is_valid(schedule_id):
                             shift_fallback = shift_master_collection.find_one({'_id': ObjectId(schedule_id)})
                         
                         if shift_fallback:
                             # Create a pseudo-rule wrapping the shift
                             rule = {
                                 '_id': shift_fallback['_id'],
                                 'schedule_name': shift_fallback.get('schedule_name', 'Direct Shift'),
                                 'shift_id': shift_fallback.get('_id'), # Point to itself as linekd shift
                                 'start_date': shift_fallback.get('start_date', 'Continuous'),
                                 'end_date': shift_fallback.get('end_date', 'Continuous'),
                                 'working_days': shift_fallback.get('working_days', []),
                                 'weekly_off': shift_fallback.get('weekly_off', []), # Ensure weekly_off is passed
                                 'is_legacy_shift': True
                             }

                    if rule:
                        shift_id = rule.get('shift_id')
                        shift = None
                        if shift_id:
                            shift = shift_master_collection.find_one({'_id': shift_id})
                            if not shift and isinstance(shift_id, str) and ObjectId.is_valid(shift_id):
                                shift = shift_master_collection.find_one({'_id': ObjectId(shift_id)})
                        # Convert _id to str if present
                        if '_id' in rule:
                            rule['_id'] = str(rule['_id'])
                        if shift and '_id' in shift:
                            shift['_id'] = str(shift['_id'])
                        if '_id' in assignment:
                            assignment['_id'] = str(assignment['_id'])
                        
                        # UPDATED: Robustly determine source object for timing/name
                        # If shift link exists but shift not found, fallback to rule.
                        # If shift link exists and shift found, use shift.
                        # If no shift link, use rule.
                        if shift:
                            source_obj = shift
                        else:
                            source_obj = rule
                        
                        if source_obj and 'time_slots' in source_obj and source_obj['time_slots']:
                            slot_str = ', '.join([
                                f"{s.get('start_time', 'N/A')}-{s.get('end_time', 'N/A')}{ ' (O)' if s.get('is_overnight', False) else '' }"
                                for s in source_obj['time_slots']
                            ])
                            default_shift = f"{source_obj.get('schedule_name', 'N/A')} ({slot_str})"
                        else:
                            # Fallback to single slot or N/A
                            default_shift = f"{source_obj.get('schedule_name', 'N/A')} {source_obj.get('start_time', 'N/A')} to {source_obj.get('end_time', 'N/A')}" if source_obj else 'N/A'
                        # Merge special days: Rule specials + Assignment overrides (prefer assignment if exists)
                        all_special_days = rule.get('special_days', [])
                        assignment_specials = assignment.get('special_day_assignments', [])
                        merged_specials = []
                        special_map = {f"{sd.get('date', '')}-{sd.get('description', '')}": sd for sd in assignment_specials} # Key for quick lookup
                        for sd in all_special_days:
                            key = f"{sd.get('date', '')}-{sd.get('description', '')}"
                            if key in special_map:
                                merged_specials.append({**sd, **special_map[key], 'is_observed': True}) # Override with assignment
                            else:
                                merged_specials.append({**sd, 'is_observed': sd.get('type') == 'Holiday'}) # Default observed for holidays
                        # Add any assignment-only specials
                        for sd in assignment_specials:
                            key = f"{sd.get('date', '')}-{sd.get('description', '')}"
                            if not any(f"{existing.get('date', '')}-{existing.get('description', '')}" == key for existing in all_special_days):
                                merged_specials.append(sd)
                     
                        assigned_schedule = {
                            'schedule_name': rule.get('schedule_name', 'N/A'), # Used as Holiday List code e.g., HL-IND-KL-2025
                            'start_date': rule.get('start_date'), # NEW: Full period for weekly off generation
                            'end_date': rule.get('end_date'), # NEW
                            'default_shift': default_shift,
                            'working_days': rule.get('working_days', []),
                            'weekly_off': rule.get('weekly_off', []), # NEW: For weekly off list
                            'special_days': all_special_days, # Original rule specials (for reference)
                            'special_day_assignments': merged_specials, # Merged for employee-specific
                            'assignment_notes': assignment.get('notes', ''),
                        }
            emp['assigned_schedule'] = assigned_schedule
            # NEW: Fetch linked delivery profile if exists (from /api/employees where generalEmployeeId == emp._id)
            delivery_profile = employees_collection.find_one({'generalEmployeeId': emp_id})
            if delivery_profile:
                if '_id' in delivery_profile:
                    delivery_profile['_id'] = str(delivery_profile['_id'])
                emp['deliveryProfile'] = delivery_profile # Add as a nested object for frontend to display in details modal
            
            # Backward compatibility for single fetch
            if 'branchCode' not in emp and 'ifscCode' in emp:
                emp['branchCode'] = emp['ifscCode']

            return jsonify(emp), 200
        except Exception as e:
            logger.error(f"Error fetching employee: {str(e)}")
            logger.error(traceback.format_exc())
            return jsonify({"error": str(e)}), 500
    elif request.method == 'PUT':
        try:
            data = request.get_json()
            if not isinstance(data, dict):
                return jsonify({"error": "JSON data must be an object"}), 400
         
            existing_emp = worker_collection.find_one({'_id': emp_id})
            if not existing_emp:
                return jsonify({"error": "Employee not found"}), 404
            # Check email uniqueness globally (including users_collection and case-insensitivity)
            if 'email' in data and data['email']:
                if not is_email_unique(data['email'], exclude_id=emp_id):
                     return jsonify({"error": "This email address is already in use by another user in the system (Company Admin, Branch Admin, or Employee). Please use a unique email."}), 400

         
            # Safe float conversion helper
            def safe_float(val, default=0.0):
                try:
                    return float(val) if val else default
                except (ValueError, TypeError):
                    return default
            # --- Ultimate Robust Branch-Specific ID Update Logic ---
            # 1. Resolve OLD primary branch
            old_primary = None
            e_branch_names = existing_emp.get('branch_names', [])
            e_branch_name = existing_emp.get('branch_name')
            e_branch_code = existing_emp.get('branchCode')
            
            if isinstance(e_branch_names, list) and e_branch_names:
                old_primary = str(e_branch_names[0]).strip()
            elif e_branch_name:
                b_parts = [p.strip() for p in str(e_branch_name).split(',') if p.strip()]
                if b_parts: old_primary = b_parts[0]
            elif e_branch_code:
                old_primary = str(e_branch_code).strip()

            # 2. Resolve NEW primary branch from request
            new_primary = None
            d_branch_names = data.get('branch_names', [])
            d_branch_name = data.get('branch_name')
            d_branch_code = data.get('branchCode')
            
            if isinstance(d_branch_names, list) and d_branch_names:
                new_primary = str(d_branch_names[0]).strip()
            elif d_branch_name:
                b_parts = [p.strip() for p in str(d_branch_name).split(',') if p.strip()]
                if b_parts: new_primary = b_parts[0]
            elif d_branch_code:
                new_primary = str(d_branch_code).strip()
            
            # Fallback to current if not provided in update
            if not new_primary:
                new_primary = old_primary

            current_id = str(existing_emp.get('employeeId', '')).strip()
            
            # 3. Decision for ID Regeneration
            # Normalize for comparison
            def normalize_b(b): return str(b).replace(" ","").lower() if b else ""
            
            is_branch_changed = new_primary and old_primary and normalize_b(new_primary) != normalize_b(old_primary)
            is_new_assignment = new_primary and not old_primary
            is_legacy_id = current_id.upper().startswith('EMP') or current_id == ""
            
            final_employee_id = current_id
            
            # Resolve primary company for ID context
            d_companies = data.get('company_name', [])
            if not isinstance(d_companies, list):
                d_companies = [d_companies] if d_companies else []
            
            primary_company_id_context = data.get('company')
            if not primary_company_id_context or str(primary_company_id_context).lower() == 'all':
                primary_company_id_context = next((c for c in d_companies if str(c).lower() != 'all'), 'All')

            # Determine if ID needs regeneration
            prefix_info = get_company_id_prefix(primary_company_id_context, worker_collection) or ''
            is_prefix_mismatch = prefix_info and not current_id.upper().startswith(prefix_info.upper())
            
            final_employee_id = current_id # Initialize default

            if primary_company_id_context and (is_branch_changed or is_new_assignment or is_legacy_id or is_prefix_mismatch):
                prefix = prefix_info or 'CO'
                
                import re
                pattern = re.compile(rf"^{re.escape(prefix)}(\d+)$")
                
                max_num = 0
                for e in worker_collection.find({"employeeId": {"$regex": f"^{re.escape(prefix)}"}}, {"employeeId": 1}):
                    eid = str(e.get('employeeId', ''))
                    match = pattern.match(eid)
                    if match:
                        try:
                            num = int(match.group(1))
                            if num > max_num: max_num = num
                        except: pass
                
                new_gen_id = f"{prefix}{(max_num + 1):04d}"
                if new_gen_id and str(new_gen_id).strip().upper() != current_id.upper():
                    final_employee_id = new_gen_id
                    logger.info(f"[Robust ID Revision] {current_id} -> {final_employee_id} due to mismatch or change")

            # Final check to ensure branch_names list is well-formed for storage
            final_branches_list = d_branch_names if (isinstance(d_branch_names, list) and d_branch_names) else ([new_primary] if new_primary else [])
            if not final_branches_list and existing_emp.get('branch_names'):
                final_branches_list = existing_emp.get('branch_names')

            # RESOLVED PRIMARY COMPANY (must be prioritized from list)
            d_companies = data.get('company_name', [])
            if not isinstance(d_companies, list):
                if isinstance(d_companies, str) and ',' in d_companies:
                    d_companies = d_companies.split(',')
                else:
                    d_companies = [d_companies] if d_companies else []
            
            d_companies = [str(c).strip() for c in d_companies if c]
            
            # Use the already resolved primary_company_id_context if available (it was hardened above)
            final_primary_company = primary_company_id_context or (next((c for c in d_companies if str(c).lower() != 'all'), d_companies[0]) if d_companies else existing_emp.get('company'))
            
            # Prepare update fields with dual-key support
            update_fields = {
                "employeeId": final_employee_id,
                "name": data.get('name', existing_emp.get('name')),
                "phoneNumber": data.get('phoneNumber') or data.get('phone_number') or existing_emp.get('phoneNumber'),
                "email": data.get('email', existing_emp.get('email')),
                "gender": data.get('gender', existing_emp.get('gender')),
                "dateOfBirth": data.get('dateOfBirth') or data.get('date_of_birth') or existing_emp.get('dateOfBirth'),
                "dateOfJoining": data.get('dateOfJoining') or data.get('date_of_joining') or existing_emp.get('dateOfJoining'),
                "company": str(final_primary_company),
                "companies": d_companies if d_companies else existing_emp.get('companies', [str(final_primary_company)]),
                "company_name": d_companies if d_companies else existing_emp.get('company_name', [str(final_primary_company)]),
                "status": data.get('status', existing_emp.get('status')),
                "salutation": data.get('salutation', existing_emp.get('salutation')),
                "maritalStatus": data.get('maritalStatus') or data.get('marital_status') or existing_emp.get('maritalStatus'),
                "address": data.get('address', existing_emp.get('address')),
                "idNumber": data.get('idNumber') or data.get('id_number') or existing_emp.get('idNumber'),
                "idExpiry": data.get('idExpiry') or data.get('id_expiry') or existing_emp.get('idExpiry'),
                "employeeDesignation": data.get('employeeDesignation') or data.get('employee_designation') or existing_emp.get('employeeDesignation'),
                "employeeType": data.get('employeeType') or data.get('employee_type') or existing_emp.get('employeeType'),
                "department": data.get('department', existing_emp.get('department')),
                # Bank Details
                "bankName": data.get('bankName') or data.get('bank_name') or existing_emp.get('bankName', ''),
                "accountHolderName": data.get('accountHolderName') or data.get('account_holder_name') or existing_emp.get('accountHolderName', ''),
                "accountNumber": data.get('accountNumber') or data.get('account_number') or existing_emp.get('accountNumber', ''),
                "branchCode": new_primary, # Consistent with new primary
                "branch_name": new_primary, # Unified field for isolation
                "branch_names": final_branches_list, # Array field for multi-branch
                # Salary
                "basicSalary": safe_float(data.get('basicSalary') or data.get('basic_salary') or existing_emp.get('basicSalary', 0)),
                "hra": safe_float(data.get('hra', existing_emp.get('hra', 0))),
                "ta": safe_float(data.get('ta', existing_emp.get('ta', 0))),
                "oa": safe_float(data.get('oa', existing_emp.get('oa', 0))),
                # Extra
                "nationality": data.get('nationality', existing_emp.get('nationality')),
                "education": data.get('education', existing_emp.get('education')),
                "previousExperience": data.get('previousExperience') or data.get('previous_experience') or existing_emp.get('previousExperience'),
                "skills": data.get('skills', existing_emp.get('skills')),
                "healthInfo": data.get('healthInfo') or data.get('health_info') or existing_emp.get('healthInfo'),
                "familyDetails": data.get('familyDetails') or data.get('family_details') or existing_emp.get('familyDetails'),
                "username": data.get('username', existing_emp.get('username')),
                "updated_at": datetime.now(ZoneInfo("UTC")).isoformat(),
                "profileImage": data.get('profileImage') or data.get('profile_image') or existing_emp.get('profileImage', '')
            }
            # Recalculate total salary if components provided, else use provided, else sum
            basic = update_fields['basicSalary']
            hra = update_fields['hra']
            ta = update_fields['ta']
            oa = update_fields['oa']
            if data.get('totalSalary'):
                update_fields['totalSalary'] = safe_float(data.get('totalSalary'))
            else:
                update_fields['totalSalary'] = basic + hra + ta + oa
            # Handle password update
            if 'password' in data and data['password']:
                try:
                    hashed_password = bcrypt.hashpw(str(data['password']).encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
                    update_fields['password'] = hashed_password
                except Exception as e:
                    return jsonify({"error": "Invalid password format"}), 400
         
            # --- Dynamic Metadata Support ---
            # Automatically capture and update any custom fields (like 'manoj1')
            standard_keys = list(update_fields.keys()) + ['password', 'confirmPassword', 'phone_number', 'date_of_birth', 'date_of_joining', 'marital_status', 'id_number', 'id_expiry', 'employee_designation', 'employee_type', 'bank_name', 'account_holder_name', 'account_number', 'branch_code', 'basic_salary', 'total_salary', 'previous_experience', 'health_info', 'family_details', 'profile_image']
            for k, v in data.items():
                if k not in standard_keys and k not in update_fields:
                    update_fields[k] = v

            # Perform update
            worker_collection.update_one({'_id': emp_id}, {'$set': update_fields})
            
            # NEW: Synchorize Human-Readable ID to linked Delivery Profile if it exists
            if final_employee_id != existing_emp.get('employeeId'):
                employees_collection.update_many({'generalEmployeeId': emp_id}, {'$set': {'employeeId': final_employee_id}})
                logger.info(f"Synchronized new employeeId {final_employee_id} to linked delivery profile for {emp_id}")
         
            # Update user collection if relevant fields changed
            user_update = {}
            if 'email' in update_fields: user_update['email'] = update_fields['email']
            if 'username' in update_fields: user_update['username'] = update_fields['username']
            if 'name' in update_fields: user_update['firstName'] = update_fields['name']
            if 'phoneNumber' in update_fields: user_update['phone_number'] = update_fields['phoneNumber']
            if 'employeeDesignation' in update_fields: user_update['role'] = update_fields['employeeDesignation']
            if 'status' in update_fields: user_update['status'] = update_fields['status']
            if 'password' in update_fields: user_update['password'] = update_fields['password']
            if 'branch_names' in update_fields: 
                user_update['branch_names'] = update_fields['branch_names']
                user_update['branch_name'] = (update_fields['branch_names'][0] if update_fields['branch_names'] else "")
            if 'companies' in update_fields:
                user_update['companies'] = update_fields['companies']
                user_update['company'] = update_fields['company']
            
            # ALWAYS sync employee/worker link
            user_update['employeeId'] = update_fields.get('employeeId') or existing_emp.get('employeeId')
            user_update['worker_id'] = str(emp_id)
         
            # Try to find associated user by email AND company (Strict Isolation)
            # Find using the original company from existing_emp to ensure we hit the right record
            user_lookup_filter = {
                'email': existing_emp.get('email'),
                'company': existing_emp.get('company')
            }
            users_collection.update_one(user_lookup_filter, {'$set': user_update})
            return jsonify({"message": "Employee updated successfully", "id": emp_id}), 200
        except Exception as e:
            logger.error(f"Error updating employee: {str(e)}")
            logger.error(traceback.format_exc())
            return jsonify({"error": f"Internal Server Error: {str(e)}"}), 500
    elif request.method == 'DELETE':
        try:
            existing_emp = worker_collection.find_one({'_id': emp_id})
            if not existing_emp:
                return jsonify({"error": "Employee not found"}), 404
         
            # Delete employee
            worker_collection.delete_one({'_id': emp_id})
         
            # Delete associated user
            # Delete associated user record (Strict Isolation)
            users_collection.delete_one({
                'email': existing_emp.get('email'),
                'company': existing_emp.get('company')
            })
         
            # Optional: Delete/Archive assignments?
            # Keeping it simple: Delete assignments
            employee_schedule_assign_collection.delete_many({'employee_id': emp_id})
         
            return jsonify({"message": "Employee deleted successfully"}), 200
        except Exception as e:
            logger.error(f"Error deleting employee: {str(e)}")
            return jsonify({"error": f"Internal Server Error: {str(e)}"}),500# 1. SHIFT MASTER


