@app.route('/api/assignment', methods=['GET'])
def get_assignment():
    try:
        emp_id = request.args.get('employee_id')
        if not emp_id:
            return jsonify({"error": "Employee ID required"}), 400
        
        # Robust Lookup
        raw_all_assigns = list(employee_schedule_assign_collection.find({}))
        active_assigns = [a for a in raw_all_assigns if str(a.get('employee_id', '')).strip() == str(emp_id).strip() and a.get('is_active')]
        
        # Sort by assigned_date desc
        active_assigns.sort(key=lambda x: x.get('assigned_date', ''), reverse=True)
        
        if not active_assigns:
            return jsonify({"error": "No active assignment found"}), 404
            
        assignment = active_assigns[0]
        schedule_id = assignment.get('schedule_id')
        
        # Robust Schedule/Shift Lookup (Schedule First, then Shift Master Fallback)
        schedule = None
        shift = None
        
        if schedule_id:
             # Try finding in Schedule Master
            schedule = schedule_master_collection.find_one({'_id': schedule_id})
            if not schedule and isinstance(schedule_id, str) and ObjectId.is_valid(schedule_id):
                schedule = schedule_master_collection.find_one({'_id': ObjectId(schedule_id)})
            
            # Fallback to Shift Master (Legacy)
            if not schedule:
                 shift_chk = shift_master_collection.find_one({'_id': schedule_id})
                 if not shift_chk and isinstance(schedule_id, str) and ObjectId.is_valid(schedule_id):
                     shift_chk = shift_master_collection.find_one({'_id': ObjectId(schedule_id)})
                 
                 if shift_chk:
                     # Create pseudo-schedule
                     schedule = {
                         '_id': shift_chk['_id'],
                         'schedule_name': shift_chk.get('schedule_name', 'Direct Shift'),
                         'shift_id': shift_chk.get('_id'),
                         'start_date': shift_chk.get('start_date', 'Continuous'),
                         'end_date': shift_chk.get('end_date', 'Continuous'),
                         'working_days': shift_chk.get('working_days', []),
                         'time_slots': shift_chk.get('time_slots', []),
                         'is_legacy_shift': True
                     }

        if schedule:
            shift_id_ref = schedule.get('shift_id')
            if shift_id_ref:
                shift = shift_master_collection.find_one({'_id': shift_id_ref})
                if not shift and isinstance(shift_id_ref, str) and ObjectId.is_valid(shift_id_ref):
                     shift = shift_master_collection.find_one({'_id': ObjectId(shift_id_ref)})

        return jsonify({
            'assignment': convert_objectid_to_str(assignment),
            'schedule': convert_objectid_to_str(schedule),
            'shift': convert_objectid_to_str(shift)
        }), 200

    except Exception as e:
        logger.error(f"Error fetching assignment: {str(e)}")
        return jsonify({"error": str(e)}), 500

