# 1. SCHEDULE MASTER (Merged Functionality)
@app.route('/api/schedules', methods=['GET'])
def get_shifts():
    try:
        # --- Centralized Permission Filtering ---
        can_access, data_scope_filter = get_data_scope_filter('schedule_master')
        if not can_access:
            return jsonify([]), 200

        # Union of Shifts (Legacy) and Schedules (New) - both filtered
        shifts = list(shift_master_collection.find(data_scope_filter))
        schedules = list(schedule_master_collection.find(data_scope_filter))
        
        # Group records by global_ref_id (preferred) OR schedule_name/shift_name
        grouped = {}
        for t in (shifts + schedules):
            # Use global_ref_id as primary key, fall back to name
            ref_id = t.get('global_ref_id', '')
            name_key = t.get('schedule_name', t.get('shift_name', '')).strip().lower()
            group_key = ref_id if ref_id else name_key
            if not group_key: continue
            
            if group_key not in grouped:
                v_copy = t.copy()
                v_copy['id'] = str(v_copy.pop('_id', '') or '')
                v_copy['branch_names'] = set()
                v_copy['company_names'] = set()
                if t.get('branch_name') and t.get('branch_name') != 'All Branches':
                    v_copy['branch_names'].add(t['branch_name'])
                if t.get('company_name'):
                    v_copy['company_names'].add(t['company_name'])
                grouped[group_key] = v_copy
            else:
                # Merge current flat row's data
                if t.get('company_name'):
                    grouped[group_key]['company_names'].add(t['company_name'])
                if t.get('branch_name') and t.get('branch_name') != 'All Branches':
                    grouped[group_key]['branch_names'].add(t['branch_name'])

        # Convert sets back to lists
        results = []
        for item in grouped.values():
            item['branch_names'] = list(item['branch_names'])
            item['company_names'] = list(item['company_names'])
            # Ensure schedule_name is always present
            if not item.get('schedule_name'):
                item['schedule_name'] = item.get('shift_name', '')
            results.append(item)
            
        return jsonify(convert_objectid_to_str(results)), 200
    except Exception as e:
        return jsonify({'error': f"Failed to fetch schedules: {str(e)}"}), 500

@app.route('/api/schedules', methods=['POST'])
def add_shift():
    try:
        data = request.json
        if not data:
            return jsonify({'error': 'No data provided'}), 400
        
        # Handle time slots
        time_slots = data.get('time_slots', [])
        if not time_slots:
            # Fallback for single slot
            if data.get('start_time') and data.get('end_time'):
                time_slots = [{
                    'start_time': data.get('start_time'),
                    'end_time': data.get('end_time'),
                    'is_overnight': data.get('is_overnight', False)
                }]
            else:
                return jsonify({'error': 'At least one time slot is required'}), 400
        
        # Validate each slot
        for slot in time_slots:
            if not slot.get('start_time') or not slot.get('end_time'):
                return jsonify({'error': 'Each time slot must have start_time and end_time'}), 400
        
        # Dynamic merging logic for metadata
        schedule = {
            'time_slots': time_slots,
            'created_at': datetime.now(timezone.utc).isoformat()
        }
        
        # Merge all incoming data fields (excluding those handled above or internals)
        exclude_keys = ['_id', 'id', 'time_slots', 'created_at', 'company_names', 'branch_names', 'company_name', 'branch_name', 'tenant_id', 'company_id', 'branch_id']
        extra_fields = {k: v for k, v in data.items() if k not in exclude_keys}

        # --- NEW MULTI-TENANT RESOLUTION AND SAVING LOGIC ---
        company_names = data.get('company_names', [])
        branch_names = data.get('branch_names', [])
        active_company = request.headers.get('X-Company-Name') or data.get('company_name', '')
        active_branch = request.headers.get('X-Branch-Name') or data.get('branch_name', '')

        if not company_names and active_company:
            company_names = [active_company]
        if not branch_names and active_branch:
            branch_names = [active_branch]

        if not company_names:
            return jsonify({"error": "At least one company must be selected."}), 400

        created_docs = []
        created_at = datetime.now(ZoneInfo("UTC")).isoformat()
        global_ref_id = str(__import__('uuid').uuid4())

        for comp_name in company_names:
            ids = _resolve_tenant_company_branch(comp_name)
            if not ids.get("company_id"):
                logger.warning(f"add_shift: Could not resolve company_id for '{comp_name}', skipping")
                continue
            
            # ALWAYS create the "All Branches" base record
            doc_all = {
                "_id": str(__import__('uuid').uuid4()),
                "global_ref_id": global_ref_id,
                "tenant_id": ids.get("tenant_id"),
                "company_id": ids.get("company_id"),
                "company_name": comp_name,
                "branch_id": None,
                "branch_name": "All Branches",
                "time_slots": time_slots,
                "created_at": created_at,
                **extra_fields
            }
            try:
                # Directly insert bypassing double tenancy injection (already resolved above)
                import json as _json
                _doc_json = _json.dumps(doc_all)
                with schedule_master_collection._lock:
                    _cur = schedule_master_collection.conn.cursor()
                    _cur.execute(f"INSERT INTO schedule_master (id, data) VALUES (?, ?)", (doc_all['_id'], _doc_json))
                    schedule_master_collection.conn.commit()
                logger.info(f"add_shift: Inserted All-Branches doc for company '{comp_name}', id={doc_all['_id']}")
                created_docs.append(doc_all)
            except Exception as insert_err:
                logger.error(f"add_shift: Failed to insert All-Branches doc for '{comp_name}': {insert_err}")
            
            # Add specific branch records
            if branch_names:
                for br_name in branch_names:
                    br_ids = _resolve_tenant_company_branch(comp_name, br_name)
                    if not br_ids.get("branch_id"):
                        logger.warning(f"add_shift: Could not resolve branch_id for '{br_name}' in '{comp_name}', skipping")
                        continue
                    
                    doc_br = {
                        "_id": str(__import__('uuid').uuid4()),
                        "global_ref_id": global_ref_id,
                        "tenant_id": br_ids.get("tenant_id"),
                        "company_id": br_ids.get("company_id"),
                        "company_name": comp_name,
                        "branch_id": br_ids.get("branch_id"),
                        "branch_name": br_name,
                        "time_slots": time_slots,
                        "created_at": created_at,
                        **extra_fields
                    }
                    try:
                        _doc_json = _json.dumps(doc_br)
                        with schedule_master_collection._lock:
                            _cur = schedule_master_collection.conn.cursor()
                            _cur.execute(f"INSERT INTO schedule_master (id, data) VALUES (?, ?)", (doc_br['_id'], _doc_json))
                            schedule_master_collection.conn.commit()
                        logger.info(f"add_shift: Inserted branch doc '{br_name}' for '{comp_name}', id={doc_br['_id']}")
                        created_docs.append(doc_br)
                    except Exception as insert_err:
                        logger.error(f"add_shift: Failed to insert branch doc '{br_name}' for '{comp_name}': {insert_err}")

        if not created_docs:
            return jsonify({"error": "No records were saved. Check company/branch resolution."}), 500

        return jsonify({"message": "Schedule created successfully", "global_ref_id": global_ref_id, "data": convert_objectid_to_str(created_docs)}), 201
    except Exception as e:
        logger.error(f"add_shift outer exception: {e}")
        return jsonify({'error': f"Failed to add schedule: {str(e)}"}), 500


@app.route('/api/schedules/bulk/<global_ref_id>', methods=['PUT', 'DELETE'])
def bulk_update_schedules(global_ref_id):
    try:
        can_access, data_scope_filter = get_data_scope_filter('schedule_master')
        if not can_access: return jsonify({"error": "Access denied"}), 403

        ctx = _get_tenant_context_for_update_delete()
        filter_query = {"$and": [data_scope_filter, _build_strict_bulk_filter(global_ref_id, ctx)]}

        if request.method == 'DELETE':
            result = schedule_master_collection.delete_many(filter_query)
            if result.deleted_count == 0: return jsonify({"error": "No linked schedules found or access denied"}), 404
            return jsonify({"message": f"{result.deleted_count} linked schedules deleted successfully"}), 200
            
        elif request.method == 'PUT':
            data = request.get_json()
            
            exclude_keys = {'company_name', 'branch_name', 'company_names', 'branch_names', '_id', 'global_ref_id', 'id', 'tenant_id', 'company_id', 'branch_id'}
            update_data = {k: v for k, v in data.items() if k not in exclude_keys}
            
            from datetime import datetime
            try:
                from zoneinfo import ZoneInfo
                update_data['modified_at'] = datetime.now(ZoneInfo("UTC")).isoformat()
            except: pass

            # --- SYNCHRONIZATION LOGIC FOR ADDED/REMOVED BRANCHES ---
            company_names = data.get('company_names', [])
            branch_names = data.get('branch_names', [])
            if branch_names:
                branch_names = [b for b in branch_names if b and str(b).lower() not in ['all', 'all branches', 'global', 'all companies']]
                
            if company_names:
                existing_records = list(schedule_master_collection.find(filter_query))
                if existing_records:
                    desired_combinations = set()
                    for comp_name in company_names:
                        desired_combinations.add((comp_name, "All Branches"))
                        if branch_names:
                            for br_name in branch_names:
                                br_ids = _resolve_tenant_company_branch(comp_name, br_name)
                                if br_ids.get("branch_id"):
                                    desired_combinations.add((comp_name, br_name))
                                    
                    existing_combinations = {(r.get('company_name'), r.get('branch_name')) for r in existing_records}
                    
                    combinations_to_add = desired_combinations - existing_combinations
                    combinations_to_remove = existing_combinations - desired_combinations
                    
                    import uuid
                    if combinations_to_add:
                        base_record = existing_records[0].copy()
                        for k in ['_id', 'company_name', 'company_id', 'branch_name', 'branch_id', 'tenant_id']:
                            base_record.pop(k, None)
                        base_record.update(update_data)
                        
                        for comp_name, br_name in combinations_to_add:
                            ids = _resolve_tenant_company_branch(comp_name)
                            if not ids.get("company_id"): continue
                            
                            br_id = None
                            if br_name != "All Branches":
                                br_ids = _resolve_tenant_company_branch(comp_name, br_name)
                                if not br_ids.get("branch_id"): continue
                                br_id = br_ids.get("branch_id")
                                tenant_id = br_ids.get("tenant_id")
                            else:
                                tenant_id = ids.get("tenant_id")
                                
                            new_doc = {
                                "_id": str(uuid.uuid4()),
                                "global_ref_id": global_ref_id,
                                "tenant_id": tenant_id,
                                "company_id": ids.get("company_id"),
                                "company_name": comp_name,
                                "branch_id": br_id,
                                "branch_name": br_name,
                                **base_record
                            }
                            logger.info(f"DEBUG new_doc before insert: {new_doc}")
                            try:
                                import json as _json
                                _doc_json = _json.dumps(new_doc)
                                with schedule_master_collection._lock:
                                    _cur = schedule_master_collection.conn.cursor()
                                    _cur.execute("INSERT INTO schedule_master (id, data) VALUES (?, ?)", (new_doc['_id'], _doc_json))
                                    schedule_master_collection.conn.commit()
                            except Exception as insert_err:
                                logger.error(f"bulk_update_schedules: Failed to insert doc for '{br_name}': {insert_err}")

                            
                    if combinations_to_remove:
                        for comp_name, br_name in combinations_to_remove:
                            schedule_master_collection.delete_one({"$and": [
                                filter_query, 
                                {"company_name": comp_name, "branch_name": br_name}
                            ]})
            # --- END SYNCHRONIZATION LOGIC ---
            
            result = schedule_master_collection.update_many(filter_query, {'$set': update_data})
            if result.matched_count == 0: return jsonify({"error": "No linked schedules found or access denied"}), 404
            return jsonify({"message": f"{result.modified_count} linked schedules updated successfully"}), 200

    except Exception as e:
        return jsonify({"error": str(e)}), 500

