# --- Item-wise Purchase Report API Endpoint ---
@app.route('/api/reports/item-wise-purchase', methods=['GET'])
def get_item_wise_purchase_report():
    try:
        # Get query parameters for filtering
        date_from = request.args.get('dateFrom')
        date_to = request.args.get('dateTo')
        item_id = request.args.get('itemId')
        supplier_id = request.args.get('supplierId')
        
        # Fetch all submitted purchase invoices
        invoices = purchase_invoices_collection.find({'status': 'Submitted'})
        
        # Filter by date range if provided
        if date_from or date_to:
            filtered_invoices = []
            for invoice in invoices:
                invoice_date = invoice.get('date')
                if isinstance(invoice_date, str):
                    invoice_date = datetime.fromisoformat(invoice_date.replace('Z', '+00:00'))
                
                include = True
                if date_from:
                    from_date = datetime.fromisoformat(date_from.replace('Z', '+00:00'))
                    if invoice_date < from_date:
                        include = False
                if date_to:
                    to_date = datetime.fromisoformat(date_to.replace('Z', '+00:00'))
                    if invoice_date > to_date:
                        include = False
                
                if include:
                    filtered_invoices.append(invoice)
            invoices = filtered_invoices
        
        # Aggregate data by item
        item_data = {}
        
        for invoice in invoices:
            # Filter by supplier if provided
            if supplier_id and invoice.get('supplierId') != supplier_id:
                continue
            
            for item in invoice.get('items', []):
                item_id_key = item.get('itemId')
                
                # Filter by item if provided
                if item_id and item_id_key != item_id:
                    continue
                
                if item_id_key not in item_data:
                    # Get item details
                    item_doc = purchase_items_collection.find_one({'_id': item_id_key})
                    if not item_doc:
                        continue
                    
                    item_data[item_id_key] = {
                        'itemId': item_id_key,
                        'itemName': item_doc.get('item_name', item_doc.get('name', 'Unknown')),
                        'brand': item_doc.get('brand', item_doc.get('company', '')),
                        'rawQuantities': {},
                        'nosQuantity': 0,
                        'totalAmount': 0,
                        'totalTaxes': 0,
                        'grandTotal': 0,
                        'currency': invoice.get('currency', 'AED'),
                        'uom': item_doc.get('nosUnit', 'Nos'),
                        'masterUnit': item_doc.get('masterUnit', 'Master'),
                        'outerUnit': item_doc.get('outerUnit', 'Outer'),
                        'masterToOuter': float(item_doc.get('masterToOuter', item_doc.get('packets_per_box', 1))),
                        'outerToNos': float(item_doc.get('outerToNos', item_doc.get('units_per_packet', 1))),
                        'suppliers': {}
                    }
                
                # Add quantity and amount
                raw_quantity = float(item.get('acceptedQuantity', 0))
                amount = float(item.get('amount', 0))
                unit = item.get('unit', 'master')
                
                master_to_outer = item_data[item_id_key]['masterToOuter']
                outer_to_nos = item_data[item_id_key]['outerToNos']
                
                if unit == 'master':
                    quantity_in_nos = raw_quantity * master_to_outer * outer_to_nos
                    unit_name = item_doc.get('masterUnit', 'Master')
                elif unit == 'outer':
                    quantity_in_nos = raw_quantity * outer_to_nos
                    unit_name = item_doc.get('outerUnit', 'Outer')
                else:
                    quantity_in_nos = raw_quantity
                    unit_name = item_doc.get('nosUnit', 'Nos')
                
                # Track raw quantities by unit
                if unit_name not in item_data[item_id_key]['rawQuantities']:
                    item_data[item_id_key]['rawQuantities'][unit_name] = 0
                item_data[item_id_key]['rawQuantities'][unit_name] += raw_quantity
                item_data[item_id_key]['nosQuantity'] += quantity_in_nos
                item_data[item_id_key]['totalAmount'] += amount
                
                # Calculate prorated taxes for this item
                inv_subtotal = float(invoice.get('subtotal', 0) or 1) # avoid div by zero
                inv_total_taxes = float(invoice.get('totalTaxes', invoice.get('taxesAdded', 0)))
                if inv_total_taxes == 0 and invoice.get('taxes'):
                    inv_total_taxes = sum(float(t.get('amount', 0)) for t in invoice['taxes'] if isinstance(t, dict))
                
                item_taxes = (amount / inv_subtotal) * inv_total_taxes if inv_subtotal > 0 else 0
                item_data[item_id_key]['totalTaxes'] += item_taxes
                item_data[item_id_key]['grandTotal'] += (amount + item_taxes)
                
                # Track supplier breakdown
                supp_id = invoice.get('supplierId')
                
                # Get supplier name from suppliers collection
                supplier_doc = suppliers_collection.find_one({'_id': supp_id})
                supp_name = supplier_doc.get('company', 'Unknown') if supplier_doc else 'Unknown'
                
                if supp_id not in item_data[item_id_key]['suppliers']:
                    item_data[item_id_key]['suppliers'][supp_id] = {
                        'supplierId': supp_id,
                        'supplierName': supp_name,
                        'quantity': 0,
                        'amount': 0,
                        'rawPurchases': {}
                    }
                
                item_data[item_id_key]['suppliers'][supp_id]['quantity'] += quantity_in_nos
                item_data[item_id_key]['suppliers'][supp_id]['amount'] += amount
                
                if unit_name not in item_data[item_id_key]['suppliers'][supp_id]['rawPurchases']:
                    item_data[item_id_key]['suppliers'][supp_id]['rawPurchases'][unit_name] = 0
                item_data[item_id_key]['suppliers'][supp_id]['rawPurchases'][unit_name] += raw_quantity
        
        # Convert to list and format suppliers as array
        result = []
        for item_info in item_data.values():
            # Build raw display string e.g. "10.00 Box"
            raw_display = ", ".join([f"{qty:.2f} {u}" for u, qty in item_info.get('rawQuantities', {}).items()])
            item_info['rawDisplay'] = raw_display  # e.g. "10.00 Box"
            item_info['totalQuantity'] = item_info['nosQuantity']  # keep for rate calculation
            for supp_info in item_info['suppliers'].values():
                supp_raw_str = ", ".join([f"{qty:.2f} {u}" for u, qty in supp_info.get('rawPurchases', {}).items()])
                supp_info['displayText'] = (
                    f"{supp_info['supplierName']}:\n"
                    f"Qty: {supp_raw_str}\n"
                    f"Purchased Units: {supp_info['quantity']:.2f} {item_info['uom']}\n"
                    f"Amt: {item_info['currency']} {supp_info['amount']:.2f}"
                )
            item_info['suppliers'] = list(item_info['suppliers'].values())
            result.append(item_info)
        
        # Sort by item name
        result.sort(key=lambda x: x['itemName'])
        
        return jsonify(convert_objectid_to_str(result)), 200
    except Exception as e:
        logger.error(f"Error generating item-wise purchase report: {str(e)}")
        return jsonify({'error': f"Failed to generate report: {str(e)}"}), 500

