# NEW: Routes for Leave Types (CRUD)
@app.route('/api/leave-types', methods=['GET', 'POST'])
def handle_leave_types():
    if request.method == 'GET':
        try:
            # --- Centralized Permission Filtering ---
            can_access, data_scope_filter = get_data_scope_filter('leave_types')
            if not can_access:
                return jsonify([]), 200

            data = list(leave_types_collection.find(data_scope_filter))
            return jsonify(convert_objectid_to_str(data)), 200
        except Exception as e:
            logger.error(f"Error fetching leave types: {str(e)}")
            return jsonify({"error": "Failed to fetch leave types"}), 500
    if request.method == 'POST':
        try:
            data = request.get_json()
            required_fields = ['leave_code', 'leave_name', 'is_paid', 'allow_half_day', 'allow_hourly', 'is_active']
            missing = [field for field in required_fields if field not in data]
            if missing:
                return jsonify({"error": f"Missing required fields: {', '.join(missing)}"}), 400
    
            data['leave_code'] = data['leave_code'].strip().upper()
            if len(data['leave_code']) > 10:
                return jsonify({"error": "Leave code must be 10 characters or less"}), 400
    
            data['leave_name'] = data['leave_name'].strip()
            if not data['leave_name']:
                return jsonify({"error": "Leave name is required"}), 400
    
            company_names = data.get('company_names', [])
            branch_names = data.get('branch_names', [])
            active_company = request.headers.get('X-Company-Name') or data.get('company_name', '')
            active_branch = request.headers.get('X-Branch-Name') or data.get('branch_name', '')
            
            if not company_names and active_company:
                company_names = [active_company]
            if not branch_names and active_branch:
                branch_names = [active_branch]

            if not company_names:
                return jsonify({"error": "At least one company must be selected."}), 400

            created_docs = []
            created_at = datetime.now(ZoneInfo("UTC")).isoformat()
            global_ref_id = str(uuid.uuid4())

            for comp_name in company_names:
                ids = _resolve_tenant_company_branch(comp_name)
                if not ids.get("company_id"): continue

                # Check duplicate
                dup_filter = {
                    "leave_code": data['leave_code'],
                    "company_id": ids.get("company_id")
                }
                if leave_types_collection.find_one(dup_filter):
                    continue

                # 1. Base 'All Branches' record
                doc_all = {
                    "_id": str(uuid.uuid4()),
                    "leave_type_id": str(uuid.uuid4()),
                    "global_ref_id": global_ref_id,
                    "tenant_id": ids.get("tenant_id"),
                    "company_id": ids.get("company_id"),
                    "company_name": comp_name,
                    "branch_id": None,
                    "branch_name": "All Branches",
                    "leave_code": data['leave_code'],
                    "leave_name": data['leave_name'],
                    "is_paid": data['is_paid'],
                    "allow_half_day": data['allow_half_day'],
                    "allow_hourly": data['allow_hourly'],
                    "is_active": data['is_active'],
                    "description": data.get('description', ''),
                    "created_at": created_at,
                    "updated_at": created_at
                }
                leave_types_collection.insert_one(doc_all)
                created_docs.append(doc_all)

                # 2. Specific branches
                if branch_names:
                    br_list = [b for b in branch_names if str(b).lower() not in ['all', 'all branches', 'global', 'all companies']]
                    for br_name in br_list:
                        b_ids = _resolve_tenant_company_branch(comp_name, br_name)
                        if not b_ids.get("branch_id"): continue
                        
                        doc_br = doc_all.copy()
                        doc_br["_id"] = str(uuid.uuid4())
                        doc_br["leave_type_id"] = str(uuid.uuid4())
                        doc_br["branch_id"] = b_ids.get("branch_id")
                        doc_br["branch_name"] = br_name
                        leave_types_collection.insert_one(doc_br)
                        created_docs.append(doc_br)

            if not created_docs:
                return jsonify({"error": f"Leave Code '{data['leave_code']}' already exists or invalid company context."}), 400

            return jsonify({"message": "Leave type created successfully", "created": len(created_docs)}), 201
        except Exception as e:
            logger.error(f"Error creating leave type: {str(e)}")
            return jsonify({"error": f"Failed to create leave type: {str(e)}"}), 500

@app.route('/api/leave-types/bulk/<global_ref_id>', methods=['PUT', 'DELETE'])
def handle_leave_types_bulk(global_ref_id):
    if request.method == 'PUT':
        try:
            data = request.get_json()
            can_access, data_scope_filter = get_data_scope_filter('leave_types')
            if not can_access: return jsonify({"error": "Access denied"}), 403

            update_data = {
                "leave_code": data.get('leave_code', '').strip().upper(),
                "leave_name": data.get('leave_name', '').strip(),
                "is_paid": data.get('is_paid'),
                "allow_half_day": data.get('allow_half_day'),
                "allow_hourly": data.get('allow_hourly'),
                "is_active": data.get('is_active'),
                "description": data.get('description', '')
            }
            update_data = {k: v for k, v in update_data.items() if v is not None and v != ''}
            update_data['updated_at'] = datetime.now(ZoneInfo("UTC")).isoformat()

            ctx = _get_tenant_context_for_update_delete()
            update_filter = {"$and": [data_scope_filter, _build_strict_bulk_filter(global_ref_id, ctx)]}

            # --- SYNCHRONIZATION LOGIC FOR ADDED/REMOVED BRANCHES ---
            company_names = data.get('company_names', [])
            branch_names = data.get('branch_names', [])
            if branch_names:
                branch_names = [b for b in branch_names if b and str(b).lower() not in ['all', 'all branches', 'global', 'all companies']]
                
            if company_names:
                existing_records = list(leave_types_collection.find(update_filter))
                if existing_records:
                    desired_combinations = set()
                    for comp_name in company_names:
                        desired_combinations.add((comp_name, "All Branches"))
                        if branch_names:
                            for br_name in branch_names:
                                desired_combinations.add((comp_name, br_name))

                    existing_combinations = set()
                    for r in existing_records:
                        comp_name = r.get("company_name")
                        br_name = r.get("branch_name", "All Branches")
                        existing_combinations.add((comp_name, br_name))

                    to_add = desired_combinations - existing_combinations
                    to_remove = existing_combinations - desired_combinations

                    for comp_name, br_name in to_add:
                        ids = _resolve_tenant_company_branch(comp_name, br_name if br_name != "All Branches" else None)
                        if not ids.get("company_id") or (br_name != "All Branches" and not ids.get("branch_id")): continue
                        
                        base_rec = existing_records[0].copy()
                        base_rec.update(update_data)
                        base_rec["_id"] = str(uuid.uuid4())
                        base_rec["leave_type_id"] = str(uuid.uuid4())
                        base_rec["company_id"] = ids.get("company_id")
                        base_rec["tenant_id"] = ids.get("tenant_id")
                        base_rec["company_name"] = comp_name
                        base_rec["branch_id"] = ids.get("branch_id")
                        base_rec["branch_name"] = br_name
                        leave_types_collection.insert_one(base_rec)

                    for comp_name, br_name in to_remove:
                        del_filter = update_filter.copy()
                        del_filter["$and"] = del_filter.get("$and", []) + [{"company_name": comp_name}, {"branch_name": br_name}]
                        leave_types_collection.delete_many(del_filter)

            result = leave_types_collection.update_many(
                update_filter,
                {"$set": update_data}
            )
            return jsonify({"message": f"Updated {result.modified_count} leave types"}), 200
        except Exception as e:
            logger.error(f"Error bulk updating leave types: {str(e)}")
            return jsonify({"error": "Failed to update leave types"}), 500

    if request.method == 'DELETE':
        try:
            can_access, data_scope_filter = get_data_scope_filter('leave_types')
            if not can_access: return jsonify({"error": "Access denied"}), 403

            ctx = _get_tenant_context_for_update_delete()
            delete_filter = {"$and": [data_scope_filter, _build_strict_bulk_filter(global_ref_id, ctx)]}
            
            result = leave_types_collection.delete_many(delete_filter)
            return jsonify({"message": f"Deleted {result.deleted_count} leave types"}), 200
        except Exception as e:
            logger.error(f"Error bulk deleting leave types: {str(e)}")
            return jsonify({"error": "Failed to delete leave types"}), 500

@app.route('/api/leave-types/<leave_type_id>', methods=['GET', 'PUT', 'DELETE'])
def handle_leave_type(leave_type_id):
    # Common filter for backward compatibility: match by leave_type_id OR _id
    or_filter = {'$or': [{'leave_type_id': leave_type_id}, {'_id': leave_type_id}]}
    
    if request.method == 'GET':
        try:
            # --- Centralized Permission Filtering ---
            can_access, data_scope_filter = get_data_scope_filter('leave_types')
            if not can_access:
                return jsonify({"error": "Access denied"}), 403

            # Combine scope filter with ID filter
            final_filter = {"$and": [data_scope_filter, or_filter]}
            data = leave_types_collection.find_one(final_filter)
            if not data:
                return jsonify({"error": "Leave type not found or access denied"}), 404
            return jsonify(convert_objectid_to_str(data)), 200
        except Exception as e:
            logger.error(f"Error fetching leave type: {str(e)}")
            return jsonify({"error": "Failed to fetch leave type"}), 500
    if request.method == 'PUT':
        try:
            data = request.get_json()
            required_fields = ['leave_code', 'leave_name', 'is_paid', 'allow_half_day', 'allow_hourly', 'is_active']
            missing = [field for field in required_fields if field not in data]
            if missing:
                return jsonify({"error": f"Missing required fields: {', '.join(missing)}"}), 400
    
            # --- Centralized Permission Filtering ---
            can_access, data_scope_filter = get_data_scope_filter('leave_types')
            if not can_access:
                return jsonify({"error": "Access denied"}), 403

            # First, find the existing record using backward-compatible filter + scope
            final_filter = {"$and": [data_scope_filter, or_filter]}
            existing = leave_types_collection.find_one(final_filter)
            if not existing:
                return jsonify({"error": "Leave type not found or access denied"}), 404
    
            # Sanitize
            data['leave_code'] = data['leave_code'].strip().upper()
            data['leave_name'] = data['leave_name'].strip()
    
            # Check duplicate leave_code, excluding current record
            exclude_current = {"$and": [
                data_scope_filter,
                {'leave_code': data['leave_code']},
                {'$nor': [{'leave_type_id': leave_type_id}, {'_id': leave_type_id}]}
            ]}
            existing_duplicate = leave_types_collection.find_one(exclude_current)
            if existing_duplicate:
                return jsonify({"error": "Leave code already exists"}), 409
    
            # Prepare update data
            update_data = data.copy()
            update_data['updated_at'] = datetime.now(ZoneInfo("UTC")).isoformat()
            
            # Backward compatibility: If old record (no leave_type_id), add it now for future consistency
            if not existing.get('leave_type_id'):
                update_data['leave_type_id'] = leave_type_id  # leave_type_id param is the _id value
    
            # Inject company and branch context if missing
            if 'company_name' not in update_data:
                update_data['company_name'] = existing.get('company_name') or request.headers.get('X-Company-Name')
            if 'branch_name' not in update_data:
                update_data['branch_name'] = existing.get('branch_name') or request.headers.get('X-Branch-Name')

            # Update using the backward-compatible filter + scope
            result = leave_types_collection.update_one(final_filter, {'$set': update_data})
            if result.modified_count == 0:
                return jsonify({"error": "Leave type not found"}), 404
            logger.info(f"Updated leave type: {data['leave_name']}")
            return jsonify({"message": "Leave type updated successfully"}), 200
        except Exception as e:
            logger.error(f"Error updating leave type: {str(e)}")
            return jsonify({"error": "Failed to update leave type"}), 500
    if request.method == 'DELETE':
        try:
            # Check if used in allocations (unchanged, as explained)
            allocs = list(leave_allocation_collection.find({'leave_type_id': leave_type_id}))
            if allocs:
                return jsonify({"error": "Cannot delete leave type used in allocations"}), 409
    
            # --- Centralized Permission Filtering ---
            can_access, data_scope_filter = get_data_scope_filter('leave_types')
            if not can_access:
                return jsonify({"error": "Access denied"}), 403

            # Delete using backward-compatible filter + scope
            final_filter = {"$and": [data_scope_filter, or_filter]}
            result = leave_types_collection.delete_one(final_filter)
            if result.deleted_count == 0:
                return jsonify({"error": "Leave type not found"}), 404
            logger.info(f"Deleted leave type ID: {leave_type_id}")
            return jsonify({"message": "Leave type deleted successfully"}), 200
        except Exception as e:
            logger.error(f"Error deleting leave type: {str(e)}")
            return jsonify({"error": "Failed to delete leave type"}), 500
@app.route('/api/leave-allocations', methods=['GET', 'POST'])
def handle_leave_allocations():
    if request.method == 'GET':
        try:
            # --- Centralized Permission Filtering ---
            # Leave allocations are typically global/system-wide settings, not employee-specific.
            # So, we use a generic permission check without an owner_field.
            can_access, filter_query = get_data_scope_filter('leave_allocation')
            if not can_access:
                 return jsonify([]), 200
            
            allocations = list(leave_allocation_collection.find(filter_query))
            # Join with leave_types for display
            enriched = []
            for alloc in allocations:
                lt_id = alloc.get('leave_type_id')
                lt = leave_types_collection.find_one({'$or': [{'leave_type_id': lt_id}, {'_id': lt_id}]})
                enriched.append({
                    **alloc,
                    'leave_name': lt.get('leave_name', 'N/A') if lt else 'N/A',
                    'leave_code': lt.get('leave_code', '') if lt else ''
                })
            return jsonify(convert_objectid_to_str(enriched)), 200
        except Exception as e:
            logger.error(f"Error fetching leave allocations: {str(e)}")
            return jsonify({"error": "Failed to fetch leave allocations"}), 500
    if request.method == 'POST':
        try:
            data = request.get_json()
            required_fields = ['leave_type_id', 'monthly_credit', 'yearly_credit', 'credit_unit', 'is_active']
            missing = [field for field in required_fields if field not in data]
            if missing:
                return jsonify({"error": f"Missing required fields: {', '.join(missing)}"}), 400
           
            leave_type_id = data['leave_type_id']
            lt = leave_types_collection.find_one({'$or': [{'leave_type_id': leave_type_id}, {'_id': leave_type_id}]})
           
            if not lt:
                return jsonify({"error": f"Invalid leave type ID: {leave_type_id}"}), 400
           
            if not lt.get('is_active'):
                return jsonify({"error": f"Leave type is inactive: {lt.get('leave_name')}"}), 400
            if float(data['monthly_credit']) < 0 or float(data['yearly_credit']) < 0:
                return jsonify({"error": "Credits must be non-negative"}), 400
           
            if data['credit_unit'] not in ['DAYS', 'MINUTES']:
                return jsonify({"error": "Invalid credit unit"}), 400
           
            existing = leave_allocation_collection.find_one({'leave_type_id': data['leave_type_id']})
            if existing:
                return jsonify({"error": "Allocation already exists for this leave type"}), 409
           
            if 'allocation_id' not in data:
                data['allocation_id'] = str(uuid.uuid4())
           
            # Inject company and branch context
            active_company = request.headers.get('X-Company-Name') or data.get('company_name')
            active_branch = request.headers.get('X-Branch-Name') or data.get('branch_name')
            if active_company: data['company_name'] = active_company
            if active_branch: data['branch_name'] = active_branch

            data['created_at'] = datetime.now(ZoneInfo("UTC")).isoformat()
            data['updated_at'] = data['created_at']
           
            result = leave_allocation_collection.insert_one(data)
            logger.info(f"Created leave allocation for leave type: {data['leave_type_id']}")
            return jsonify({"message": "Leave allocation created successfully", "id": data['allocation_id']}), 201
        except Exception as e:
            logger.error(f"Error creating leave allocation: {str(e)}")
            return jsonify({"error": f"Failed to create leave allocation: {str(e)}"}), 500

@app.route('/api/leave-allocations/<allocation_id>', methods=['GET', 'PUT', 'DELETE'])
def handle_leave_allocation(allocation_id):
    if request.method == 'GET':
        try:
            # --- Centralized Permission Filtering ---
            can_access, filter_query = get_data_scope_filter('leave_allocation')
            if not can_access:
                 return jsonify({"error": "Access denied to leave allocations"}), 403
            
            filter_query['allocation_id'] = allocation_id # Add specific ID to the filter
            
            alloc = leave_allocation_collection.find_one(filter_query)
            if not alloc:
                return jsonify({"error": "Leave allocation not found or access denied"}), 404
            lt_id = alloc.get('leave_type_id')
            lt = leave_types_collection.find_one({'$or': [{'leave_type_id': lt_id}, {'_id': lt_id}]})
            enriched = {
                **alloc,
                'leave_name': lt.get('leave_name', 'N/A') if lt else 'N/A',
                'leave_code': lt.get('leave_code', '') if lt else ''
            }
            return jsonify(convert_objectid_to_str(enriched)), 200
        except Exception as e:
            logger.error(f"Error fetching leave allocation: {str(e)}")
            return jsonify({"error": "Failed to fetch leave allocation"}), 500
    if request.method == 'PUT':
        try:
            data = request.get_json()
            required_fields = ['leave_type_id', 'monthly_credit', 'yearly_credit', 'credit_unit', 'is_active']
            missing = [field for field in required_fields if field not in data]
            if missing:
                return jsonify({"error": f"Missing required fields: {', '.join(missing)}"}), 400
           
            leave_type_id = data['leave_type_id']
            lt = leave_types_collection.find_one({'$or': [{'leave_type_id': leave_type_id}, {'_id': leave_type_id}]})
            if not lt:
                return jsonify({"error": f"Invalid leave type ID: {leave_type_id}"}), 400
            if not lt.get('is_active'):
                return jsonify({"error": f"Leave type is inactive: {lt.get('leave_name')}"}), 400
           
            # --- Centralized Permission Filtering ---
            can_access, filter_query = get_data_scope_filter('leave_allocation')
            if not can_access:
                return jsonify({"error": "Access denied"}), 403
            
            filter_query['allocation_id'] = allocation_id

            existing = leave_allocation_collection.find_one(filter_query)
            if not existing:
                return jsonify({"error": "Leave allocation not found"}), 404

            if float(data['monthly_credit']) < 0 or float(data['yearly_credit']) < 0:
                return jsonify({"error": "Credits must be non-negative"}), 400
           
            if data['credit_unit'] not in ['DAYS', 'MINUTES']:
                return jsonify({"error": "Invalid credit unit"}), 400
           
            # Check duplication for other records
            dup_filter = filter_query.copy()
            del dup_filter['allocation_id']
            dup_filter['leave_type_id'] = data['leave_type_id']
            dup_filter['allocation_id'] = {'$ne': allocation_id}
            
            existing_dup = leave_allocation_collection.find_one(dup_filter)
            if existing_dup:
                return jsonify({"error": "Allocation already exists for this leave type"}), 409
           
            data['updated_at'] = datetime.now(ZoneInfo("UTC")).isoformat()
            
            # Inject company/branch if missing
            if 'company_name' not in data:
                data['company_name'] = existing.get('company_name') or request.headers.get('X-Company-Name')
            if 'branch_name' not in data:
                data['branch_name'] = existing.get('branch_name') or request.headers.get('X-Branch-Name')

            result = leave_allocation_collection.update_one({'allocation_id': allocation_id}, {'$set': data})
            if result.modified_count == 0:
                # Might be same data, check if existed
                pass 
            logger.info(f"Updated leave allocation: {allocation_id}")
            return jsonify({"message": "Leave allocation updated successfully"}), 200
        except Exception as e:
            logger.error(f"Error updating leave allocation: {str(e)}")
            return jsonify({"error": "Failed to update leave allocation"}), 500
    if request.method == 'DELETE':
        try:
            result = leave_allocation_collection.delete_one({'allocation_id': allocation_id})
            if result.deleted_count == 0:
                return jsonify({"error": "Leave allocation not found"}), 404
            logger.info(f"Deleted leave allocation ID: {allocation_id}")
            return jsonify({"message": "Leave allocation deleted successfully"}), 200
        except Exception as e:
            logger.error(f"Error deleting leave allocation: {str(e)}")
            return jsonify({"error": "Failed to delete leave allocation"}), 500

@app.route('/api/leave-applications', methods=['GET', 'POST'])
def handle_leave_applications():
    if request.method == 'GET':
        try:
            # --- Centralized Permission Filtering ---
            # Leave applications use 'employee_id' as owner field
            # Allow passing pageId for context-aware filtering (e.g. from Roster page)
            page_id = request.args.get('pageId', 'leave_apply')
            can_access, filter_query = get_data_scope_filter(page_id, owner_field='employee_id')
            if not can_access:
                 return jsonify([]), 200

            # Narrow down by requested employee if applicable
            req_emp_id = request.args.get('employee_id')
            if req_emp_id:
                if 'employee_id' in filter_query:
                    # If already filtered (OWN/HIERARCHY), check if requested is in allowed
                    if isinstance(filter_query['employee_id'], dict) and '$in' in filter_query['employee_id']:
                        if req_emp_id not in filter_query['employee_id']['$in']:
                            return jsonify([]), 200
                    elif filter_query['employee_id'] != req_emp_id:
                        return jsonify([]), 200
                filter_query['employee_id'] = req_emp_id
            
            logger.info(f"leave_applications filter: {filter_query}")
            applications = list(leave_apply_collection.find(filter_query))

            enriched = []
            for app in applications:
                emp_id = app.get('employee_id')
                lt_id = app.get('leave_type_id')
                # optimization: fetch only if needed, or rely on loop (ok for small scale)
                employee = worker_collection.find_one({'$or': [{'_id': emp_id}, {'employeeId': emp_id}]})
                lt = leave_types_collection.find_one({'$or': [{'leave_type_id': lt_id}, {'_id': lt_id}]})
                enriched.append({
                    **app,
                    'employee_name': employee.get('name', 'N/A') if employee else 'N/A',
                    'leave_name': lt.get('leave_name', 'N/A') if lt else 'N/A',
                    'leave_code': lt.get('leave_code', '') if lt else ''
                })
            return jsonify(convert_objectid_to_str(enriched)), 200
        except Exception as e:
            logger.error(f"Error fetching leave applications: {str(e)}")
            return jsonify({"error": "Failed to fetch leave applications"}), 500
    if request.method == 'POST':
        try:
            data = request.get_json()
            required_fields = ['employee_id', 'leave_type_id', 'from_date', 'to_date', 'status']
            missing = [field for field in required_fields if field not in data]
            if missing:
                return jsonify({"error": f"Missing required fields: {', '.join(missing)}"}), 400
         
            employee_id = data['employee_id']
         
            # CONFLICT CHECK: Attendance / Holiday / Weekly Off
            try:
                start_dt = datetime.strptime(data['from_date'].split('T')[0], '%Y-%m-%d').date()
                end_dt = datetime.strptime(data['to_date'].split('T')[0], '%Y-%m-%d').date()
                curr = start_dt
             
                # Pre-fetch check data
                all_assigns = list(employee_schedule_assign_collection.find({'employee_id': employee_id}))
                # Exclude temporary substitutes to find the regular schedule
                active = [
                    a for a in all_assigns 
                    if a.get('is_active') and "Substitute for" not in a.get('notes', '')
                ]
                active.sort(key=lambda x: x.get('assigned_date',''), reverse=True)
                
                # Find valid assignment effective for the leave period
                # Ideally check per day, but taking latest before start_dt is a reasonable approximation
                schedule = None
                # Filter assignments that started on or before the leave start date
                valid_assigns = [a for a in active if a.get('assigned_date') <= data['from_date']]
                if valid_assigns:
                    schedule = schedule_master_collection.find_one({'_id': valid_assigns[0]['schedule_id']})

                while curr <= end_dt:
                    d_str = curr.strftime('%Y-%m-%d')
                 
                    # 1. Check Existing Attendance
                    if attendance_collection.find_one({'employee_id': employee_id, 'attendance_date': d_str}):
                        return jsonify({"error": f"Cannot apply leave: Attendance record exists for {d_str}"}), 400
                 
                    # 2. Check Schedule (Holiday/WeeklyOff)
                    if schedule:
                        # Weekly Off
                        wd = ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'][curr.weekday()]
                        if wd in schedule.get('weekly_off', []):
                            # Allow applying leave on weekly off? Usually no, or it doesn't count.
                            # System enforces NO leave on weekly off to prevent double counting or illogical states.
                            return jsonify({"error": f"Cannot apply leave: {d_str} is a Weekly Off ({wd})"}), 400
                        # Holiday
                        sp = next((s for s in schedule.get('special_days', []) if s.get('date') == d_str), None)
                        if sp and sp.get('type') == 'Holiday':
                            return jsonify({"error": f"Cannot apply leave: {d_str} is a Holiday"}), 400
                 
                    curr += timedelta(days=1)
            except Exception as e:
                logger.error(f"Conflict check error: {e}")
                return jsonify({"error": f"Error validating dates: {str(e)}"}), 400

            emp = worker_collection.find_one({'$or': [{'_id': employee_id}, {'employeeId': employee_id}]})
            if not emp:
                return jsonify({"error": f"Invalid employee ID: {employee_id}"}), 400
         
            leave_type_id = data['leave_type_id']
            lt = leave_types_collection.find_one({'$or': [{'leave_type_id': leave_type_id}, {'_id': leave_type_id}]})
            if not lt:
                return jsonify({"error": f"Invalid leave type ID: {leave_type_id}"}), 400
            if not lt.get('is_active'):
                return jsonify({"error": f"Leave type is inactive: {lt.get('leave_name')}"}), 400
         
            data['leave_mode'] = data.get('leave_mode', 'FULL_DAY')
            if data['leave_mode'] not in ['FULL_DAY', 'HALF_DAY', 'HOURLY']:
                return jsonify({"error": "Invalid leave mode"}), 400
         
            try:
                from_d = data['from_date'].split('T')[0]
                to_d = data['to_date'].split('T')[0]
                data['from_date'] = from_d
                data['to_date'] = to_d
                if from_d > to_d:
                    return jsonify({"error": "From Date cannot be later than To Date"}), 400
            except ValueError:
                return jsonify({"error": "Invalid date format (use YYYY-MM-DD)"}), 400
         
            data['schedule_id'] = data.get('schedule_id')
            data['shift_id'] = data.get('shift_id')
            data['from_time'] = data.get('from_time')
            data['to_time'] = data.get('to_time')
            data['total_units'] = float(data.get('total_units', 0))
            data['unit_type'] = data.get('unit_type', 'DAYS')
            data['reason'] = data.get('reason', '').strip()[:500]
            data['remarks'] = data.get('remarks', '').strip()
            data['approved_by'] = data.get('approved_by')
            data['approved_at'] = data.get('approved_at')
         
            data['status'] = data.get('status', 'PENDING')
            if data['status'] not in ['PENDING', 'APPROVED', 'REJECTED']:
                return jsonify({"error": "Invalid status"}), 400
         
            if 'leave_id' not in data:
                data['leave_id'] = str(uuid.uuid4())
         
            data['applied_at'] = data.get('applied_at', datetime.now(ZoneInfo("UTC")).isoformat())
            data['updated_at'] = data['applied_at']
         
            result = leave_apply_collection.insert_one(data)
            logger.info(f"Created leave application for employee: {emp.get('name', employee_id)}")
            return jsonify({"message": "Leave application created successfully", "id": data['leave_id']}), 201
        except Exception as e:
            logger.error(f"Error creating leave application: {str(e)}")
            return jsonify({"error": f"Failed to create leave application: {str(e)}"}), 500

