@app.route('/api/vehicle/management', methods=['GET', 'POST', 'OPTIONS'])
def manage_vehicles():
    if request.method == 'OPTIONS':
        return jsonify({"success": True}), 200

    if request.method == 'GET':
        # --- Centralized Permission Filtering ---
        can_access, filter_query = get_data_scope_filter('vehicle_management')
        if not can_access:
             return jsonify([]), 200
             
        vehicles = list(vehiclemanagement_collection.find(filter_query))
        grouped = {}
        for v in vehicles:
            # We group by vehicle_number to merge multi-tenant rows
            key = v.get('vehicle_number', '').strip().lower()
            if not key: continue
            if key not in grouped:
                v_copy = v.copy()
                v_copy['id'] = str(v_copy.pop('_id'))
                v_copy['branch_names'] = set(v_copy.get('branch_names', []))
                v_copy['company_names'] = set(v_copy.get('company_names', []))
                grouped[key] = v_copy
            
            if v.get('company_name'):
                grouped[key]['company_names'].add(v['company_name'])
            if v.get('branch_name'):
                grouped[key]['branch_names'].add(v['branch_name'])

        results = []
        for item in grouped.values():
            item['branch_names'] = list(item['branch_names'])
            item['company_names'] = list(item['company_names'])
            results.append(item)
            
        return jsonify(convert_objectid_to_str(results)), 200
    
    if request.method == 'POST':
        # Handle FormData
        data = request.form.to_dict()
        
        # Handle multiple branch selection from FormData
        branch_names = request.form.getlist('branch_names[]')
        if branch_names:
            data['branch_names'] = branch_names
        elif 'branch_names' in data and isinstance(data['branch_names'], str):
             # Handle single string if not using getlist
             data['branch_names'] = [data['branch_names']]
        
        # Handle boolean conversion for FormData
        if 'is_company_owned' in data:
            data['is_company_owned'] = data['is_company_owned'].lower() == 'true'
            
        # Optional: Check duplicate ONLY if vehicle_number is provided
        # if data.get('vehicle_number'):
        #     existing = vehiclemanagement_collection.find_one({"vehicle_number": data['vehicle_number']})
        #     if existing:
        #         return jsonify({"error": "Vehicle number already exists"}), 400
        
        # Handle file uploads
        if 'insurance_doc' in request.files:
            file = request.files['insurance_doc']
            filename = handle_image_upload(file)
            if filename:
                data['insurance_doc'] = filename
                
        if 'pollution_doc' in request.files:
            file = request.files['pollution_doc']
            filename = handle_image_upload(file)
            if filename:
                data['pollution_doc'] = filename

        data['created_at'] = datetime.now(ZoneInfo("UTC")).isoformat()
        
        # MULTI-TENANCY V3 LOGIC
        company_names = request.form.getlist('company_names[]')
        branch_names = request.form.getlist('branch_names[]')
        
        # Clean up FormData array keys from `data` dict
        for key in list(data.keys()):
            if key.endswith('[]'):
                data.pop(key, None)
        
        if not company_names:
            company_names = [request.headers.get('X-Company-Name') or data.get('company_name', '')]
            company_names = [c for c in company_names if c]
            
        if not company_names:
            return jsonify({"error": "At least one company must be selected"}), 400
            
        global_ref_id = str(__import__('uuid').uuid4())
        created_docs = []
        
        import uuid
        for comp_name in company_names:
            ids = _resolve_tenant_company_branch(comp_name)
            if not ids.get("company_id"): continue
            
            # Base Record
            doc_all = data.copy()
            doc_all.update({
                "_id": str(uuid.uuid4()),
                "global_ref_id": global_ref_id,
                "tenant_id": ids.get("tenant_id"),
                "company_id": ids.get("company_id"),
                "company_name": comp_name,
                "branch_id": None,
                "branch_name": "All Branches"
            })
            vehiclemanagement_collection.insert_one(doc_all)
            created_docs.append(doc_all)
            
            # Specific Branches
            if branch_names:
                for br_name in branch_names:
                    br_ids = _resolve_tenant_company_branch(comp_name, br_name)
                    if not br_ids.get("branch_id"): continue
                    
                    doc_br = data.copy()
                    doc_br.update({
                        "_id": str(uuid.uuid4()),
                        "global_ref_id": global_ref_id,
                        "tenant_id": br_ids.get("tenant_id"),
                        "company_id": br_ids.get("company_id"),
                        "company_name": comp_name,
                        "branch_id": br_ids.get("branch_id"),
                        "branch_name": br_name
                    })
                    vehiclemanagement_collection.insert_one(doc_br)
                    created_docs.append(doc_br)
                    
        return jsonify({"message": "Vehicle created successfully", "global_ref_id": global_ref_id}), 201


