@app.route('/api/admin-dashboard/chart-data', methods=['GET'])
def admin_dashboard_chart_data():
    try:
        user_id, role = get_request_user_info()
        user_doc = users_collection.find_one({'_id': user_id}) if user_id else {}
        tenant_id = user_doc.get('tenant_id') if user_doc else None
        
        company = request.args.get('company')
        branch = request.args.get('branch')
        date_filter = request.args.get('date_filter', 'monthly') # daily, monthly, yearly, custom
        metric_type = request.args.get('metric_type', 'sales') # sales, customers, items, employees
        
        start_date_str = request.args.get('start_date')
        end_date_str = request.args.get('end_date')
        
        selected_month = request.args.get('selected_month') # YYYY-MM
        selected_year = request.args.get('selected_year') # YYYY
        start_year = request.args.get('start_year') # YYYY
        end_year = request.args.get('end_year') # YYYY
        
        strict_scope_clauses = []
        if tenant_id:
            strict_scope_clauses.append({'tenant_id': tenant_id})
            
        if company and company.lower() not in ['all', 'all companies', 'none', 'null']:
            company_doc = company_details_collection.find_one({'restaurantName': company})
            c_id = company_doc.get('_id') if company_doc else None
            c_clause = {'$or': [
                {'company_name': company},
                {'company': company},
                {'company_names': {'$in': [company]}}
            ]}
            if c_id:
                c_clause['$or'].append({'company_id': str(c_id)})
            strict_scope_clauses.append(c_clause)
            
        if branch and branch.lower() not in ['all', 'all branches', 'any']:
            branch_doc = branches_collection.find_one({'branch_name': branch})
            b_id = branch_doc.get('_id') if branch_doc else None
            b_clause = {'$or': [
                {'branch_name': branch},
                {'branch': branch},
                {'branch_names': {'$in': [branch]}}
            ]}
            if b_id:
                b_clause['$or'].append({'branch_id': str(b_id)})
            strict_scope_clauses.append(b_clause)
            
        final_query = {'$and': strict_scope_clauses} if strict_scope_clauses else {}
        
        from collections import defaultdict
        from datetime import datetime, timedelta
        import calendar
        
        chart_data = defaultdict(float)
        
        # Determine which collection to query based on metric_type
        docs = []
        if metric_type == 'sales':
            d_all = {str(d.get('_id', id(d))): d for d in sales_collection.find(final_query, {'timestamp': 1, 'date': 1, 'created_at': 1, 'grand_total': 1, 'total': 1})}
            docs = list(d_all.values())
        elif metric_type == 'customers':
            d_all = {str(d.get('_id', id(d))): d for d in customers_collection.find(final_query, {'created_at': 1, 'date': 1})}
            docs = list(d_all.values())
        elif metric_type == 'employees':
            d_all = {str(d.get('_id', id(d))): d for d in worker_collection.find(final_query, {'created_at': 1, 'dateOfJoining': 1})}
            docs = list(d_all.values())
        elif metric_type == 'items':
            d_all = {str(d.get('_id', id(d))): d for d in items_collection.find(final_query, {'created_at': 1})}
            docs = list(d_all.values())
        elif metric_type == 'customers':
            d1 = list(customers_collection.find(query, {'created_at': 1, 'date': 1}))
            d2 = list(customers_collection.find(query2, {'created_at': 1, 'date': 1}))
            d_all = {str(d.get('_id', id(d))): d for d in d1 + d2}
            docs = list(d_all.values())
        elif metric_type == 'employees':
            d1 = list(worker_collection.find(query, {'created_at': 1, 'dateOfJoining': 1}))
            d2 = list(worker_collection.find(query2, {'created_at': 1, 'dateOfJoining': 1}))
            d_all = {str(d.get('_id', id(d))): d for d in d1 + d2}
            docs = list(d_all.values())
        elif metric_type == 'items':
            d1 = list(items_collection.find(query, {'created_at': 1}))
            d2 = list(items_collection.find(query2, {'created_at': 1}))
            d_all = {str(d.get('_id', id(d))): d for d in d1 + d2}
            docs = list(d_all.values())
            
        start_dt = None
        end_dt = None
        now = datetime.now()
        
        # Seed default zeroes to make the line chart continuous
        if date_filter == 'daily':
            if selected_month:
                try:
                    y, m = map(int, selected_month.split('-'))
                    num_days = calendar.monthrange(y, m)[1]
                    start_dt = datetime(y, m, 1)
                    end_dt = datetime(y, m, num_days, 23, 59, 59)
                    for i in range(1, num_days + 1):
                        chart_data[f"{y:04d}-{m:02d}-{i:02d}"] = 0.0
                except:
                    pass
            else:
                for i in range(14, -1, -1):
                    chart_data[(now - timedelta(days=i)).strftime('%Y-%m-%d')] = 0.0
        elif date_filter == 'monthly':
            if selected_year:
                try:
                    y = int(selected_year)
                    start_dt = datetime(y, 1, 1)
                    end_dt = datetime(y, 12, 31, 23, 59, 59)
                    for i in range(1, 13):
                        chart_data[f"{y:04d}-{i:02d}"] = 0.0
                except:
                    pass
            else:
                for i in range(5, -1, -1):
                    d = now.replace(day=1) - timedelta(days=28 * i)
                    chart_data[d.strftime('%Y-%m')] = 0.0
        elif date_filter == 'yearly':
            if start_year and end_year:
                try:
                    sy = int(start_year)
                    ey = int(end_year)
                    if sy > ey:
                        sy, ey = ey, sy
                    start_dt = datetime(sy, 1, 1)
                    end_dt = datetime(ey, 12, 31, 23, 59, 59)
                    for y in range(sy, ey + 1):
                        chart_data[str(y)] = 0.0
                except:
                    pass
            else:
                for i in range(4, -1, -1):
                    chart_data[str(now.year - i)] = 0.0
        elif date_filter == 'custom' and start_date_str and end_date_str:
            try:
                start_dt = datetime.strptime(start_date_str, '%Y-%m-%d').replace(hour=0, minute=0, second=0)
                end_dt = datetime.strptime(end_date_str, '%Y-%m-%d').replace(hour=23, minute=59, second=59)
                curr = start_dt
                while curr <= end_dt:
                    chart_data[curr.strftime('%Y-%m-%d')] = 0.0
                    curr += timedelta(days=1)
            except:
                pass
        
        for doc in docs:
            # Fallback multiple date fields
            date_val = doc.get('timestamp') or doc.get('created_at') or doc.get('date') or doc.get('dateOfJoining')
            if not date_val:
                continue
            
            try:
                if isinstance(date_val, str):
                    if 'T' in date_val:
                        dt = datetime.fromisoformat(date_val.replace('Z', '+00:00'))
                    else:
                        dt = datetime.strptime(date_val.split(' ')[0], '%Y-%m-%d')
                else:
                    dt = date_val
                    
                # Date Filtering
                dt_naive = dt.replace(tzinfo=None)
                if start_dt and end_dt:
                    if not (start_dt <= dt_naive <= end_dt):
                        continue
                
                # Format Key based on filter
                if date_filter == 'daily' or date_filter == 'custom':
                    key = dt.strftime('%Y-%m-%d')
                elif date_filter == 'yearly':
                    key = dt.strftime('%Y')
                else: # monthly
                    key = dt.strftime('%Y-%m')
                    
                # Only add if the key is in our padded range (strict mode for dynamic filters)
                if (date_filter in ['daily', 'monthly', 'yearly'] and (selected_month or selected_year or start_year)):
                    if key not in chart_data:
                        continue
                    
                if metric_type == 'sales':
                    amount = float(doc.get('grand_total', doc.get('total', 0)))
                    chart_data[key] += amount
                else:
                    chart_data[key] += 1
                    
            except Exception as e:
                pass
                
        sorted_keys = sorted(chart_data.keys())
        labels = sorted_keys
        data = [chart_data[k] for k in sorted_keys]
        
        return jsonify({
            'labels': labels,
            'data': data,
            'metric': metric_type
        }), 200
    except Exception as e:
        logger.error(f"Error fetching chart data: {e}")
        return jsonify({"error": str(e)}), 500




import uuid
from datetime import datetime
try:
    from zoneinfo import ZoneInfo
except ImportError:
    from backports.zoneinfo import ZoneInfo
from flask import request, jsonify, g
import logging
logger = logging.getLogger(__name__)

# NOTE: This file is meant to be appended to app1.py, so it assumes app, items_collection, etc. exist.

def _get_tenant_context_for_update_delete():
    """Helper to strictly resolve tenant, company, branch for PUT/DELETE"""
    u_id, role = get_request_user_info()
    tenant_id = getattr(g, 'tenant_id', None)
    company_id = getattr(g, 'company_id', None)
    branch_id = getattr(g, 'branch_id', None)
    
    if role in ['Super Admin', 'Master Admin']:
        # They can operate globally if headers provided
        active_company = request.headers.get('X-Company-Name')
        active_branch = request.headers.get('X-Branch-Name')
        t_id = None
        c_id = None
        b_id = None
        if active_company and active_company.lower() not in ['all', 'all companies']:
            comp = _resolve_tenant_company_branch(active_company)
            c_id = comp.get('company_id')
            t_id = comp.get('tenant_id')
        if active_branch and active_branch.lower() not in ['all', 'all branches']:
            br = _resolve_tenant_company_branch(active_company, active_branch)
            b_id = br.get('branch_id')
        return {"tenant_id": t_id, "company_id": c_id, "branch_id": b_id}
    
    # Strictly lock to g context
    return {"tenant_id": tenant_id, "company_id": company_id, "branch_id": branch_id}

def _build_strict_filter(record_id, context):
    """Builds a query filter enforcing strict tenant/company/branch match."""
    from bson import ObjectId
    q_id = record_id
    try:
        if isinstance(record_id, str) and ObjectId.is_valid(record_id):
             q_id = ObjectId(record_id)
    except:
        pass
        
    f = {"_id": q_id}
    if context.get("tenant_id"): f["tenant_id"] = context["tenant_id"]
    if context.get("company_id"): f["company_id"] = context["company_id"]
    if context.get("branch_id"): f["branch_id"] = context["branch_id"]
    return f

def _build_strict_bulk_filter(global_ref_id, context):
    """Builds a query filter enforcing strict tenant/company/branch match for bulk operations."""
    f = {"global_ref_id": global_ref_id}
    if context.get("tenant_id"): f["tenant_id"] = context["tenant_id"]
    if context.get("company_id"): f["company_id"] = context["company_id"]
    if context.get("branch_id"): f["branch_id"] = context["branch_id"]
    return f


