# @app.route('/api/items', methods=['POST'])
def create_item():
    try:
        data = request.json
        if not data:
            return jsonify({"error": "No data provided"}), 400

        can_access, data_scope_filter = get_data_scope_filter('create_item')
        if not can_access:
            return jsonify({"error": "Access denied"}), 403

        # Data Sanitization
        if 'offer_start_time' in data and data['offer_start_time'] and 'offer_end_time' in data and data['offer_end_time']:
            try:
                st = datetime.fromisoformat(str(data['offer_start_time']).replace('Z', '+00:00'))
                et = datetime.fromisoformat(str(data['offer_end_time']).replace('Z', '+00:00'))
                if st >= et:
                    return jsonify({"error": "Offer start time must be before offer end time"}), 400
            except:
                pass

        data = sanitize_image_fields(data)
        if not data.get('tax_applicable', False): data['tax_rate'] = 0
        for addon in data.get('addons', []):
            if not addon.get('tax_applicable', False): addon['tax_rate'] = 0
        for combo in data.get('combos', []):
            if not combo.get('tax_applicable', False): combo['tax_rate'] = 0

        # --- MULTI-TENANT RESOLUTION AND SAVING ---
        company_names = data.get('company_names', [])
        branch_names = data.get('branch_names', [])
        active_company = request.headers.get('X-Company-Name') or data.get('company_name', '')
        active_branch = request.headers.get('X-Branch-Name') or data.get('branch_name', '')

        if not company_names and active_company:
            company_names = [active_company]
        if not branch_names and active_branch:
            branch_names = [active_branch]
            
        if not company_names:
            return jsonify({"error": "At least one company must be selected."}), 400

        # Sanitize branch_names to remove generic tags
        if branch_names:
            branch_names = [b for b in branch_names if b and str(b).lower() not in ['all', 'all branches', 'global', 'all companies']]

        exclude_keys = {'company_name', 'branch_name', 'company_names', 'branch_names', '_id', 'company_prices', 'branch_prices', 'tenant_id', 'company_id', 'branch_id'}
        extra_fields = {k: v for k, v in data.items() if k not in exclude_keys}

        created_docs = []
        created_at = datetime.now(ZoneInfo("UTC")).isoformat()
        
        # Link all cloned items together
        global_ref_id = str(uuid.uuid4())

        for comp_name in company_names:
            ids = _resolve_tenant_company_branch(comp_name)
            if not ids.get("company_id"):
                continue

            if branch_names:
                for br_name in branch_names:
                    br_ids = _resolve_tenant_company_branch(comp_name, br_name)
                    # CRITICAL: Skip if branch doesn't belong to company
                    if not br_ids.get("branch_id"):
                        continue
                        
                    doc = {
                        "_id": str(uuid.uuid4()),
                        "global_ref_id": global_ref_id,
                        "tenant_id": br_ids.get("tenant_id"),
                        "company_id": br_ids.get("company_id"),
                        "company_name": comp_name,
                        "branch_id": br_ids.get("branch_id"),
                        "branch_name": br_name,
                        "created_at": created_at,
                        **extra_fields
                    }
                    items_collection.insert_one(doc)
                    created_docs.append(doc)
            else:
                doc = {
                    "_id": str(uuid.uuid4()),
                    "global_ref_id": global_ref_id,
                    "tenant_id": ids.get("tenant_id"),
                    "company_id": ids.get("company_id"),
                    "company_name": comp_name,
                    "branch_id": None,
                    "branch_name": "All Branches",
                    "created_at": created_at,
                    **extra_fields
                }
                items_collection.insert_one(doc)
                created_docs.append(doc)

        logger.info(f"Items created: {len(created_docs)} rows")
        return jsonify({
            "message": "Item created successfully", 
            "item_id": created_docs[0]['_id'] if created_docs else None, 
            "global_ref_id": global_ref_id,
            "items": convert_objectid_to_str(created_docs)
        }), 201
    except Exception as e:
        logger.error(f"Error creating item: {str(e)}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/items/<item_id>', methods=['PUT'])
def update_item(item_id):
    try:
        data = request.json
        if not data:
            return jsonify({"error": "No data provided"}), 400
        if '_id' in data: del data['_id']
        
        can_access, data_scope_filter = get_data_scope_filter('create_item')
        if not can_access:
             return jsonify({"error": "Access denied"}), 403

        data = sanitize_image_fields(data)
        exclude_keys = {'company_name', 'branch_name', 'company_names', 'branch_names', 'global_ref_id'}
        update_data = {k: v for k, v in data.items() if k not in exclude_keys}
        update_data['modified_at'] = datetime.now(ZoneInfo("UTC")).isoformat()

        # Strict Matching
        ctx = _get_tenant_context_for_update_delete()
        update_filter = {"$and": [data_scope_filter, _build_strict_filter(item_id, ctx)]}
        
        result = items_collection.update_one(update_filter, {'$set': update_data})
        if result.matched_count == 0:
            return jsonify({"error": "Item not found or access denied"}), 404
            
        return jsonify({"message": "Item updated successfully"}), 200
    except Exception as e:
        logger.error(f"Error updating item {item_id}: {str(e)}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/items/<item_id>', methods=['DELETE'])
def delete_item(item_id):
    try:
        can_access, data_scope_filter = get_data_scope_filter('item_list')
        if not can_access:
             return jsonify({"error": "Access denied"}), 403

        ctx = _get_tenant_context_for_update_delete()
        delete_filter = {"$and": [data_scope_filter, _build_strict_filter(item_id, ctx)]}
        
        result = items_collection.delete_one(delete_filter)
        if result.deleted_count == 0:
            return jsonify({"error": "Item not found or access denied"}), 404
            
        return jsonify({"message": "Item deleted successfully"}), 200
    except Exception as e:
        logger.error(f"Error deleting item {item_id}: {str(e)}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/items/bulk/<global_ref_id>', methods=['PUT'])
def bulk_update_item(global_ref_id):
    try:
        data = request.json
        if not data:
            return jsonify({"error": "No data provided"}), 400
            
        can_access, data_scope_filter = get_data_scope_filter('create_item')
        if not can_access: return jsonify({"error": "Access denied"}), 403

        data = sanitize_image_fields(data)
        exclude_keys = {'company_name', 'branch_name', 'company_names', 'branch_names', '_id', 'global_ref_id'}
        update_data = {k: v for k, v in data.items() if k not in exclude_keys}
        update_data['modified_at'] = datetime.now(ZoneInfo("UTC")).isoformat()

        ctx = _get_tenant_context_for_update_delete()
        update_filter = {"$and": [data_scope_filter, _build_strict_bulk_filter(global_ref_id, ctx)]}
        
        # --- SYNCHRONIZATION LOGIC FOR ADDED/REMOVED BRANCHES ---
        company_names = data.get('company_names', [])
        branch_names = data.get('branch_names', [])
        if branch_names:
            branch_names = [b for b in branch_names if b and str(b).lower() not in ['all', 'all branches', 'global', 'all companies']]
            
        if company_names:
            existing_records = list(items_collection.find(update_filter))
            if existing_records:
                desired_combinations = set()
                for comp_name in company_names:
                    # ALWAYS require the master "All Branches" record for each selected company
                    desired_combinations.add((comp_name, "All Branches"))
                    
                    # Also require specific branch records if they are valid for this company
                    if branch_names:
                        for br_name in branch_names:
                            br_ids = _resolve_tenant_company_branch(comp_name, br_name)
                            if br_ids.get("branch_id"):
                                desired_combinations.add((comp_name, br_name))
                        
                existing_combinations = {(r.get('company_name'), r.get('branch_name')) for r in existing_records}
                
                combinations_to_add = desired_combinations - existing_combinations
                combinations_to_remove = existing_combinations - desired_combinations
                
                if combinations_to_add:
                    base_record = existing_records[0].copy()
                    for k in ['_id', 'company_name', 'company_id', 'branch_name', 'branch_id', 'tenant_id']:
                        base_record.pop(k, None)
                    base_record.update(update_data)
                    
                    for comp_name, br_name in combinations_to_add:
                        ids = _resolve_tenant_company_branch(comp_name)
                        if not ids.get("company_id"): continue
                        
                        br_id = None
                        if br_name != "All Branches":
                            br_ids = _resolve_tenant_company_branch(comp_name, br_name)
                            if not br_ids.get("branch_id"): continue
                            br_id = br_ids.get("branch_id")
                            tenant_id = br_ids.get("tenant_id")
                        else:
                            tenant_id = ids.get("tenant_id")
                            
                        new_doc = {
                            "_id": str(uuid.uuid4()),
                            "global_ref_id": global_ref_id,
                            "tenant_id": tenant_id,
                            "company_id": ids.get("company_id"),
                            "company_name": comp_name,
                            "branch_id": br_id,
                            "branch_name": br_name,
                            **base_record
                        }
                        items_collection.insert_one(new_doc)
                        
                if combinations_to_remove:
                    for comp_name, br_name in combinations_to_remove:
                        items_collection.delete_one({"$and": [
                            update_filter, 
                            {"company_name": comp_name, "branch_name": br_name}
                        ]})
        # --- END SYNCHRONIZATION LOGIC ---
        
        result = items_collection.update_many(update_filter, {'$set': update_data})
        if result.matched_count == 0:
            return jsonify({"error": "No linked items found or access denied"}), 404
            
        return jsonify({"message": f"{result.modified_count} linked items updated successfully"}), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/api/items/bulk/<global_ref_id>', methods=['DELETE'])
def bulk_delete_item(global_ref_id):
    try:
        can_access, data_scope_filter = get_data_scope_filter('item_list')
        if not can_access: return jsonify({"error": "Access denied"}), 403

        ctx = _get_tenant_context_for_update_delete()
        delete_filter = {"$and": [data_scope_filter, _build_strict_bulk_filter(global_ref_id, ctx)]}
        
        result = items_collection.delete_many(delete_filter)
        if result.deleted_count == 0:
            return jsonify({"error": "No linked items found or access denied"}), 404
            
        return jsonify({"message": f"{result.deleted_count} linked items deleted successfully"}), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 500


