# @app.route('/api/customers', methods=['POST'])
def create_customer():
    try:
        can_access, data_scope_filter = get_data_scope_filter('customers')
        if not can_access: return jsonify({"error": "Access denied"}), 403

        customer_data = request.json
        if not customer_data: return jsonify({'error': 'No data provided'}), 400

        company_names = customer_data.get('company_names', [])
        branch_names = customer_data.get('branch_names', [])
        active_company = request.headers.get('X-Company-Name') or customer_data.get('company_name', '')
        active_branch = request.headers.get('X-Branch-Name') or customer_data.get('branch_name', '')

        if not company_names and active_company: company_names = [active_company]
        if not branch_names and active_branch: branch_names = [active_branch]
        if not company_names: return jsonify({"error": "At least one company must be selected."}), 400

        exclude_keys = {'company_name', 'branch_name', 'company_names', 'branch_names', '_id', 'company_id', 'branch_id'}
        extra_fields = {k: v for k, v in customer_data.items() if k not in exclude_keys}

        created_docs = []
        created_at = datetime.now(ZoneInfo("UTC")).isoformat()
        global_ref_id = str(uuid.uuid4())

        for comp_name in company_names:
            ids = _resolve_tenant_company_branch(comp_name)
            
            if not ids.get("company_id"):
                if comp_name.lower() in ['all', 'all companies', 'none', 'null', '']:
                    tenant_id = getattr(g, 'tenant_id', None)
                    if not tenant_id:
                        user_id, role = get_request_user_info()
                        user_doc = users_collection.find_one({'_id': user_id}) if user_id else None
                        tenant_id = user_doc.get('tenant_id') if user_doc else None
                        
                    doc = {
                        "_id": str(uuid.uuid4()),
                        "global_ref_id": global_ref_id,
                        "tenant_id": tenant_id,
                        "company_id": None,
                        "company_name": "All Companies",
                        "branch_id": None,
                        "branch_name": "All Branches",
                        "created_at": created_at,
                        **extra_fields
                    }
                    customers_collection.insert_one(doc)
                    created_docs.append(doc)
                continue
            
            if branch_names:
                for br_name in branch_names:
                    br_ids = _resolve_tenant_company_branch(comp_name, br_name)
                    if not br_ids.get("branch_id"):
                        if br_name.lower() in ['all', 'all branches', 'none', 'null', '']:
                            # Insert for all branches within this company
                            doc = {
                                "_id": str(uuid.uuid4()),
                                "global_ref_id": global_ref_id,
                                "tenant_id": ids.get("tenant_id"),
                                "company_id": ids.get("company_id"),
                                "company_name": comp_name,
                                "branch_id": None,
                                "branch_name": "All Branches",
                                "created_at": created_at,
                                **extra_fields
                            }
                            customers_collection.insert_one(doc)
                            created_docs.append(doc)
                        continue
                    
                    doc = {
                        "_id": str(uuid.uuid4()),
                        "global_ref_id": global_ref_id,
                        "tenant_id": br_ids.get("tenant_id"),
                        "company_id": br_ids.get("company_id"),
                        "company_name": comp_name,
                        "branch_id": br_ids.get("branch_id"),
                        "branch_name": br_name,
                        "created_at": created_at,
                        **extra_fields
                    }
                    customers_collection.insert_one(doc)
                    created_docs.append(doc)
            else:
                doc = {
                    "_id": str(uuid.uuid4()),
                    "global_ref_id": global_ref_id,
                    "tenant_id": ids.get("tenant_id"),
                    "company_id": ids.get("company_id"),
                    "company_name": comp_name,
                    "branch_id": None,
                    "branch_name": "All Branches",
                    "created_at": created_at,
                    **extra_fields
                }
                customers_collection.insert_one(doc)
                created_docs.append(doc)

        return jsonify({"message": "Customer created successfully", "global_ref_id": global_ref_id, "customers": convert_objectid_to_str(created_docs)}), 201
    except Exception as e:
        return jsonify({"error": str(e)}), 500

