@app.route('/api/tenants-hierarchy', methods=['GET'])
def get_tenants_hierarchy():
    try:
        if tenants_collection is None:
            return jsonify({"error": "Database initialization in progress"}), 503
        
        tenants = list(tenants_collection.find({}))
        companies = list(companies_collection.find({})) if companies_collection else []
        branches = list(branches_collection.find({})) if branches_collection else []
        
        hierarchy = []
        for t in tenants:
            tid = t.get("_id")
            t_comps = [c for c in companies if c.get("tenant_id") == tid]
            t_comp_list = []
            for c in t_comps:
                cid = c.get("_id")
                c_branches = [b for b in branches if b.get("company_id") == cid]
                t_comp_list.append({
                    "company": c,
                    "branches": c_branches
                })
            hierarchy.append({
                "tenant": t,
                "companies": t_comp_list
            })
        return jsonify(hierarchy), 200
    except Exception as e:
        logger.error(f"Error fetching hierarchy: {str(e)}")
        return jsonify({"error": "Failed to fetch hierarchy", "message": str(e)}), 500

@app.route('/api/tenants-public/<tenant_id>', methods=['PUT'])
def update_public_tenant(tenant_id):
    try:
        data = request.get_json()
        if not data:
            return jsonify({"error": "No data provided"}), 400

        # Update tenant
        existing = tenants_collection.find_one({"_id": tenant_id})
        if not existing:
            return jsonify({"error": "Tenant not found"}), 404
        
        update_data = {k: v for k, v in data.items() if k not in ["admin_password", "admin_username"]}
        if update_data:
            for k, v in update_data.items():
                existing[k] = v
            tenants_collection.update_one({"_id": tenant_id}, {"$set": existing})

        # Update Admin User if provided
        new_username = data.get("admin_username")
        new_password = data.get("admin_password")
        
        if new_username or new_password:
            user_doc = users_collection.find_one({"tenant_id": tenant_id, "role": "Tenant Admin"})
            if user_doc:
                if new_username:
                    user_doc["username"] = new_username
                    user_doc["email"] = new_username # Keep them synced as per onboarding logic
                if new_password:
                    from werkzeug.security import generate_password_hash
                    user_doc["password"] = generate_password_hash(new_password)
                    user_doc["plain_password"] = new_password
                users_collection.update_one({"_id": user_doc["_id"]}, {"$set": user_doc})

        return jsonify({"message": "Tenant updated successfully"}), 200
    except Exception as e:
        logger.error(f"Error updating tenant: {str(e)}")
        return jsonify({"error": "Failed to update tenant", "message": str(e)}), 500

@app.route('/api/onboard-organization/<tenant_id>', methods=['GET'])
def get_onboard_organization(tenant_id):
    try:
        tenant = tenants_collection.find_one({"_id": tenant_id})
        if not tenant:
            return jsonify({"error": "Tenant not found"}), 404
            
        tenant_admin = users_collection.find_one({"tenant_id": tenant_id, "role": {"$in": ["Tenant Admin", "admin"]}})
        if tenant_admin:
            if "plain_password" in tenant_admin:
                tenant["plain_password"] = tenant_admin["plain_password"]
            tenant["admin_email"] = tenant_admin.get("email", "")
            tenant["admin_username"] = tenant_admin.get("username", "")
            
        comps = list(companies_collection.find({"tenant_id": tenant_id}))
        for c in comps:
            # Add default admin details for UI binding
            admin_doc = users_collection.find_one({"company_id": c.get("_id"), "role": "Company Admin"})
            if admin_doc:
                c["admin_email"] = admin_doc.get("email", "")
                c["admin_username"] = admin_doc.get("username", "")
                c["plain_password"] = admin_doc.get("plain_password", "")
                
        brs = list(branches_collection.find({"tenant_id": tenant_id}))
        for b in brs:
            admin_doc = users_collection.find_one({"branch_id": b.get("_id"), "role": "Branch Admin"})
            if admin_doc:
                b["admin_email"] = admin_doc.get("email", "")
                b["admin_username"] = admin_doc.get("username", "")
                b["plain_password"] = admin_doc.get("plain_password", "")
                
        return jsonify({
            "tenant": tenant,
            "companies": comps,
            "branches": brs
        }), 200
    except Exception as e:
        logger.error(f"Error fetching onboard org: {str(e)}")
        return jsonify({"error": "Failed to fetch organization", "message": str(e)}), 500

@app.route('/api/onboard-organization/<tenant_id>', methods=['PUT'])
def update_onboard_organization(tenant_id):
    try:
        g.skip_tenancy = True
        data = request.get_json()
        
        tenant_details = data.get('tenant', {})
        companies = data.get('companies', [])
        branches = data.get('branches', [])
        
        # 1. Update Tenant
        existing_tenant = tenants_collection.find_one({"_id": tenant_id})
        if not existing_tenant:
            return jsonify({"error": "Tenant not found"}), 404
        
        for k, v in tenant_details.items():
            if k not in ["admin_password", "admin_username", "_id"]:
                existing_tenant[k] = v
        tenants_collection.update_one({"_id": tenant_id}, {"$set": existing_tenant})
        
        # Update Tenant Admin if needed
        new_t_email = tenant_details.get("admin_email")
        new_t_username = tenant_details.get("admin_username")
        new_t_password = tenant_details.get("admin_password")
        if new_t_email or new_t_username or new_t_password:
            user_doc = users_collection.find_one({"tenant_id": tenant_id, "role": "Tenant Admin"})
            if user_doc:
                if new_t_email:
                    user_doc["email"] = new_t_email
                if new_t_username:
                    user_doc["username"] = new_t_username
                if new_t_password and "ΓÇó" not in new_t_password: # Ignore masked passwords from UI
                    import bcrypt
                    user_doc["password"] = bcrypt.hashpw(str(new_t_password).encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
                    user_doc["plain_password"] = new_t_password
                users_collection.update_one({"_id": user_doc["_id"]}, {"$set": user_doc})

        # 2. Re-sync Companies
        import bcrypt
        import uuid
        
        # For simplicity in this demo system, we update existing or insert new.
        # We map existing companies by ID if provided from frontend.
        company_map = {}
        for c in companies:
            cid = c.get("_id") or str(uuid.uuid4())
            c["_id"] = cid
            c["tenant_id"] = tenant_id
            company_map[c.get("company_name")] = cid
            
            existing_c = companies_collection.find_one({"_id": cid})
            if existing_c:
                c_update = {k: v for k, v in c.items() if k not in ["admin_password", "admin_email", "admin_username"]}
                for k,v in c_update.items(): existing_c[k] = v
                companies_collection.update_one({"_id": cid}, {"$set": existing_c})
            else:
                companies_collection.insert_one(c)
            
            # Update/Insert Company Admin
            admin_email = c.get("admin_email")
            admin_pwd = c.get("admin_password")
            if admin_email:
                admin_doc = users_collection.find_one({"company_id": cid, "role": "Company Admin"})
                if not admin_doc:
                    users_collection.insert_one({
                        "_id": str(uuid.uuid4()),
                        "tenant_id": tenant_id,
                        "company_id": cid,
                        "company_name": c.get("company_name"),
                        "username": admin_email,
                        "email": admin_email,
                        "password": bcrypt.hashpw(str(admin_pwd).encode('utf-8'), bcrypt.gensalt()).decode('utf-8') if admin_pwd and "ΓÇó" not in admin_pwd else "",
                        "plain_password": admin_pwd if admin_pwd and "ΓÇó" not in admin_pwd else "",
                        "role": "Company Admin",
                        "status": "Active"
                    })
                else:
                    admin_doc["username"] = admin_email
                    admin_doc["email"] = admin_email
                    if admin_pwd and "ΓÇó" not in admin_pwd:
                        admin_doc["password"] = bcrypt.hashpw(str(admin_pwd).encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
                        admin_doc["plain_password"] = admin_pwd
                    users_collection.update_one({"_id": admin_doc["_id"]}, {"$set": admin_doc})

        # 3. Re-sync Branches
        for b in branches:
            bid = b.get("_id") or str(uuid.uuid4())
            b["_id"] = bid
            b["tenant_id"] = tenant_id
            # Map company_id if it's a newly added branch matching a company name
            if not b.get("company_id") and b.get("company_name"):
                b["company_id"] = company_map.get(b.get("company_name"))
            
            existing_b = branches_collection.find_one({"_id": bid})
            if existing_b:
                b_update = {k: v for k, v in b.items() if k not in ["admin_password", "admin_email", "admin_username"]}
                for k,v in b_update.items(): existing_b[k] = v
                branches_collection.update_one({"_id": bid}, {"$set": existing_b})
            else:
                branches_collection.insert_one(b)

            # Branch Admin
            b_admin_email = b.get("admin_email")
            b_admin_pwd = b.get("admin_password")
            if b_admin_email:
                b_admin_doc = users_collection.find_one({"branch_id": bid, "role": "Branch Admin"})
                if not b_admin_doc:
                    users_collection.insert_one({
                        "_id": str(uuid.uuid4()),
                        "tenant_id": tenant_id,
                        "company_id": b.get("company_id"),
                        "company_name": b.get("company_name"),
                        "branch_id": bid,
                        "branch_name": b.get("branch_name"),
                        "username": b_admin_email,
                        "email": b_admin_email,
                        "password": bcrypt.hashpw(str(b_admin_pwd).encode('utf-8'), bcrypt.gensalt()).decode('utf-8') if b_admin_pwd and "ΓÇó" not in b_admin_pwd else "",
                        "plain_password": b_admin_pwd if b_admin_pwd and "ΓÇó" not in b_admin_pwd else "",
                        "role": "Branch Admin",
                        "status": "Active"
                    })
                else:
                    b_admin_doc["username"] = b_admin_email
                    b_admin_doc["email"] = b_admin_email
                    if b_admin_pwd and "ΓÇó" not in b_admin_pwd:
                        b_admin_doc["password"] = bcrypt.hashpw(str(b_admin_pwd).encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
                        b_admin_doc["plain_password"] = b_admin_pwd
                    users_collection.update_one({"_id": b_admin_doc["_id"]}, {"$set": b_admin_doc})

        return jsonify({"message": "Organization updated successfully"}), 200
    except Exception as e:
        logger.error(f"Error updating onboard org: {str(e)}")
        return jsonify({"error": "Failed to update organization", "message": str(e)}), 500




if __name__ == "__main__":
    logger.info(f"Serving static files from: {app.static_folder}")
    if getattr(sys, "frozen", False):
        logger.info("Running as frozen executable, using Waitress")
        import waitress
        waitress.serve(app, host="0.0.0.0", port=6034, threads=8)
    else:
        socketio.run(app, host="0.0.0.0", port=6034, debug=True, allow_unsafe_werkzeug=True, use_reloader=False)
